PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE videos (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    date TEXT NOT NULL,
    name TEXT NOT NULL,
    structure TEXT DEFAULT '',
    video_link TEXT DEFAULT '',
    script_path TEXT DEFAULT '',
    created_at TEXT DEFAULT (datetime('now', 'localtime')),
    updated_at TEXT DEFAULT (datetime('now', 'localtime'))
  , video_title TEXT DEFAULT '', duration TEXT DEFAULT '', publish_date TEXT DEFAULT '', summary TEXT DEFAULT '', hook TEXT DEFAULT '', hook_tags TEXT DEFAULT '', video_tags TEXT DEFAULT '', technique TEXT DEFAULT '', mechanism_name TEXT DEFAULT '', mechanism TEXT DEFAULT '', adapt_tags TEXT DEFAULT '', adapt_brief TEXT DEFAULT '', views TEXT DEFAULT '', likes TEXT DEFAULT '', source_video_id INTEGER DEFAULT '', video_type TEXT DEFAULT '故事类', protagonist TEXT DEFAULT '', protagonist_goal TEXT DEFAULT '', antagonist TEXT DEFAULT '', antagonist_goal TEXT DEFAULT '', video_path TEXT DEFAULT '', thumb_url TEXT DEFAULT '', notes TEXT DEFAULT '');
CREATE TABLE scenes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    video_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    description TEXT DEFAULT '', function TEXT DEFAULT '',
    FOREIGN KEY (video_id) REFERENCES videos(id) ON DELETE CASCADE
  );
CREATE TABLE props (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    video_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    function TEXT DEFAULT '', type TEXT DEFAULT '',
    FOREIGN KEY (video_id) REFERENCES videos(id) ON DELETE CASCADE
  );
CREATE TABLE characters (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    video_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    persona TEXT DEFAULT '', abilities TEXT DEFAULT '', states TEXT DEFAULT '',
    FOREIGN KEY (video_id) REFERENCES videos(id) ON DELETE CASCADE
  );
COMMIT;
