INSERT INTO videos VALUES(2,'2026-03-25','辣椒成瘾','','https://www.youtube.com/watch?v=3GwE5yoh4s4','scripts/辣椒成瘾.txt','2026-03-25 23:20:32','2026-03-29 02:17:28','Why is Rumi OBSESSED with Red Chilies?#ai #kpop #rumi #funny #shorts','48','2026-02-20','rumi在教室疯狂吃红辣椒进行吃辣特训，黑发肌肉男和朋友们反复劝阻无果，父母也心疼但无法阻止。最终揭晓原因——rumi的好友mira患有精神疾病，mira曾好心给rumi做辣椒面包却导致rumi剧烈咳嗽，mira因此极度自责陷入创伤。rumi为了消除mira的心结，独自承受痛苦练习吃辣，最终在探视时轻松吃下辣椒面包，微笑说我喜欢，两人握手完成双向救赎。','rumi在教室强忍不适，疯狂往嘴里塞红辣椒','异常行为','感动, 治愈','前半段用自虐式吃辣制造不解和心疼，逐步累积情感厚度，结尾反转揭晓真正目的是为朋友克服创伤，将异常行为转化为深厚友情的证明','极端执念与治愈反转','异常行为展示→多方阻止失败→真相揭晓→行为重新定义→情感升华','','','8726165','106657','','故事类','rumi','通过吃辣特训帮助患精神疾病的好友mira','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/002_辣椒成瘾.mp4','/thumbs/002_3GwE5yoh4s4.jpg','');
INSERT INTO videos VALUES(3,'2026-03-26','柠檬成瘾','','https://www.youtube.com/watch?v=3x7LilYhhtY','scripts/柠檬成瘾.txt','2026-03-26 00:13:11','2026-03-29 02:17:26','Everyone thinks Rumi is crazy for eating lemons, UNTIL... 🍋🤫 #rumi #family #comedy  #kpop #zoey','35','2026-03-13','rumi在办公室疯狂啃食极酸的生柠檬进行抗酸特训，jinu和mira大惊失色上前制止，rumi假意收下正常食物后继续偷练。回到家中父母也苦苦劝阻，rumi却固执拒绝。手机屏幕上rumi和zoye的合影揭示了特训动机——zoey患有精神疾病，曾好心喂rumi柠檬却导致rumi酸到五官扭曲，zoye因此极度自责陷入创伤。rumi为了消除zoye的心结独自承受痛苦练习吃柠檬，最终在探视时轻松咬下柠檬面带微笑，zoye如释重负开心拍手大笑，完成双向救赎。','rumi在办公室疯狂啃食极酸的生柠檬，面容极度扭曲','异常行为','感动, 治愈','前半段用自虐式吃酸制造不解和心疼，逐步累积情感厚度，结尾反转揭晓真正目的是为精神病好友克服创伤，将异常行为转化为深厚友情的证明','极端执念与治愈反转','异常行为展示→多方阻止失败→真相揭晓→行为重新定义→情感升华','换皮型改编','从辣椒成瘾改编，保留"异常行为→阻止→真相→救赎"机制链条，把辣椒换成柠檬，mira换成zoye，教室换成办公室，精神病院探视室换成探视区','9500320','98862',2,'故事类','rumi','通过吃柠檬特训帮助患精神疾病的zoye','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/003_柠檬成瘾.mp4','/thumbs/003_3x7LilYhhtY.jpg','');
INSERT INTO videos VALUES(4,'2026-03-26','冰块成瘾','','https://www.youtube.com/watch?v=cKUXk95fw8o','scripts/997冰块成瘾.txt','2026-03-26 00:18:51','2026-03-30 00:30:30','rumi help zoey  #rumi#zoey#kpop #funny#kpopdemonhunters','36','2026-03-17','rumi在家里满身泥污地疯狂啃食巨大的工业冰柱进行抗寒特训，jinu、mira和romance大惊失色上前制止。jinu端来烤吐司让rumi暖胃，rumi却偷偷把冰块夹进吐司继续啃咬，众人崩溃。桌上相框里rumi和zoye的合影揭示了特训动机——zoye患有精神疾病，曾好心给rumi做冰块三明治却导致rumi被冻得痛苦流泪，zoye因此极度自责陷入创伤。rumi为了消除zoye的心结独自承受痛苦练习吃冰，最终在探视时轻松咬下冰块三明治面带微笑夸赞美味，zoye破涕为笑，完成双向救赎。','rumi满身泥污疯狂啃食巨大的工业冰柱','身体异常, 异常行为','感动, 治愈','前半段用自虐式吃冰制造荒诞与不解，逐步累积情感厚度，结尾反转揭晓真正目的是为精神病好友克服创伤，将异常行为转化为深厚友情的证明','极端执念与治愈反转','异常行为展示→多方阻止失败→真相揭晓→行为重新定义→情感升华','换皮型改编','从辣椒成瘾改编，保留"异常行为→阻止→真相→救赎"机制链条，把辣椒换成工业冰块，教室换成客厅，mira/zoye角色分工重组，增加照片相框作为叙事枢纽','25543210','251669',2,'故事类','rumi','通过啃冰特训帮助患病的zoye','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/004_冰块成瘾.mp4','/thumbs/004_cKUXk95fw8o.jpg','开头类型可以叠加，异常行为可以配合惊讶的音效和剧烈抖动的运镜');
INSERT INTO videos VALUES(5,'2026-03-26','跳舞成瘾','','https://www.youtube.com/watch?v=bSE5DblMXgs','scripts/996跳舞成瘾','2026-03-26 00:32:20','2026-03-29 02:17:22','Why does Jinu keep dancing ballet?#kpopdemonhunters #kpop #rumi #funny #jinu','40','2026-03-11','jinu在舞蹈室穿着粉色芭蕾裙拼命练习芭蕾旋转，mira拿篮球劝阻，父亲怒砸篮球鞋逼他做正常男孩，jinu委屈落泪但坚定地选择了粉色芭蕾舞鞋。真相揭晓——jinu带着舞鞋来到医院探望双腿打石膏坐轮椅的rumi，rumi崩溃哭喊自己再也不能跳舞。jinu默默换上粉色足尖鞋，含泪微笑说让我来做你的腿，然后在病房里为rumi翩翩起舞。rumi喜极而泣，门外曾阻碍他的人们红着眼眶为他鼓掌。','jinu穿着粉色芭蕾裙和足尖鞋在舞蹈室拼命练习芭蕾旋转','异常行为','感动, 治愈','用男生穿芭蕾裙跳舞的性别错位制造荒诞与不解，逐步累积委屈与坚持，结尾反转揭晓是为了延续挚友断送的舞蹈梦想，将怪异行为转化为极致深情的证明','极端执念与治愈反转','异常行为展示→多方阻止失败→真相揭晓→行为重新定义→情感升华','核心机制迁移型改编','从辣椒成瘾迁移核心机制"误解反转"，将食物抗性特训换为芭蕾舞特训，精神病友换为受伤失去跳舞能力的挚友，自虐动机从"接纳朋友的爱"变为"替朋友延续梦想"','13653149','144201',2,'故事类','jinu','替双腿受伤的rumi完成芭蕾梦想','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/005_跳舞成瘾.mp4','/thumbs/005_bSE5DblMXgs.jpg','');
INSERT INTO videos VALUES(6,'2026-03-26','谁偷吃了','','https://www.youtube.com/watch?v=JfzzKecajH8','scripts/995谁偷吃了','2026-03-26 01:39:25','2026-03-29 02:17:20','Did Jinu steal food? #funny #kpop','46','2026-03-14','rumi发现火龙果被偷吃，质问满嘴红汁的jinu，jinu死不承认说是吃小番茄。rumi又端来曲奇饼干当诱饵，饼干再次被偷吃，满嘴碎屑的jinu依然否认。rumi心生一计，从猫砂盆铲出猫砂用破壁机打成黑色糊状物，伪装成黑芝麻糊端上桌并警告不准吃。贪吃的jinu再次中计，吃得满嘴黑泥、恶心反胃甚至强行咽下反酸物，但仍然坚持否认。最终rumi对镜头坏笑并比出噤声手势，完成恶搞复仇。','rumi怒气冲冲质问谁吃了我的火龙果','冲突对峙, 提出疑问','搞笑, 荒诞','用重复升级结构（偷吃→铁证如山→死不承认）三轮循环堆叠荒诞感，第三轮加入观众知道但角色不知道的信息差（猫砂伪装成芝麻糊），将喜剧效果推至极点','不停干坏事','干坏事→被质问→死不承认→重复干→升级惩罚','','','8322616','64248','','故事类','rumi','抓住偷吃零食的人','jinu','偷吃零食不被发现','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/006_谁偷吃了.mp4','/thumbs/006_JfzzKecajH8.jpg','');
INSERT INTO videos VALUES(7,'2026-03-26','谁偷吃了2','','https://www.youtube.com/watch?v=SGkH-sJBljo','scripts/994谁偷吃了2','2026-03-26 01:43:36','2026-03-29 02:17:18','🍔😡 ¡¿QUIÉN se comió mi hamburguesa?! #kpop #kpopdemonhunters #rumi #jinu','49','2026-03-16','jinu发现汉堡被偷吃，满嘴生菜的rumi死不承认说自己只是爱吃生菜。jinu又端来泡面当诱饵转身倒数，回头发现连汤都不剩，嘴里挂着面条的rumi依然否认。jinu祭出终极陷阱——装有炸弹的榴莲，再次转身倒数后当场抓获正试图掰开榴莲的zoye、romance和rumi三人，大喊里面有炸弹，随即爆炸将三人炸死。事后jinu在墓地为他们献上汉堡，一转身汉堡却离奇消失，暗示贪吃的鬼魂仍在偷吃。','jinu怒气冲冲质问谁吃了我的汉堡','冲突对峙, 提出疑问','搞笑, 荒诞','沿用重复升级套路（偷吃→铁证→否认）三轮循环，但第三轮升级为致命物理惩罚（炸弹），并追加墓地惊悚反转（鬼魂偷吃）作为超预期收尾','不停干坏事','干坏事→被质问→死不承认→重复干→升级惩罚','递进升级型改编, 延伸式改编','从谁偷吃了改编，保留重复升级恶搞机制，将室内场景换为海滩+墓地，将猫砂惩罚升级为炸弹爆炸物理毁灭，追加死后鬼魂依然偷吃的惊悚反转','10107057','98325',6,'故事类','jinu','抓住偷吃食物的人','rumi','偷吃食物不被发现','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/007_谁偷吃了2.mp4','/thumbs/007_SGkH-sJBljo.jpg','');
INSERT INTO videos VALUES(8,'2026-03-26','谁关了音乐','','https://www.youtube.com/watch?v=BQ5fSiO0hxo','scripts/993谁关了音乐','2026-03-26 02:00:16','2026-03-29 02:17:16','Who stopped the song? #kpop #kpopdemonhunters #rumi #funny #jinu #mira','38','2026-03-19','jinu开车载着rumi和zoye兜风时，车内音乐被一只只有观众能看见的半透明手臂（mira的虚影）频繁关掉。jinu以为是rumi和zoye在捣鬼，不顾两人极力否认，愤怒地用粗麻绳将她们绑在后座。jinu回到驾驶座再次播放音乐，结果mira的半透明手臂直接在他面前悬空关掉音乐。jinu亲眼目睹灵异事件后吓破胆弃车逃跑，留在车内的rumi、zoye和mira虚影相视一笑，暗示女孩们早就串通完成了对jinu的终极恶作剧。','一只半透明的全息手臂突然伸出关掉了车内音乐','提出疑问','搞笑, 荒诞','利用观众全知视角（看得到幽灵手）和角色受限视角（看不到）的信息差制造喜剧，通过重复质问→否认→升级惩罚堆叠张力，最终真凶现身让冤枉者自己崩溃','不停干坏事','干坏事→被质问→死不承认→重复干→升级惩罚','核心机制迁移型改编','从谁偷吃了迁移"重复质问→否认→升级惩罚"机制，将偷吃食物换为关音乐，真实犯人从当事人换为隐形幽灵，惩罚对象从真凶变为无辜者，结局从犯人自食恶果变为冤枉者被吓跑','10513210','82949',6,'故事类','jinu','找出谁一直关掉车内音乐','mira','隐身偷关音乐不被发现','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/008_谁关了音乐.mp4','/thumbs/008_BQ5fSiO0hxo.jpg','');
INSERT INTO videos VALUES(9,'2026-03-26','谁偷吃了3','','https://www.youtube.com/watch?v=-hZMdiAjo8Y','scripts/992谁偷吃了3','2026-03-26 15:41:26','2026-03-29 02:17:14','Rumi is trying every trick in the book just to sneak a bite! 😏#rumi #funny #kpop','54','2026-03-16','贪吃的rumi为了偷吃不被jinu抓到用尽奇招。第一幕用保鲜膜包脸吃火龙果，吃完撕掉保鲜膜，以一张干净的脸成功洗白。第二幕趁jinu离开时把半个西瓜的果肉全部掏空，让准备切西瓜的jinu举着空壳崩溃。第三幕偷吃方块巧克力后利用几何拼图错觉将剩余巧克力重新拼成完美矩形，让气势汹汹赶来的jinu看着完整的巧克力盘子陷入自我怀疑。','rumi偷吃火龙果，脑海中突然闪回被jinu抓包质问的画面','异常行为','搞笑, 荒诞','以偷吃者视角展示三轮越来越高级的反侦察诡计（物理防护→视角盲区→几何错觉），每轮的智商碾压递进升级，让观众站在偷吃者一边享受智商优越感','不停干坏事','干坏事→被质问→死不承认→重复干→升级惩罚','败者重生改编','开局继承母版中rumi被jinu质问的失败经历，偷吃者吸取教训变聪明，用保鲜膜防汁液、掏空西瓜、几何拼图等诡计从被抓包变成完美脱罪','15349123','141257',6,'故事类','jinu','抓住偷吃食物的人','rumi','用各种妙招偷吃不被发现','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/009_谁偷吃了3.mp4','/thumbs/009_-hZMdiAjo8Y.jpg','');
INSERT INTO videos VALUES(10,'2026-03-27','海底列车伪装','','http://www.youtube.com/watch?v=px4YZxXKstg','scripts/981海底列车伪装.md','2026-03-27 01:18:03','2026-03-29 02:17:12','What is Mira trying to tell Rumi? #rumi #kpop #jinu #mira','37','2026-03-03','紫裙Rumi在海底列车内喝果汁，窗外潜水服Mira敲击求救。Rumi依次递出紫发辫、把Romance按在窗上均被拒。Rumi举起绿锤时，Mira惊恐指向她身后。白衣Rumi出现，紫裙Rumi被闪现到水中Mira怀里。白衣Rumi大笑变身为Jinu，揭示紫裙Rumi由Jinu伪装。真Rumi下令驱逐，Jinu与Mira在海中合十求饶。','Rumi在海底列车中喝果汁，突然白光闪烁，她惊恐吐出果汁','异常场景, 突发意外','荒诞, 搞笑','身份伪装+双重反转：先用各种荒诞物品献殷勤制造笑点，再通过"背后有人"揭示真假身份，最终变身揭露真凶','伪装揭穿','角色A伪装成角色B行动 → 各种行为暴露不合理 → 真正的B出现 → A原形毕露受罚','','','22273889','161775','','故事类','rumi','在海底列车内救助窗外求救的mira','jinu','伪装成白衣Rumi取代紫裙Rumi','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/010_海底列车伪装.mp4','/thumbs/010_px4YZxXKstg.jpg','');
INSERT INTO videos VALUES(11,'2026-03-27','爬辫子塔','','http://www.youtube.com/watch?v=ayVOijHgG9E','scripts/982爬辫子塔.md','2026-03-27 01:18:32','2026-03-29 02:17:10','Jinu Climbed Rumi''s Hair… And THIS Happened at the Top😳 #comedy #kpop','27','2026-03-19','jinu与橘发眼镜男面对三根巨型麻花辫，jinu选紫辫，橘发男选绿辫并幻想有公主。jinu途中力竭求赞获能量后登顶，rumi奖励金条。橘发男在绿辫上闻到臭味仍执意攀爬，爬进窗口后迎面撞见丑陋绿发怪物喊他"我的爱人"，橘发男惊恐尖叫。','jinu与橘发男站在三根巨型麻花辫（紫、蓝、绿）底部，辫子如通天塔延伸至云端，jinu选了紫色那根','异常场景','荒诞, 搞笑','双线叙事+期望落差：jinu线获奖励（正反馈），橘发男线遇怪物（负反馈），通过平行剪辑制造对比反转','盲选陷阱','多选项呈现 → 角色凭直觉/贪念选择 → 正确选项获奖 → 错误选项遭遇远超预期的惩罚','','','25608503','423346','','故事类','jinu','攀爬紫辫登顶获得奖励','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/011_爬辫子塔.mp4','/thumbs/011_ayVOijHgG9E.jpg','');
INSERT INTO videos VALUES(12,'2026-03-27','脱毛膏误用','','https://www.youtube.com/shorts/bINC2W--rUE','scripts/983脱毛膏误用.md','2026-03-27 01:19:00','2026-03-29 02:17:08','🚫Careless Jinu #demonhunters #kpopdemonhunters #rumi #jinu','28','2026-03-17','Jinu看到Rumi敷黑面膜想要，被拒后偷拿一管印着Hair Removal的黑色脱毛膏误当面膜涂满全脸。干涸后发现撕不下来，冲进浴室疯狂泼水用海绵擦，导致衬衫沾满黑水且面部红肿发炎。Rumi进浴室看到惨状大笑，帮Jinu撕下额头黑膜，Jinu凄厉惨叫后发现眉毛被全部撕掉。','Jinu看到Rumi敷着黑色面膜，兴奋地凑上去表示也想要一个，Rumi无情拒绝','异常行为','荒诞, 搞笑','误用道具+连锁灾难：通过偷窃导致错误使用，再通过自救失败层层加码痛苦，最终由帮手的善意行为引爆最惨结果','误用灾难链','角色偷用/误用道具 → 发现异常 → 自救失败不断加码 → 他人好心帮忙反而引爆最惨后果','','','28348234','141729','','故事类','jinu','想敷面膜变好看','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/012_脱毛膏误用.mp4','/thumbs/012_bINC2W--rUE.jpg','');
INSERT INTO videos VALUES(13,'2026-03-27','火鸡面灵魂','','https://www.youtube.com/shorts/edcdfM2YrzA','scripts/984火鸡面灵魂.md','2026-03-27 01:19:25','2026-03-27 19:40:26','#rumi #jinu #funny #kpopdemonhunters #kpop','13','2026-03-05','Rumi在厨房吃绿色乌龟食物，Jinu端火鸡面从后方大喊吓到她，导致食物卡喉咙窒息倒地。Jinu跑来单膝跪地，激动展示火鸡面问她是否没事，完全忽视昏迷状态。Rumi的紫色半透明灵魂从躯体飘出，直扑火鸡面大口吸食。Jinu大惊失色喊有鬼。','Rumi在厨房正要吃一颗绿色乌龟形状的食物，Jinu端着两碗火鸡面从走廊走入，大喊"Rumi！"','异常行为, 异常物品','荒诞, 搞笑','意外致死+灵魂出窍：通过日常惊吓引发荒诞死亡，再用灵魂出窍吃面的超自然行为制造终极反差笑点','食物执念','角色因意外失去行动力 → 美食出现 → 对食物的执念超越生死/物理限制 → 产生超自然反应','','','29388383','133838','','故事类','jinu','分享火鸡面给rumi','','','','/thumbs/013.jpg','');
INSERT INTO videos VALUES(14,'2026-03-27','真假Rumi','','http://www.youtube.com/watch?v=Enjy5yfaXtA','scripts/985真假Rumi.md','2026-03-27 01:20:02','2026-03-29 02:17:06','Two Rumis💨 Who is the real? #kpop #rumi','33','2026-02-27','红衣Rumi掀被释放绿色毒屁，熏醒Jinu。Jinu发现床上竟有红蓝两名Rumi，两人互指对方为假。Jinu端来焦黑章鱼触手测试，两人吃下后蓝衣Rumi面部喷出绿烟，被Jinu、Zoye与Romance判定为假并架出别墅。留在床上的红衣Rumi得意比嘘，特效闪过现出Mira原形——她才是放屁与伪装的真凶。','红衣Rumi对镜头神秘比"嘘"，随即掀开被子释放绿色毒屁，旁边熟睡的Jinu被熏醒惊恐坐起','异常行为','荒诞, 搞笑','真假鉴别+双重反转：先设疑（两个Rumi），再用测试制造误判（蓝衣被冤），最后终极反转揭示真凶是第三方Mira','伪装揭穿','角色A伪装成角色B行动 → 各种行为暴露不合理 → 真正的B出现 → A原形毕露受罚','','','29542279','203953','','故事类','jinu','找出谁是假Rumi','mira','伪装成Rumi不被识破','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/014_真假Rumi.mp4','/thumbs/014_Enjy5yfaXtA.jpg','');
INSERT INTO videos VALUES(15,'2026-03-27','创可贴修水管','','http://www.youtube.com/watch?v=GBPVsLEwX5I','scripts/986创可贴修水管.md','2026-03-27 01:20:29','2026-03-29 02:17:04','If we are together, we can heal the wounds. #kpop #rumi #mira','50','2026-03-21','rumi用爱心创可贴修补漏水水管，婴儿车自行车碾过无事，但电动滑板车碾过后水管爆裂喷水。rumi焦急徒手堵漏失败，mira右臂戴石膏夹板手持木板赶来，用嘴撕开绷带，两人合力将木板像骨折夹板般绑在水管上。滑板车再次碾过水管完好，两人欢呼竖大拇指。','rumi神情专注地撕下一片爱心形创可贴，郑重地贴在绿色水管的破损漏水处，拍手起身微笑说"There, good as new."','异常行为','治愈, 搞笑','问题-验证-升级-解决：用阶梯式压力测试推动情节，创可贴修水管的荒诞性+mira用骨折夹板思路修水管的暗线呼应制造惊喜','合作修复','角色A用错误方式修复 → 更大压力导致失败 → 角色B带来专业方案 → 合力修复成功','','','27043944','215148','','故事类','rumi','修好漏水的水管','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/015_创可贴修水管.mp4','/thumbs/015_GBPVsLEwX5I.jpg','');
INSERT INTO videos VALUES(16,'2026-03-27','忍痛轮椅逃亡-汤版','','https://www.youtube.com/shorts/zPO-DGLeAgg','scripts/987忍痛轮椅逃亡-汤版.md','2026-03-27 01:20:58','2026-03-27 19:40:26','Until when does Rumi want Jinu to tough it out? 🤨🤣','21','2026-03-21','Rumi失手将滚烫红色汤汁泼在Jinu赤裸脚上。Jinu极度痛苦但死死捂嘴强忍，Rumi比嘘手势要求别吵醒沙发上熟睡的企鹅玩偶。Rumi推Jinu上轮椅狂奔，穿越城市街道（轮椅擦火花）、海滩涉水、沙漠。最终在樱花雪山前Jinu忍耐到极限，双眼射出蓝光怒吼爆发，声波导致雪山如火山般喷发。','Rumi在厨房失手将一锅滚烫的红色汤汁泼洒在Jinu赤裸的双脚上，Jinu极度痛苦，死死捂住嘴巴强忍尖叫','突发意外, 滑稽疼痛','荒诞, 搞笑','情绪压抑-爆发：先用荒诞的禁声理由（不吵玩偶）建立极端限制，再通过轮椅穿越多极端地形不断叠加压抑，最终能量爆发导致超自然灾难','隐忍爆发','意外伤害 → 荒诞的禁声限制 → 极速空间转移叠加压抑 → 忍耐到极限释放超自然破坏力','','','34146477','202170','','故事类','jinu','忍住烫伤的疼痛不叫出声','','','','/thumbs/016.jpg','');
INSERT INTO videos VALUES(17,'2026-03-27','忍痛轮椅逃亡-蛋版','','http://www.youtube.com/watch?v=GLHn7q5Oat0','scripts/988忍痛轮椅逃亡-蛋版.md','2026-03-27 01:21:30','2026-03-29 02:17:01','#rumi #jinu #funny #kpopdemonhunters #kpop','24','2026-03-20','jinu恶作剧吓唬正在煎蛋的rumi，导致煎蛋飞出烫到jinu光脚。rumi捂住他的嘴示意别吵醒沙发上三只猫，将jinu按上轮椅推着狂奔穿越郊区、时代广场、花海和冰面。抵达极寒雪山，jinu释放毁天灭地的尖叫，声波震碎巨大冰山并掀起海啸。','Jinu在厨房从背后突然大吼吓唬正在煎蛋的Rumi，Rumi受惊，锅中煎蛋飞出精准掉在Jinu赤裸的光脚上，Jinu痛苦捂嘴强忍','突发意外, 滑稽疼痛','荒诞, 搞笑','情绪压抑-爆发：煎蛋烫脚起因+三只猫禁声限制+多极端地形叠加压抑，最终冰山粉碎释放','隐忍爆发','意外伤害 → 荒诞的禁声限制 → 极速空间转移叠加压抑 → 忍耐到极限释放超自然破坏力','换皮型改编','保留核心机制（隐忍爆发+轮椅逃亡+超自然破坏），将起因从热汤改为煎蛋，禁声对象从企鹅玩偶改为三只猫，终局从火山喷发改为冰山粉碎+海啸','32645911','167007',16,'故事类','jinu','忍住烫伤的疼痛不叫出声','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/017_忍痛轮椅逃亡-蛋版.mp4','/thumbs/017_GLHn7q5Oat0.jpg','');
INSERT INTO videos VALUES(18,'2026-03-27','大小道具对决','','https://www.youtube.com/watch?v=1MBftPiwgyA','scripts/989大小道具对决.md','2026-03-27 01:22:07','2026-03-29 02:16:58','😂❓¿Grande o Pequeño? ¿Cuál elegirías tú? #kpop #kpopdemonhunters #funny #rumi #jinu','50','2026-03-15','jinu与rumi在蒙面裁判监督下三轮大小道具盲选对决。首轮涂口红，jinu选大滚筒糊满mira全脸，rumi用小刷子获胜。次轮挡墨水，jinu选迷你伞被浇黑，rumi用大伞防御成功。终局剥葡萄，rumi徒手精细剥下完整葡萄皮，jinu用巨型青龙刀劈碎葡萄。rumi捧杯获胜，jinu彻底溃败大哭。','蒙面裁判宣布开始，Jinu拍桌抢先夺走巨型红漆滚筒，Rumi无奈只能拿起桌上剩下的迷你化妆刷','冲突对峙, 异常物品','荒诞, 搞笑, 竞赛','三轮竞赛+尺寸错配：每轮通过大小道具与精细任务的错配制造必然翻车，三轮递进强化"大≠好"的反直觉笑点','尺寸错配竞赛','呈现大小两个道具 → 角色凭直觉选大 → 精细任务中大道具必然翻车 → 多轮重复强化反讽','','','47742157','507965','','故事类','jinu','在大小道具盲选对决中赢过rumi','rumi','在对决中赢过jinu','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/018_大小道具对决.mp4','/thumbs/018_1MBftPiwgyA.jpg','');
INSERT INTO videos VALUES(19,'2026-03-27','巨型榴莲追逐','','http://www.youtube.com/watch?v=GfWo8kHdWKk','scripts/990巨型榴莲追逐.md','2026-03-27 01:22:33','2026-03-29 02:16:56','Poor Jinu 😂🏃‍♂️💨#kpop #funny #rumi #jinu','8','2026-03-16','rumi和mira在坡顶失手使大量水果滚下山坡。坡底jinu迅速侧躺用身体拦住果群，得意地在果堆上单手托腮休息。突然后方传来轰鸣，三颗巨型CG榴莲滚来，jinu惊恐起身向山下狂奔。','rumi和mira在坡顶仰头惊声尖叫，手中水果袋底骤然爆裂，大量水果哗然倾泻而出滚落山坡','突发意外','荒诞, 搞笑','反转升级：先用小水果建立安全感，角色得意休息时突然出现CG巨型危险物打破惬意，制造从享受到逃命的极端反差','惬意打断','角色化解小危机 → 得意享受 → 更大更荒诞的危机突然降临 → 从享受瞬间切换为逃命','','','86275599','267383','','故事类','jinu','拦住滚落的水果并活命','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/019_巨型榴莲追逐.mp4','/thumbs/019_GfWo8kHdWKk.jpg','');
INSERT INTO videos VALUES(20,'2026-03-27','Rumi的妈咪','','https://www.youtube.com/shorts/IT9Qu32MUnQ','scripts/991Rumi的妈咪.md','2026-03-27 01:22:58','2026-03-29 02:16:54','Rumi''s MOMMY Left Jinu COMPLETELY SPEECHLESS! 😱','9','2026-03-15','Jinu抱着穿婴儿服的Rumi在樱花树下野餐。Rumi突然指着前方大喊Mommy，Jinu疑惑转头。肌肉壮汉Abby赤裸上身仅穿粉色碎花围裙端着纸杯蛋糕欢快跑来喊Come to mommy sweetie。Jinu极度震惊目瞪口呆。','Jinu在樱花树下抱着穿婴儿连体服、嘴含蓝色奶嘴的Rumi野餐，Rumi突然一脸惊喜地指向画外大喊"Mommy！"','提出疑问','荒诞, 搞笑','悬念+身份反差：先用Baby Rumi喊妈妈建立观众预期（温馨场景），再用肌肉壮汉穿围裙登场彻底打破期待','身份反差','正常称呼/身份 → 建立预期 → 实际登场者的外形与预期极端不符 → 旁观者震惊反应','','','166562218','735963','','故事类','jinu','照顾穿婴儿服的rumi','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/020_Rumi的妈咪.mp4','/thumbs/020_IT9Qu32MUnQ.jpg','');
INSERT INTO videos VALUES(21,'2026-03-27','抢座陷阱','','https://www.youtube.com/shorts/t7SJTBe6_60','scripts/976抢座陷阱.md','2026-03-27 01:27:29','2026-03-29 02:16:52','Rumi thought Jinu needed some company, but... 😄🤣','25','2026-03-11','五人拿着零食抢座位，Jinu没抢到失落坐墙角吃零食。Rumi走来微笑陪伴，Jinu感谢后突然推开Rumi抢占她的座位并得意大笑。被推开的Rumi冷笑掏出遥控器按下红按钮，两条黑色皮带瞬间将Jinu绑死在椅子上。Zoye、Mira、黄帽男和Rumi端着巨大草莓蛋糕狠狠砸在Jinu脸上。','Zoye、Mira、黄帽男、Rumi和Jinu五人手拎零食同时冲向餐桌疯狂抢座，混乱碰撞，Jinu落败没抢到','冲突对峙','荒诞, 搞笑','善意陷阱+暗线反杀：先用示弱建立信任，制造背叛反转，再通过暗线道具（遥控器）揭示一切都是圈套','善意陷阱','假装示弱/施恩 → 诱导目标暴露真面目 → 触发预设惩罚机关 → 群体围攻制裁','','','22239347','118765','','故事类','jinu','抢到一个座位','rumi','惩罚背叛自己好意的jinu','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/021_抢座陷阱.mp4','/thumbs/021_t7SJTBe6_60.jpg','');
INSERT INTO videos VALUES(22,'2026-03-27','拔箭插箭','','https://www.youtube.com/shorts/AkseDCe-kAo','scripts/977拔箭插箭.md','2026-03-27 01:27:56','2026-03-29 02:16:49','Does Rumi Owe Jinu a Thank You? #funny #rumi #jinu','13','2026-02-28','身受重伤的rumi背靠废墟石墙瘫坐，胸口插着长箭。jinu焦急跑来说要救她，直接双手拔出箭，rumi凄厉惨叫质问为什么拔出来。jinu看着带血箭头无辜说以为应该拔出来，随后又果断将箭重新扎回rumi胸口。rumi二次惨叫后虚弱哀求别碰，jinu一脸迷茫看镜头问我做错什么了吗。','rumi背靠废墟石墙瘫坐地上，胸口插着长箭，表情极度痛苦虚弱。jinu从远处满脸焦急地狂奔而来，大喊"Rumi, I''m here to save you！"','冲突对峙, 生命威胁, 身体异常','荒诞, 搞笑','好心办坏事×2：通过角色对常识（贯穿伤不能拔）的彻底无知，将救援变成二次伤害，用清澈的愚蠢对比受害者的绝望制造地狱笑话','好心二次伤害','角色受伤 → 救援者用错误常识施救 → 造成更大伤害 → 试图补救反而重复伤害 → 全程毫无自知','','','23357116','108255','','故事类','rumi','活下去、让jinu别乱碰箭','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/022_拔箭插箭.mp4','/thumbs/022_AkseDCe-kAo.jpg','');
INSERT INTO videos VALUES(23,'2026-03-27','脱毛膏与Xbox烤面包机','','https://www.youtube.com/shorts/ZYDU8JszKQM','scripts/978脱毛膏与Xbox烤面包机.md','2026-03-27 01:28:28','2026-03-29 02:16:47','This hair mask is literal magic! #kpop #jinu #funny#rumi','51','2026-03-12','Rumi向Jinu展示魔法发膜让头发发光。Jinu兴奋去化妆柜找发膜，误拿红色脱毛膏涂满头，瞬间变光头。Rumi嘲笑后给他扣上假发。Jinu因光头决定宅家，要求Rumi去工具房拿Xbox和HDMI线。Rumi面对一堆外观相同的黑线随意拿了一根。Jinu发现拿的是烤面包机电源线而非HDMI。Rumi耸肩将线插上Xbox并在顶部放入吐司，伴随叮声烤好的吐司从Xbox弹出。','Rumi坐在沙发上向Jinu展示发出魔法般光芒的紫发，称其为魔法发膜，Jinu惊奇地前倾凑近查看','身体异常','荒诞, 搞笑','双线误用+暗线揭晓：前半段脱毛膏误用制造光头笑点，后半段线缆误拿揭露Xbox是烤面包机的隐藏暗线，两段误用形成结构对称','连环误用','误用道具A造成灾难 → 因灾难引发新任务 → 新任务中再次误用道具B → 误用B意外揭露隐藏真相','','','20082980','158792','','故事类','jinu','找到发膜让头发发光','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/023_脱毛膏与Xbox烤面包机.mp4','/thumbs/023_ZYDU8JszKQM.jpg','');
INSERT INTO videos VALUES(24,'2026-03-27','吃辣喷火','','https://www.youtube.com/shorts/vJFebbsi8WU','scripts/979吃辣喷火.md','2026-03-27 01:29:02','2026-03-29 02:16:45','Jinu exaggerating? #kpop #funny #rumi #jinu','29','2026-03-18','rumi满脸通红吃极辣汤面，jinu吐槽她太夸张后夺过筷子吃了一大口并强装不辣。jinu脸瞬间憋红嘴唇夸张肿胀，仰头喷出烈火。冲向水槽狂饮整壶水无果，趴在桌上继续喷火将蔬菜全烧成爆米花。jinu一路狂奔至户外寻找水源，跑到湖边将头扎进水中，高温瞬间引发蒸汽爆炸，腾起蘑菇云。rumi站在高层阳台端着爆米花边吃边嘲讽。','rumi在厨房满脸通红、大汗淋漓地吃着极辣红色汤面，Jinu走近吐槽"Rumi, you are exaggerating"，随后夺过筷子大口吃下，强装镇定说"Not spicy at all"','异常行为, 滑稽疼痛','荒诞, 搞笑','打脸升级+暗线伏笔：先用jinu的"不辣"立Flag，再通过喷火→喝水无果→烧出爆米花→蘑菇云不断升级荒诞感，爆米花成为首尾呼应的闭环伏笔','打脸连锁升级','角色吹嘘/质疑 → 立即被打脸 → 自救失败不断升级 → 超自然灾难级后果 → 暗线伏笔完成首尾闭环','','','22883053','132573','','故事类','jinu','证明自己不怕辣','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/024_吃辣喷火.mp4','/thumbs/024_vJFebbsi8WU.jpg','');
INSERT INTO videos VALUES(25,'2026-03-27','真假Rumi2','','https://www.youtube.com/shorts/LoQRs8W-BX4','scripts/980真假Rumi2.md','2026-03-27 01:29:35','2026-03-29 02:16:43','Two Rumis💨 Who is the real? #kpop #rumi #kpopdemonhunters','28','2026-03-06','红衣Rumi在床上对镜头比嘘后释放绿色毒气，Jinu被熏醒发现两个Rumi。两人互指对方是放屁假货。Jinu端来焦黑章鱼让她们试吃，蓝衣Rumi吃后中毒喷出绿气倒下。四人欢呼抓到假货，Jinu和Zoye将昏迷蓝衣Rumi扔出大门。红衣Rumi对镜头比嘘，变身为Mira揭示真相。','红衣Rumi在床上面对镜头神秘比"嘘"，随即释放出绿色毒气，Jinu惊醒被熏到，震惊发现床上竟有红蓝两个Rumi','异常行为','荒诞, 搞笑','真假鉴别+双重反转：先设疑（两个Rumi），再用测试制造误判（蓝衣被冤），最后终极反转揭示真凶是第三方Mira','伪装揭穿','角色A伪装成角色B行动 → 各种行为暴露不合理 → 真正的B出现 → A原形毕露受罚','换皮型改编','保留核心机制（放屁→真假鉴别→章鱼测试→驱逐→Mira变身），场景从明亮卧室改为同类卧室，角色服装细节微调，黄帽男替代Romance参与判定','22938826','136038',14,'故事类','jinu','找出谁是假Rumi','mira','伪装成红衣Rumi不被识破','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/025_真假Rumi2.mp4','/thumbs/025_LoQRs8W-BX4.jpg','');
INSERT INTO videos VALUES(26,'2026-03-27','电梯盲盒','','https://www.youtube.com/shorts/5qtsLt151tA','scripts/972电梯盲盒.md','2026-03-27 01:31:04','2026-03-29 02:16:41','The Elevator Surprise Box Challenge! #rumi #funny','41','2026-03-05','rumi、romance与mira同乘电梯。电梯开门mira步出，天花板掉落大量纸币，mira欢呼跑走。rumi按下3层按钮，门开出现两名abby肌肉男将rumi公主抱走。独留的romance许愿富婆到来，门开进来穿豹纹裙红皮草的大妈。两人对视大惊——互相认出是母子。妈妈暴怒揪住romance耳朵质问花了多少钱买盲盒，一路拖出电梯。','rumi、romance与mira同乘不锈钢电梯，三人正面朝镜头挥手打招呼，笑容灿烂','提出疑问','荒诞, 搞笑','盲盒递进+身份反转：每次开门揭晓不同奖品（纸币→肌肉男→大妈），前两次建立正向期待，第三次用母子身份认出制造终极反转','盲盒递进','封闭空间+按键触发随机事件 → 前N次正向奖励建立期待 → 最后一次出现远超预期的负面结果 → 身份反转加倍惩罚','','','16669724','196167','','故事类','romance','希望电梯门后出现好运','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/026_电梯盲盒.mp4','/thumbs/026_5qtsLt151tA.jpg','');
INSERT INTO videos VALUES(27,'2026-03-27','金鸭盲盒','','https://www.youtube.com/shorts/QeeMJxhydco','scripts/973金鸭盲盒.md','2026-03-27 01:31:36','2026-03-29 02:16:39','Which roast duck would Rumi choose?​😱#kpop #kpopdemonhunters #rumi #jinu','14','2026-03-20','jinu和rumi面前各有金色锡纸包裹物。rumi撕开露出金色烤鸭，咬下一口伴随金属撞击声嘴角流血大喊这是金属。jinu撕开发现紫色气球，被rumi嘲笑。jinu双手拍爆气球，掉出真正烤鸭。rumi突然意识到金属烤鸭是纯金的惊呼，jinu立刻抢过金鸭试图咬。rumi趁机夺走真烤鸭大口吃起来。','jinu和rumi坐在桌前，两人面前各有一个金色锡纸包裹的神秘物品，rumi兴奋地撕开自己的锡纸','异常物品, 提出疑问','荒诞, 搞笑','多重反转+价值错位：金色烤鸭→咬不动（反转1）→气球里藏真鸭（反转2）→金属是真金（反转3）→抢金鸭丢真鸭（反转4），连续反转制造价值判断的喜剧','价值连环反转','盲盒揭晓A看似好实际坏 → 盲盒揭晓B看似坏实际好 → A暗藏更高价值 → 角色为抢A放弃B → 旁人轻松获得B','','','19853035','85338','','故事类','jinu','拆到好的盲盒奖品','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/027_金鸭盲盒.mp4','/thumbs/027_QeeMJxhydco.jpg','');
INSERT INTO videos VALUES(28,'2026-03-27','爬发怒剪','','https://www.youtube.com/shorts/4wuxwcORWgQ','scripts/974爬发怒剪.md','2026-03-27 01:32:08','2026-03-29 02:16:37','Kak Rumi Emosi, Panjat Rambut yang mirip Miliknya 😆‼️Endingnya serem','27','2026-03-08','rumi发现树上垂下巨大紫色麻花辫，怒斥其模仿自己发型后跳上辫子攀爬。眼镜男孩认出这是神圣头发为救rumi也跳上。rumi途中喝完饮料将空杯扔下，眼镜男孩接住后空杯变满杯开心喝下。rumi爬到树顶发现紫发长在白发怪物头上，不但不怕反而嫉妒其发型更酷，掏出巨型剪刀剪断紫发后仰面跳下大笑逃走。','rumi发现树上垂下一根巨大的紫色麻花辫与自己完全相同，愤怒指着它怒斥"模仿我的发型"，随即跳上辫子开始向上攀爬','异常物品, 冲突对峙','荒诞, 搞笑','错位动机+反套路：rumi的攀爬动机不是好奇而是愤怒（模仿发型），到达终点不是害怕怪物而是嫉妒并物理剪断，全程反英雄式行为制造笑点','错位动机反套路','角色因错误动机发起行动 → 途中产生喜剧副产品 → 到达终点发现真相 → 用完全反套路的方式解决问题','','','17575307','88953','','故事类','rumi','找到模仿自己发型的源头','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/028_爬发怒剪.mp4','/thumbs/028_4wuxwcORWgQ.jpg','');
INSERT INTO videos VALUES(29,'2026-03-27','学鸭走路','','https://www.youtube.com/shorts/51ekJ6dSyxA','scripts/975学鸭走路.md','2026-03-27 01:32:44','2026-03-29 02:16:35','Who Deserves the Duck？#kpop #rumi #mira #zoey #jinu','63','2026-02-28','romance在公交车上将发光金蛋抛出窗外，jinu在街头接住带回公寓。金蛋在rumi、mira、zoye注视下发光碎裂孵出小黄鸭。女孩们抢夺，jinu提出挑战：谁学鸭子走路最像鸭子就归谁。rumi四肢着地爬行，鸭子呆萌无反应；mira蹲跳摔倒，鸭子从领口探出张望；zoye半蹲扭胯模拟翅膀快走后抛媚眼，鸭子张嘴嘎叫。jinu最后向观众发问谁有资格得到鸭子。','粉发男生romance坐在公交车靠窗位置，将一颗闪闪发光的金蛋随手从窗口抛出','异常行为, 异常物品','荒诞, 搞笑','竞赛+评委反应：三轮挑战中穿插鸭子作为评委的反应镜头（呆萌→探头→嘎叫），用动物反应制造喜剧节奏，结尾向观众抛出互动钩子','竞赛评委反应','设定荒诞挑战规则 → 多角色依次表演 → 每轮穿插评委（动物）反应镜头 → 观众投票式开放结局','','','16758638','170317','','故事类','jinu','赢得模仿小鸭走路的挑战','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/029_学鸭走路.mp4','/thumbs/029_51ekJ6dSyxA.jpg','');
INSERT INTO videos VALUES(30,'2026-03-27','巧克力灵魂','','http://www.youtube.com/watch?v=NyGtCqihIAA','scripts/968巧克力灵魂.md','2026-03-27 01:43:56','2026-03-29 02:16:33','🍫 The most tragic (and funny) snack fail! #Rumi #Jinu','16','2026-03-02','Rumi在厨房吃巧克力，被画外Jinu大喊吓到噎住后仰摔落地板昏迷。Jinu满脸笑容端两盒泡面跑进来喊这是她最爱的面。Rumi的半透明幽灵从躯体升起悬空吸食泡面，Jinu全程注视幽灵吃完并看着它返回躯体。幽灵消失后，Jinu低头看着一动不动的躯体，笑容消失发出悲伤呜咽。','Rumi站在厨房料理台上悠闲地吃巧克力，画外Jinu突然大喊Rumi名字，Rumi受惊被噎到，失衡后仰摔落地板昏迷','突发意外','荒诞, 搞笑','意外致死+灵魂出窍+悲喜反转：惊吓噎食导致荒诞死亡→灵魂出窍吃面→灵魂回归后Jinu悲伤呜咽，从搞笑转为黑色幽默','食物执念','角色因意外失去行动力 → 美食出现 → 对食物的执念超越生死/物理限制 → 产生超自然反应','换皮型改编','保留核心机制（意外致死→灵魂出窍吃面），将起因从绿乌龟零食改为巧克力，触发方式从Jinu喊名字吓到改为类似，结尾增加悲伤呜咽的黑色幽默','17267161','76412',13,'故事类','rumi','吃到巧克力','jinu','用突然大喊吓唬rumi','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/030_巧克力灵魂.mp4','/thumbs/030_NyGtCqihIAA.jpg','');
INSERT INTO videos VALUES(31,'2026-03-27','婴儿认妈','','https://www.youtube.com/watch?v=ymCdFzqeEXE','scripts/969婴儿认妈.md','2026-03-27 01:44:24','2026-03-29 02:16:31','She can tell who the real Rumi is.😬#kpop #funny #kpopdemonhunters #rumi','7','2026-03-12','jinu抱着紫发婴儿站中间，左右两侧背对镜头站着两个一模一样的紫发rumi。婴儿指向左侧喊Mama，左侧rumi转身面无表情冷漠，婴儿大哭。jinu转向右侧，右侧rumi转身灿烂微笑，婴儿破涕为笑。突然魔法切换，jinu跌坐地上，右侧真rumi抱着婴儿，左侧冷漠rumi变回mira原形得意摊手。jinu绝望大喊Not again。','jinu双手抱着一个紫色麻花辫婴儿站在中央，左右两侧各站着一个背对镜头的紫发女生，婴儿突然伸手指向左侧喊"Mama"','提出疑问','荒诞, 搞笑','婴儿鉴别+身份反转：用婴儿的情绪反应（哭/笑）作为真假判断工具，最终揭示一切是mira和rumi联手的恶作剧','伪装揭穿','角色A伪装成角色B行动 → 各种行为暴露不合理 → 真正的B出现 → A原形毕露受罚','','','21392674','74259','','故事类','jinu','让婴儿认出真正的mama','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/031_婴儿认妈.mp4','/thumbs/031_ymCdFzqeEXE.jpg','');
INSERT INTO videos VALUES(32,'2026-03-27','粉色蘑菇云','','http://www.youtube.com/watch?v=XwkbZrV9fOI','scripts/970粉色蘑菇云.md','2026-03-27 01:44:54','2026-03-29 02:16:29','Much Powder? #kpop #funny #rumi #jinu','21','2026-03-13','rumi在房间化妆涂了大量散粉，jinu凑近亲吻脸颊时吸入大量粉色散粉。此后jinu嘴里持续不受控地咳出粉色烟雾：走出公寓→走在街头→健身房硬拉→骑黄色单车。骑车途中回头发现身后的粉色烟雾汇聚成核爆级蘑菇云向自己追来，吓得凄厉尖叫疯狂踩车逃命，路人四处逃窜。','rumi坐在房间里拿粉扑给自己化妆，脸上散粉涂得极度夸张。jinu从背后凑近准备亲吻脸颊，却意外大口吸入大量粉色散粉，惊恐后仰咳出一大团粉色烟雾','亲密互动, 异常行为','荒诞, 搞笑','日常起因+渐进升级+灾难反噬：从亲吻吸粉的小事件开始，通过多场景展示吐粉成为常态，最终粉雾累积成蘑菇云追击制造灾难级高潮','日常累积灾难','日常微小事件 → 产生持续性荒诞症状 → 症状在多场景中不断累积 → 累积量突破阈值引发灾难级后果 → 反噬追击','','','17281827','78288','','故事类','jinu','正常生活不被粉色烟雾骚扰','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/032_粉色蘑菇云.mp4','/thumbs/032_XwkbZrV9fOI.jpg','');
INSERT INTO videos VALUES(33,'2026-03-27','发膜误食','','https://www.youtube.com/shorts/BhOIQFxfxEE','scripts/971发膜误食.md','2026-03-27 01:45:24','2026-03-29 02:16:26','#kpop #rumi #funny #jinu','13','2026-03-14','jinu在海边用木勺搅拌装满绿色泥状物的玻璃罐。rumi伸手挖走一块说是抹茶酱并品尝后微笑说味道不错。jinu焦急大喊不并将绿泥拍在自己头顶，举起罐子展示上面的绿茶控油发膜字样。rumi整张脸变绿嘴里吐绿色泡沫，双手掐住脖子痛苦仰头，幽灵动画从口中飞出升天。','jinu在海边手捧装满绿色泥状物的玻璃罐用木勺搅拌。rumi的手突然伸入画面，用手指挖走一块绿泥，说这是抹茶酱','异常行为, 提出疑问','荒诞, 搞笑','误食揭晓+夸张后果：先用抹茶酱的误判建立安全感，再通过拍头+展示罐身揭晓发膜真相，最终用变绿+灵魂出窍的夸张后果制造笑点','误食暗线','物品A外观酷似食物B → 角色误食 → 享受后被揭示真相 → 产生夸张的超自然中毒后果','','','17831255','77584','','故事类','jinu','阻止rumi误食发膜','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/033_发膜误食.mp4','/thumbs/033_BhOIQFxfxEE.jpg','');
INSERT INTO videos VALUES(34,'2026-03-29','丧尸爆发预言','','http://www.youtube.com/watch?v=d-H6WlHZ7W4','scripts/0967-影视拆解报告：Zombie Outbreak.md','2026-03-29 02:01:35','2026-03-29 19:45:14','Zombie Outbreak in 2 Hours? #rumi #kpopdemonhunters','59','2026-03-08',unistr('00-01s：rumi正在熟睡，画面昏暗。数双苍白、布满青筋的僵尸之手从黑暗中伸出，正要抓向她的脸。rumi猛地睁开双眼，大口喘气，从噩梦中惊醒。她惊魂未定地低声呢喃："no\u000ahelp\\..."，意识到这只是个梦。\u000a\u000a02-06s：rumi起身后，在昏暗的走廊/房间转角突然撞见了一个和自己长得一模一样的女子（先知rumi）。对方穿着深黑色机能风外套，眼神凌厉。rumi极度震惊，身体后缩，颤声质问："who\u000aare you why do you have my face?"\u000a\u000a07-11s：先知rumi步步紧逼，语气严厉且不容置疑："A global zombie outbreak\u000astarts in 2 hours. Your dreams, they\\''re all real."\u000a她宣称受上帝指派来救她，随后猛地推了rumi一把，吼道："now move!"\u000a\u000a12-15s：先知rumi继续下达指令，要求rumi去寻找物资并通知Mira、Zoye和Shajoba小分队的男生们。她强调所有人必须在下午6点前赶回家，语气极其紧迫。\u000a\u000a16-22s：rumi冲到Zoye的房间。Zoye穿着白色抹胸和牛仔短裙，正神情轻松地整理/折叠床上的衣服。rumi满头大汗，语速极快地警告丧尸爆发还有90分钟，要求她囤粮锁门。Zoye停下动作，满脸困惑和不安，反驳道："zombies\u000ain real life that\\''s impossible you\\''re scaring me for no reason"。\u000a\u000a23-31s：rumi顾不得多说，拍打Mira的房门。穿着红色亮片短裙、戴着金色夸张耳环的Mira一脸不耐烦地开门。rumi焦急地诉说真相，但Mira冷笑一声，眼神轻蔑，嘲讽道："stop\u000awatching so many movies\\... I think you\\''ve lost your damn\u000amind"。Mira最后愤怒地指着走廊，一把推开rumi："get lost rumi"。\u000a\u000a32-40s：rumi彻底慌了神，身体剧烈抖动。她来到Jinu的住处，Jinu此时正戴着专业电竞耳机，手握白色游戏手柄坐在椅子上专注地打游戏。rumi冲过去打断他，Jinu放下手柄，起步走向rumi，温柔地扶住她的双肩关切问道："what\\''s\u000awrong? you\\''re shaking"。rumi抓住他的手臂，绝望地哭诉病毒将在6点爆发。\u000a\u000a41-50s：Jinu露出一个怜悯且无奈的微笑，伸出手温柔地抚摸rumi的头发，试图安慰她："rooney\u000ayou\\''ve been working too hard lately\\... you\\''re just exhausted and\u000ahaving\u000ahallucinations"。他坚定地认为rumi出现了幻觉，并执意要带她去看医生。\u000a\u000a51-59s：rumi感到前所未有的绝望，她推开Jinu，独自跑到空旷清冷的街道上。她无力地跪倒在地，双手死死抱住头部，在暮色中发出凄厉的尖叫："why\u000awhy won\\''t anyone believe me?! why?!"\u000a背景音乐在绝望的呐喊中达到顶峰并戛然而止。'),'rumi正在熟睡，数双苍白布满青筋的僵尸之手从黑暗中伸出正要抓向她的脸，rumi猛地惊醒大口喘气，低声呢喃no...help...','生命威胁','恐怖, 感动','预言真相无人相信→逐级递增的社交拒绝（困惑→嘲讽→理性否定）→最终孤立崩溃','卡桑德拉困境','真相持有→逐级求助→每一级以不同方式否定→绝望累积→孤立爆发','','','7045272','66747','','故事类','rumi','在2小时内说服所有人准备应对丧尸爆发','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/034_丧尸爆发预言.mp4','/thumbs/034_d-H6WlHZ7W4.jpg','');
INSERT INTO videos VALUES(35,'2026-03-29','抢座位忘恩负义','','https://www.youtube.com/shorts/ugo8CLdveNc','scripts/0968-影视级深度拆解：Never feel sorry for a guy like Jinu!.md','2026-03-29 02:01:35','2026-03-29 02:16:21','Never feel sorry for a guy like Jinu! #rumi #funny #jinu','42','2026-03-07',unistr('在阳光充足的现代公寓内，jinu（黑发偏分）、Romance（粉发）、Mystery（银发）和\u000a    Mira（红色双马尾）端着拉面碗拼命冲向餐桌。jinu\u000a    一边狂奔一边大喊："Quick quick, that\\''s my\u000a    seat!"（快点快点，那是我的位子！）。然而，就在他即将触碰椅子的一瞬间，Mira\u000a    和其他伙伴以更敏捷的动作迅速切入并稳稳坐下。jinu\u000a    猛地刹车，身体由于惯性略微前倾，他僵在原地，双手端着碗，眼睁睁看着最后一把椅子被占领。\u000a\u000a餐桌上，另外四人已经落座并开始大快朵颐。Romance\u000a    甚至发出了"This is insanely\u000a    delicious!"（这简直太好吃了！）的赞叹。jinu\u000a    站在桌边，神情尴尬且落寞，他试图寻找插足的空间却发现桌子已被挤满。他抿着嘴，眼神中流露出强烈的嫉妒与无奈，随后默默转身离开。\u000a\u000a转场后，jinu\u000a    躲进了走廊尽头的白色墙角。他低着头，极度委屈地蹲在冰冷的地板上，将面碗放在膝盖上。他强颜欢笑，对着镜头自我安慰道："It\\''s\u000a    fine. It tastes good eating by myself too. It\\''s really\u000a    funny."（没事，一个人吃也挺好吃的。真的很有趣。）。说这段话时，他的眼眶微微湿润，鼻翼抽动，展现出一种"死要面子"的卑微感。\u000a\u000arumi（紫色麻花辫）端着面碗出现在走廊。她看到蜷缩在墙角的\u000a    jinu，原本平静的表情瞬间变得温柔且富有同情心。她轻声细语地关心道："Why\u000a    are you hiding here all alone? Here, let me join\u000a    you."（你怎么一个人躲在这儿？来，我陪你。）。rumi\u000a    慢慢蹲下身子，准备陪 jinu 一起在地板上吃面。\u000a\u000a就在 rumi 蹲下的一刹那，jinu 的视线越过\u000a    rumi，发现餐厅里 rumi\u000a    刚刚离开的那个位置现在是空的。他的悲伤瞬间清零，双眼瞪圆，瞳孔骤缩，惊叫道："Holy\u000a    crap! An empty seat!"（天呐！一个空位！）。他完全无视了正在关心他的\u000a    rumi，直接像弹簧一样蹦起来，推开 rumi 就往餐桌冲去。\u000a\u000ajinu\u000a    以极高的速度冲回餐厅，拉开空椅子重重坐下。他长舒一口气，脸上洋溢着扭曲的快感："Phew!\u000a    Thank god, finally got a seat. It tastes way better sitting\u000a    down."（呼！谢天谢地，终于有位子了。坐着吃味道好多了。）。他甚至故意在原本的伙伴面前显摆，却没发现身后的空气已经凝固。\u000a\u000arumi\u000a    此时已经从走廊冲到了餐厅，她的善良被彻底利用成了愤怒。她双眼圆睁，牙关紧咬，发出了最后通牒："You\u000a    dare steal my seat?! You\\''re asking for\u000a    it!"（你敢偷我的位子？！你找死！）。\u000a\u000a在众人惊恐的注视下，rumi\u000a    果断地将自己手中整碗热腾腾的拉面倒扣在 jinu 的头顶。金黄色的面条顺着\u000a    jinu 的黑色头发滑下，汤汁溅满了他的白衬衫。jinu\u000a    的表情从得意转为呆滞，彻底沦为笑柄。'),'jinu、Romance和Mira端着拉面碗拼命冲向餐桌，jinu边狂奔边大喊Quick quick, thats my seat！，眼看即将落座却被Mira一步抢先','冲突对峙','搞笑, 荒诞','善良被利用的即时反转→同情心被精准背叛→暴力正义收尾，反差极致','农夫与蛇','角色陷入困境→好心人出现施以援手→角色利用好心人→好心人愤怒惩罚','','','8364024','66671','','故事类','rumi','出于善良陪伴孤独的jinu','jinu','抢到餐桌座位','','/thumbs/035_ugo8CLdveNc.jpg','');
INSERT INTO videos VALUES(36,'2026-03-29','蔬菜变异减肥记','','http://www.youtube.com/watch?v=Fb9A70Y0ooI','scripts/0969-视频专业影视拆解分析报告(1).md','2026-03-29 02:01:35','2026-03-29 02:16:19','Rumi Tried to Make Jinu Lose Weight... But\... #kpop','28','2026-03-19',unistr('Jinu站在居家厨房中，手里拿着一根新鲜长黄瓜。他张大嘴巴狠狠地咬了一口并吞下，就在吞咽动作完成的瞬间，伴随着一道亮黄色的闪电特效和沉闷的撞击声，Jinu的躯干和四肢像弹簧一样向上拉伸，他的头顶重重地撞在天花板上。Rumi在旁边低头记录，猛地抬头，看着已经高出画面的Jinu，嘴巴张成圆形，满脸不可思议。\u000a\u000aJinu由于头部抵住天花板，只能痛苦地低头俯视矮小的Rumi，疑惑地问："等一下，我变高了吗？"。Rumi愤怒地挥舞手中的蓝色圆珠笔，大声吼道："这本来是让你减肥的，不是让你变高的！"。\u000a\u000a两人转移到专业工作室厨房。Rumi从桌上的一盘蔬菜（含生菜、胡萝卜、西兰花）中抓起一整颗西兰花，怼到Jinu脸前："试这个，这个绝对管用"。Jinu眉头拧成疙瘩，视线紧盯着西兰花，闭着眼睛露出痛苦面具般的表情，一口将西兰花冠部咬碎。\u000a\u000a吃完西兰花后，Jinu的右手掌心涌出螺旋状的绿光。在数帧之内，绿光覆盖全身，Jinu的肤色从肉色变成了高饱和度的亮绿色。Jinu惊恐地举起变绿的双手，大喊："宝贝，我变绿了！"。Rumi崩溃地双手抱头尖叫："西兰花，为什么？！"。\u000a\u000a场景切换至客厅一角，Rumi像举着火炬一样举起一根带长绿叶的胡萝卜，神情肃穆："这是最后一个了，我相信它，吃！"。她不由分说地将整根胡萝卜塞进Jinu嘴里。\u000a\u000aJinu面无表情地咀嚼并吞下胡萝卜。瞬间，他的头顶炸出一个直径约80厘米的巨大橙色爆炸头（非洲发型）。Jinu麻木地用手摸了摸如云朵般的假发，Rumi在一旁彻底无语，眼神中失去了光芒。\u000a\u000a画面回到橙色背景的实验区。Rumi端出一个散发金光的粉色撒点甜甜圈。Jinu惊喜地问："那是甜甜圈吗？"。Rumi表情庄重如传教士："这不只是甜甜圈，这是科学。"。\u000a\u000aJinu咬下甜甜圈，画面发生剧烈白平衡偏移。在金光与爆炸特效中，原本肥胖的Jinu消失，取而代之的是浑身肌肉极其夸张的Abby。\u000a\u000aAbby穿着被肌肉撑爆的白色短袖，疯狂地侧向和正面展示肱二头肌，发出震耳欲聋的"Yeah!"声。随后他蹲下身子，对着镜头和身旁瘫坐的Rumi露出自信的笑容并竖起大拇指。Rumi看着手中毫无意义的减肥计划书，眼神空洞地抱怨这药不对症。'),'Jinu站在厨房手持一根新鲜黄瓜，张大嘴巴狠狠咬下一口，吞咽瞬间伴随黄色闪电特效，身体像弹簧一样向上拉伸，头顶重撞天花板','异常行为, 身体异常','搞笑, 荒诞','每次尝试减肥都触发荒诞的基因变异（变高→变绿→爆炸头→变肌肉男），与初始目标完全背离','连环反效果','明确目标→尝试手段→结果与目标完全相反→更换手段→更离谱的反效果→循环升级','','','5264131','34730','','故事类','rumi','帮jinu减肥','','','','/thumbs/036_Fb9A70Y0ooI.jpg','');
INSERT INTO videos VALUES(37,'2026-03-29','长发公主爬塔选择','','https://www.youtube.com/shorts/P49yZ7eCzY4','scripts/0970-视频专业影视拆解分析报告(2).md','2026-03-29 02:01:35','2026-03-29 02:16:14','Jinu Climbed Rumi\''s Hair\... And It\''s Full of','27','2026-03-23',unistr('场景位于一座宏伟的石砌塔楼下。jinu（黑发偏分男生）与一名橙发爆炸头男生（以下称Chuck）站在塔前。塔身上垂下紫、蓝、绿三条巨大的发辫。jinu兴奋地指向紫色发辫，大声说："那肯定是Rumi的头发！我要爬紫色这根！"\u000a\u000aChuck（戴着圆框眼镜，神情夸张）指向绿色的发辫，大喊："好！我选绿色的！那上面肯定住着一个可爱的公主！"两人并排站立，jinu面带自信的微笑，Chuck则张大嘴巴表现出极度的期待。\u000a\u000a两人开始在塔楼外墙上攀爬。jinu抓着紫色发辫，Chuck抓着绿色发辫，动作迅速而敏捷。镜头采用远景，展现塔楼的高耸。\u000a\u000ajinu爬到中途，体力不支。他紧紧抱住紫色发辫，满脸大汗，对着镜头虚弱地说："伙计们，我累了。我需要能量！给我点赞和关注，让我有力气爬到顶端去见Rumi！"他的眼神中透着渴望。\u000a\u000ajinu终于翻过塔顶的石墙，气喘吁吁。Rumi（紫色麻花辫）早已在顶端等候。\u000a\u000aRumi面带温柔的微笑，手里拿着一块沉甸甸的金砖递给jinu，表扬道："你成功了jinu！你真的爬上来了！这是给你的奖励。"jinu双手接过金砖，表情从疲惫瞬间转为狂喜。\u000a\u000ajinu端详着金砖，发出一声惊叹。Rumi突然收起笑容，疑惑地看向窗外下方，问道："等等，Chuck在哪？他怎么还没上来？"\u000a\u000a镜头切回到绿色发辫。Chuck正抓着发辫吃力地往上挪。他皱起眉头，鼻子抽动，嫌弃地说："这味道闻起来像穿旧了的臭运动袜还是什么的......"但他转念一想，"管他呢，如果上面有个可爱的公主，我也要去！"\u000a\u000aChuck奋力一跃，钻进塔顶的窗口。他脸上挂着期待的、甚至有些猥琐的笑容，喊道："你好，我的爱人------"\u000a\u000a画面揭晓，窗口内站着的不是可爱的公主，而是一个皮肤翠绿、身材壮硕、扎着绿色辫子的菲奥娜风格的女性。她面带诡异的微笑，用粗犷的声音回应："你好，我的爱人。"Chuck的表情瞬间凝固，瞳孔地震，随后爆发出惊恐的惨叫。'),'jinu与橙发爆炸头男生Chuck站在石砌塔楼下，塔身垂下紫、蓝、绿三条巨大发辫，jinu兴奋地指向紫辫大喊那肯定是Rumi的头发！我要爬紫色这根！','异常场景','搞笑, 荒诞','颜色选择预设命运→一人获奖一人遭殃→选错颜色的人见到菲奥娜式怪物公主','盲选赌注','多选项呈现→角色基于错误假设选择→过程中暗示选错→揭晓结果天差地别','','','6503230','74980','','故事类','jinu','爬上紫色发辫见到rumi','','','','/thumbs/037_P49yZ7eCzY4.jpg','');
INSERT INTO videos VALUES(38,'2026-03-29','丛林砸手大逃亡','','https://www.youtube.com/shorts/wqYi8IKjz1A','scripts/0971-视频专业影视拆解分析报告.md','2026-03-29 02:01:35','2026-03-29 02:16:10','Poor Jinu got accidentally hurt by Rumi!','43','2026-03-14','','jinu俯身在大石块上小心调整一颗棕色圆形物体，rumi站在他身后双手举起沉重灰色岩石准备向下砸','冲突对峙, 突发意外','搞笑, 荒诞','真实痛苦被强制压制（塞嘴）→跨越荒诞场景（丛林→LV店→沙漠→海滩）→最终释放引发超现实奇观','痛苦压制与释放','痛苦触发→不能叫的理由→长距离压制→释放时的超现实爆发','','','6045858','58911','','故事类','jinu','释放被压制的痛苦尖叫','','','','/thumbs/038_wqYi8IKjz1A.jpg','');
INSERT INTO videos VALUES(39,'2026-03-29','甜甜圈葬礼','','https://www.youtube.com/shorts/offac2nttak','scripts/0972-视频专业影视拆解报告(1).md','2026-03-29 02:01:35','2026-03-29 02:16:07','RIP to Rumi''s favorite donut. 😭💔','39','2026-02-28',unistr('rumi（紫色麻花辫）正沉浸在美味中，开心地咬下一口粉色糖霜甜甜圈。就在她露出满足表情的瞬间，一只蓝猫的爪子突然从画面侧边快速伸出，精准地将甜甜圈从她手中打掉。\u000a\u000a甜甜圈脱手后在灰色地毯上滚动，背景响起了一声猫叫声。\u000a\u000a镜头切换至医院，rumi\u000a    神色崩溃，拼命推着一辆蓝色平车在走廊疾驰。平车上，那块甜甜圈被庄重地安放在无菌布上。身后，mira（红色双马尾）和\u000a    zoye（黑发双丸子头）紧紧跟随，rumi 嘶哑地大喊："Doctor!（医生！）"。\u000a\u000a手术室内，绿衣医生站在缠满绷带的甜甜圈前，沉重地垂下头，宣告了甜甜圈的"临床死亡"："We\u000a    did everything we could. Amen.（我们尽力了。阿门。）"。\u000a\u000a手术室门开，当看到被白布完全覆盖的甜甜圈时，rumi\u000a    仰天长啸，发出绝望的哀号："Donut!（甜甜圈！）"。\u000a\u000a在肃穆的教堂里，mystery（银发/紫发男生）身披神父黑袍，手捧甜甜圈遗照。他哀悼道："Farewell\u000a    dear donut. May your glaze rest in\u000a    peace.（永别了亲爱的甜甜圈。愿你的糖霜安息。）"。rumi\u000a    穿着黑色吊带裙坐在轮椅上，靠在 zoye 肩头，泣不成声。\u000a\u000a雨夜墓地，氛围凄凉。romance（粉发）与\u000a    abby（棕发肌肉男）抬着刻有甜甜圈浮雕的微型黄金棺材。rumi\u000a    抱着遗照，在 zoye 的推动下缓缓行进，哭喊着："Don\\''t go my\u000a    donut!（别走我的甜甜圈！）"。\u000a\u000a在刻有"Escape being a snack"的墓碑前，棺材入土。rumi\u000a    情绪失控跌下轮椅，双手疯狂抓挠泥水，凄惨地咆哮："No!（不！）"。\u000a\u000a画面快速闪过 rumi\u000a    与甜甜圈在一起的快乐点滴：新年烟火下的合影、电影院的陪伴、草地上的野餐，每一幕都充满了讽刺的温馨。\u000a\u000a雷鸣电闪中，mystery\u000a    突然以黄色外卖员身份现身墓地，高举一盒新鲜甜甜圈大喊："Donut\u000a    delivery!（甜甜圈外送！）"。\u000a\u000arumi\u000a    瞬间复活，背景升起金色神光。她双手各持一个粉色甜甜圈，在神圣的 BGM\u000a    中露出了最灿烂的笑容。'),'rumi沉浸在美味中开心咬下一口粉色糖霜甜甜圈，就在露出满足表情的瞬间，一只蓝猫爪子突然从画面侧边伸出，精准将甜甜圈从她手中打掉','突发意外','搞笑, 荒诞','将日常小事（甜甜圈掉地）用极度庄严的仪式感处理（送医→葬礼→入土），荒诞反差制造笑点','小事大办','微不足道的损失→用极端庄严的仪式处理（医院→教堂→墓地）→悲剧感登峰造极→一键复活逆转','','','5797782','31929','','故事类','rumi','悼念并安葬心爱的甜甜圈','','','','/thumbs/039_offac2nttak.jpg','');
INSERT INTO videos VALUES(40,'2026-03-29','不公平竞赛三连','','http://www.youtube.com/watch?v=IPbWHxWijY8','scripts/0973-视频专业影视拆解报告(2).md','2026-03-29 02:01:35','2026-03-29 02:16:04','Who is the winner #rumi #kpop #shortvideo','47','2026-02-27',unistr('视频通过三轮极度不公平的"竞赛"，讲述了角色Jinu在与Rumi的对决中惨败并发现真相的过程。\u000a\u000a- 画面开始，jinu和rumi相对而坐。工作人员递出两个尺寸悬殊的叉子。jinu自信地选择了巨大的银色钢叉，并挑衅地对rumi说："这个大的是我的，那个小的是你的。"rumi接过精巧的小叉子，露出礼貌而略带狡黠的微笑。\u000a\u000a    - 比赛开始，rumi迅速用小叉子叉起盘中的绿葡萄，优雅地送入嘴中咀嚼，表情轻松。\u000a\u000a    - jinu尝试挥动沉重的巨型叉子，但因体积过大且重心不稳，叉尖根本无法精准捕捉盘中的单颗葡萄。他表情狰狞，费力地向下猛刺，结果不仅没吃到葡萄，反而弄得手忙脚乱。\u000a\u000a    - 结果：mira作为裁判宣布rumi获胜，rumi兴奋欢呼，jinu则满脸愁苦。\u000a\u000a- 背景切换到办公室。两人面前是成堆的碎纸屑。\u000a\u000a    - 这一次，jinu试图"反其道而行之"，他主动选择了牙刷，认为精细工具更有效，而rumi拿到了长柄扫帚。jinu自信满满地宣布："这次我肯定赢，我要拿这把牙刷。"\u000a\u000a    - 比赛开始后，rumi挥动扫帚，每一次大范围清扫都带起大片纸屑，动作高效。\u000a\u000a    - jinu蹲在地上，像是在进行考古挖掘，用牙刷一点点拨弄，甚至还认真地刷起了地板。他很快意识到进度极慢，愤怒地质问："按这个速度我们什么时候才能干完？"\u000a\u000a    - 结果：rumi再次欢呼胜利，大捧的碎纸屑如雪花般落在失落的jinu头上。\u000a\u000a- 在华丽的颁奖台场景下，工作人员递上一个深绿色的超大登山包和一个红蓝配色的轻便小书包。\u000a\u000a    - 已经输红眼的jinu孤注一掷，一把抢过两个背包："这轮我不能再输了，两个我都要带上！"rumi在一旁露出惊讶的表情。\u000a\u000a    - mira哨响，两人开始在楼梯间竞速。rumi身轻如燕，提着裙摆快速拾级而上。\u000a\u000a    - jinu背着如小山般的背包，每走一级台阶都伴随着沉重的喘息，汗水流过因极度用力而扭曲的脸部。\u000a\u000a    - 最终，在璀璨的聚光灯下，rumi接过了金色的奖杯。\u000a\u000a    - 结尾反转：jinu瘫坐在楼梯间，疑惑地拉开沉重的登山包拉链，竟然从中掏出了一块厚重的红砖。他愤怒地对着镜头咆哮："这到底是怎么回事？！"'),'公园里jinu和rumi相对而坐，工作人员递出一大一小两个叉子，jinu抢先夺走大叉子，挑衅地对rumi说这个大的是我的，那个小的是你的','异常物品, 冲突对峙','搞笑, 竞赛','三轮竞赛每轮都因jinu的错误选择失败→大叉子叉不起葡萄、牙刷扫不了地、背红砖爬楼→递进式打脸','错误选择递进','多轮竞赛→每轮角色自信选错工具→工具反噬导致失败→最终揭晓被暗算的真相','','','20800758','196062','','故事类','rumi','赢得竞赛','jinu','通过选择大/特殊工具赢得竞赛','','/thumbs/040_IPbWHxWijY8.jpg','');
INSERT INTO videos VALUES(41,'2026-03-29','点石成金的诅咒','','http://www.youtube.com/watch?v=ZdM7Fkc6qQ4','scripts/0974-视频专业影视拆解报告(3).md','2026-03-29 02:01:35','2026-03-29 02:15:01','One Kiss Gave Jinu a Golden Power...but\...#kpop #rumi','22','2026-03-23',unistr('在充满午后阳光的工作室内，Rumi（紫色麻花辫）正专注地为自己涂抹指甲油。Jinu（黑发偏分）深情地俯下身，轻轻亲吻了Rumi正在涂指甲的手指。\u000a\u000a亲吻结束后，Jinu突然感到鼻腔不适，猛地打了一个喷嚏，一股浓郁的金色粉尘随之喷出，击中了桌上的苹果。苹果在一阵耀眼的闪光中瞬间质变为纯金。\u000a\u000aRumi惊叫："这苹果真的是金子吗？"\u000a    Jinu再次剧烈咳嗽，更大规模的金雾喷涌而出，直接覆盖了旁边的布艺沙发。沙发在触碰到金雾的瞬间，从纤维到框架全部变成了沉重的固态黄金。\u000a\u000a两人意识到这种"点石成金"的能力后，陷入了极度的兴奋。他们对着镜头大喊："天哪，我们发财了！"\u000a    并在巨大的落地窗前紧紧相拥、疯狂大笑。\u000a\u000a画面转至街头，Jinu的力量开始失控。他每走一步都在咳嗽，随手一指，路边的黑色豪华轿车瞬间被镀上了一层厚实的黄金。围观群众纷纷惊呼并拿手机记录。\u000a\u000aJinu惊恐地发现自己的右手掌已彻底变为黄金，失去肉体质感。他颤抖着对Rumi说："亲爱的，我的手......"\u000a    Rumi意识到危险，拼命喊道："停下！快停止咳嗽！"\u000a\u000aJinu无法抑制生理反应，在街道上狂奔，路过的邮筒、指示牌在金雾扫过后全部化为金质。他痛苦地哀号："我停不下来！"\u000a\u000a夕阳斜照，Jinu站在街道尽头。原本灰色的城市街道已彻底改变------路面、路灯、成排的自行车以及两侧的建筑外墙全部变成了刺眼的纯金。他孤独地站在这座"金矿中心"，呢喃着："我到底做了什么？"\u000a\u000a镜头逼近Jinu的面部，他的双眼充血，口腔内透出强烈的、无法阻挡的金光，暗示他的内脏和身体内部正在被黄金彻底吞噬。'),'工作室内Rumi专注地为自己涂指甲油，Jinu深情俯下身，轻轻亲吻了Rumi正在涂指甲的手指','亲密互动, 异常行为, 异常物品','荒诞, 感动','点石成金从惊喜到诅咒→能力从小件到大件再到身体→从狂喜到绝望的情绪翻转','迈达斯之触','获得超能力→小规模验证欣喜→能力失控扩大→侵蚀自身→美好变成诅咒','','','7299193','40198','','故事类','jinu','控制住点石成金的能力','','','','/thumbs/041_ZdM7Fkc6qQ4.jpg','');
INSERT INTO videos VALUES(42,'2026-03-29','邋遢变美被骗','','https://www.youtube.com/shorts/E3pvSN0EbBw','scripts/0975-视频专业影视拆解报告.md','2026-03-29 02:01:35','2026-03-29 02:14:59','What happened to Rumi? #kpopdemonhunters #rumi #kpop','28','2025-10-11',unistr('rumi\u000a    正躺在洁白的床上熟睡。她满头散开的紫色长发铺满了整个枕头。镜头特写显示她不仅满脸胡茬，嘴角还挂着食物残渣，甚至有浓重的鼾声。\u000a\u000a一阵急促的敲门声惊醒了\u000a    rumi。她猛地坐起，表情狰狞，愤怒地掀开被子跳下床，头发乱成一团巨大的紫色云雾。\u000a\u000arumi\u000a    冲到门口，通过猫眼向外看。猫眼画面中出现了一个极其英俊的男生\u000a    jinu。jinu\u000a    梳着精致的黑色偏分头，穿着黑色西装，正对着镜头温柔地微笑并眨眼示意。\u000a\u000a看到男神的 rumi\u000a    瞬间从愤怒转为极度恐慌。她低头看向自己糟糕的状态，发出了惊恐的尖叫，立刻转身奔向浴室。\u000a\u000arumi\u000a    开启了极致的"变美工程"。她冲到洗手台前，先是惊恐地对着镜子张大嘴巴，然后开始疯狂剃除浓密的腋毛，紧接着疯狂往脸上泼水洗脸。\u000a\u000arumi\u000a    拿着吹风机对着脸和头发狂吹，尽管此时她脸上依然有胡须，但动作极快，发丝在强风中剧烈摆动。\u000a\u000a转场后，rumi\u000a    完成了华丽变身。她化着精致的韩系妆容，紫色头发编成了整齐的麻花辫。她正对着镜子用刷子扫腮红，最后对着镜子露出满意的甜美微笑。\u000a\u000arumi\u000a    换上了白色的丝绸衬衫和浅蓝色长裤，穿着高跟鞋，优雅自信地走向门口。她深吸一口气，微笑着打开门，期待着见\u000a    jinu。\u000a\u000a门打开后，外面站着的并不是 jinu，而是粉发男生\u000a    romance。romance\u000a    穿着绿色碎花衬衫，手里拿着手机，手机屏幕上正播放着刚才 jinu\u000a    眨眼的视频。romance 还没来得及说话，愤怒的 rumi\u000a    飞起一拳重重击中他的腹部，紧接着又是一记重拳。画面最后，romance\u000a    痛苦地倒在地上，rumi 愤怒地瞪着他。'),'rumi躺在洁白床上熟睡，满头散开的紫色长发铺满枕头，镜头特写显示她满脸胡茬、嘴角挂着食物残渣，还发出浓重的鼾声','身体异常','搞笑, 荒诞','极致的前后反差（邋遢→精致）+期待与现实的落差（以为是男神→其实是手机视频）','变美白忙活','邋遢态暴露→外部刺激触发变美→极速变装完成→开门揭晓刺激是假的→愤怒惩罚','','','169421752','918140','','故事类','rumi','在男神到来前完成变美','romance','用jinu的视频戏弄rumi','','/thumbs/042_E3pvSN0EbBw.jpg','');
INSERT INTO videos VALUES(43,'2026-03-29','LEGO车人质博弈','','http://www.youtube.com/watch?v=GQLuY6o8Ws8','scripts/0976-视频专业影视拆解：Rumi与Jinu的LEGO博弈.md','2026-03-29 02:01:35','2026-03-29 02:14:57','❤️Rumi Finally Got What She Wanted #demonhunters','19','2026-03-14',unistr('在阳光明媚的高层阳台上，rumi双眉紧锁，表情愤怒，右手悬空拎着一辆蓝白相间的LEGO布加迪跑车，威胁要将其扔下楼。\u000a\u000a镜头切到jinu，他一脸惊恐且挑衅，右手紧握着rumi的一支红色口红。jinu大喊："Put\u000a    down my car!（放下我的车！）"，rumi紧接着怒吼："Put down my\u000a    lipstick!（放下我的口红！）"。\u000a\u000ajinu睁大双眼，不可置信地回应："No, you\\''re\u000a    crazy!（不，你疯了！）"。话音刚落，jinu因过度愤怒直接动手将手中的红色口红硬生生掰断。rumi见状冷笑一声，直接松手让LEGO车坠下，但在车下坠数米后，她迅速利用手中隐藏的细绳将车重新拉回阳台------原来她并未真打算扔掉。\u000a\u000ajinu虽然毁了口红，但看到爱车"坠落"的一瞬间由于极度恐慌而心理防线崩溃，他摆手大喊："Wait,\u000a    wait, wait a\u000a    second!（等等，等一下！）"，随即转身冲进室内寻找补偿方案。\u000a\u000ajinu冲进卧室，动作极快，先是在书桌上乱翻，接着跳起来猛推衣柜门，最后在抽屉里疯狂翻找，嘴里念叨着："Anything,\u000a    I just need a gift\\...（管它什么，我只需要一个礼物......）"。\u000a\u000a画面回到阳台。jinu气喘吁吁地回到rumi身边，手里变魔术般掏出一个棕色钱包，从中抽出一张金色的信用卡。\u000a\u000ajinu一脸讨好地递上卡片说："Surprise!（惊喜吧！）"。rumi原本阴沉、撅嘴的脸瞬间绽放出灿烂的笑容，眼睛放光，惊呼："Thanks\u000a    babe!（谢谢宝贝！）"。\u000a\u000arumi开心地收下信用卡，把LEGO车搂回怀里。jinu虽然"损失"了钱财且毁了口红，但总算保住了爱车，两人达成了某种危险的平衡。'),'阳光明媚的高层阳台上，rumi双眉紧锁，右手悬空拎着一辆蓝白LEGO布加迪跑车威胁要扔下楼，jinu一脸惊恐紧握着rumi的红色口红，两人对峙互喊Put down my car！Put down my lipstick！','冲突对峙','搞笑','互相用对方心爱之物作人质→口红被毁→车假装坠落实际有绳→信用卡止损达成和解','人质交换博弈','双方各持对方软肋→威胁升级→一方过激操作→另一方以更高筹码止损→达成新平衡','','','7538286','34680','','故事类','rumi','用LEGO车要挟获取更大利益（信用卡）','jinu','保住心爱的LEGO车','','/thumbs/043_GQLuY6o8Ws8.jpg','');
INSERT INTO videos VALUES(44,'2026-03-29','车内放错歌真香','','http://www.youtube.com/watch?v=bzpjNGA9fz8','scripts/0977-视频专业拆解报告(1).md','2026-03-29 02:28:35','2026-03-29 02:29:05','Cool music #jinu #kpop #rumi #zoey #kenji #mira','21','2026-03-06','','Jinu急匆匆坐进银灰色SUV副驾驶，对蓝色短发女生道歉说Sorry I am late, lets go，女生微笑回应Okay伸手准备开音乐，车内突然传出极其滑稽低幼的猫叫音乐','突发意外','搞笑','尴尬氛围→全员石化→本人试图关闭→被阻止→音乐drop后全员真香狂欢','尴尬真香','公开出丑→极度尴尬→试图挽回→被阻止→意外发现好处→集体真香','','','5411530','35665','','故事类','jinu','阻止关闭音乐，引爆全车嗨翻','','','','/thumbs/044_bzpjNGA9fz8.jpg','');
INSERT INTO videos VALUES(45,'2026-03-29','木雕Mira生日礼物','','http://www.youtube.com/watch?v=finvvp4aNJk','scripts/0978-视频专业拆解报告(10).md','2026-03-29 02:28:35','2026-03-29 02:29:02','Does this birthday gift look good? #kpop','21','2026-03-15',unistr('在阳光明媚的公园草地上，rumi（紫色麻花辫）正专注地使用锤子和凿子雕刻一个等身比例的木质人偶。此时，一名彩虹马尾女孩躲在不远处的粗壮树干后，露出惊讶且疑惑的表情，低声自语："What\u000a    on earth is Rumi doing there?（Rumi到底在那儿干什么？）"。\u000a\u000a镜头切换。rumi戴着黑色半指皮手套，用铅笔和精细工具为人偶勾勒眼部轮廓，眼神极其专注。随后，她换上电动砂轮机，在强烈的阳光背光下为人偶打磨身体，木屑随风飞扬。\u000a\u000a彩虹马尾女孩看到木雕雏形后，表情由疑惑转为惊喜，她张大嘴巴发出一声赞叹，然后兴奋地甩动马尾，快步从树后跑向rumi。\u000a\u000arumi开始为木偶穿上"衣服"------她拿着调色盘，用刷子将木偶的裙子涂成鲜艳的亮橘色。彩虹马尾女孩此时已站在rumi身后，双手托腮，满脸不可思议，赞叹道："What\u000a    is this masterpiece?（这是什么杰作？）"。\u000a\u000arumi转过头，对着镜头露出灿烂的笑容，自豪地回答："It\u000a    is a surprise birthday gift for\u000a    Mira!（这是给Mira准备的惊喜生日礼物！）"。\u000a\u000a彩虹马尾女孩深受感动，双手合十放在唇边，眼角泛起感动的泪光，激动地说："That\u000a    is so cool! Let me help\u000a    you!（太酷了！让我帮你吧！）"。随即两人分工协作，rumi涂抹木偶的饰品，彩虹马尾女孩细心地为人偶涂抹肤色，气氛温馨。\u000a\u000a成品完工。一个栩栩如生的mira木偶立在中央。彩虹马尾女孩拿着写有"LIKE"的蓝色牌子，rumi拿着写有"SUBSCRIBE"的红色牌子，两人在木偶两旁欢快地跳动。画面上方出现"Happy\u000a    Birthday Mira!"的彩虹艺术字，纸屑在空中飞舞，充满了节日的喜悦。'),'阳光明媚的公园草地上，rumi专注地用锤子和凿子雕刻一个等身木质人偶，一名彩虹马尾女孩躲在树后露出疑惑表情，低声自语What on earth is Rumi doing there？','异常行为, 提出疑问','治愈, 感动','手工制作过程展示→第三方视角引入悬念→揭晓是生日礼物→合作完成→温馨结局','手作惊喜揭晓','神秘制作过程→旁观者好奇→逐步揭晓意图→共同参与→成品展示','','','9744196','57801','','故事类','rumi','为mira制作等身木雕生日礼物','','','','/thumbs/045_finvvp4aNJk.jpg','');
INSERT INTO videos VALUES(46,'2026-03-29','人偶rumi被救赎','','https://www.youtube.com/shorts/WiuGUfzX6NI','scripts/0979-视频专业拆解报告(11).md','2026-03-29 02:28:35','2026-03-29 02:28:58','Poor Rumi rescued by Jinu #rumi #jinu #kpop','21','2026-03-10',unistr('在下着雨、霓虹闪烁的繁华都市街道上，一个名为\u000a    rumi\u000a    的紫色麻花辫编织人偶独自站在湿漉漉的地面上。她右手举着一朵鲜红的长茎玫瑰，面带纯真的微笑，用甜美的声音问道："Hi,\u000a    would you like to be my\u000a    friend?"（嗨，你愿意做我的朋友吗？），眼神充满期待。\u000a\u000a镜头中突然出现一双巨大的黑色皮靴（行人的脚）。行人完全无视地面上的小人偶，重重地踩了过去。rumi\u000a    被巨大的冲击力撞倒在积水中，手中的玫瑰花被踩入泥泞。\u000a\u000arumi\u000a    狼狈地坐在水坑里，身体沾满了污泥，她的表情从惊喜转为极度的悲伤和震惊。她低头看着毁掉的玫瑰，哀叹道："Oh\u000a    no, my flower."（噢不，我的花。）。\u000a\u000a此时，黑发偏分的男生 jinu\u000a    走在街上，他背着黑色双肩包，背包带上挂着一个小巧的 jinu\u000a    同款人偶。他注意到了地面上的情况，惊讶地喊道："Look over\u000a    there!"（看那边！），随即快步走过去蹲下，心疼地轻声说："Oh you poor\u000a    little thing."（噢，你这可怜的小家伙。），并温柔地将泥泞的 rumi\u000a    捧起。\u000a\u000a场景切换至温馨的洗手间。jinu\u000a    站在洗手池旁，一边哼着歌一边用小刷子为 rumi\u000a    刷洗身上的污垢。洗手池里充满了细腻的肥皂泡。背包里的迷你 jinu\u000a    也在旁边递肥皂帮忙。jinu 鼓励道："Let\\''s get you cleaned up. You\u000a    will be clean in no\u000a    time."（让我们把你洗干净。你很快就会焕然一新了。）。rumi\u000a    重新露出了灿烂的笑容，感激地回应："Thank you so\u000a    much!"（非常感谢！）。\u000a\u000a转场至室内明亮的客厅。jinu\u000a    换上了一身灰色运动卫衣，双手各举着一个干净如新的编织人偶（左手\u000a    rumi，右手小 jinu），对着镜头兴奋地宣布："What a beautiful day!\u000a    Let\\''s go\u000a    hiking!"（多美好的一天！我们去远足吧！）。画面充满阳光与活力。'),'下着雨霓虹闪烁的都市街道上，紫色麻花辫编织人偶rumi独自站在湿漉漉地面上，右手举着鲜红玫瑰，面带纯真微笑说Hi, would you like to be my friend？','异常物品','治愈, 感动','微小人偶vs巨大人类的视觉压迫→被踩踏激发同情→洗刷污垢的治愈过程→焕然一新的情感升华','弱者救赎','弱小角色求助→被冷漠伤害→英雄出现救助→修复创伤→重获新生','','','5170558','35440','','故事类','rumi(编织人偶)','找到一个愿意做朋友的人','','','','/thumbs/046_WiuGUfzX6NI.jpg','');
INSERT INTO videos VALUES(47,'2026-03-29','巧克力轮胎肌肉男','','http://www.youtube.com/watch?v=J3R2A09Pe0I','scripts/0980-视频专业拆解报告(2).md','2026-03-29 02:28:35','2026-03-29 02:28:54','GYM BRO Destroys Rumi\''s SECRET Dessert! 😱 #funny','29','2026-03-14',unistr('场景位于洒满阳光的后院。rumi（紫色麻花辫）蹲在草地上，双手扶着一个巨大的黑色"轮胎"，并张大嘴狠狠咬向轮胎边缘。身旁的mira（红色双马尾）满脸惊恐，身体后缩，双手紧紧抓着轮胎侧面，大喊："Oh\u000a    my god, that is a tire! You can\\''t eat\u000a    that!"（我的天，那是轮胎！你不能吃那个！）。\u000a\u000arumi停止咀嚼，抬头看向mira，表情轻松甚至带着一丝俏皮，解释道："Relax,\u000a    it\\''s actually chocolate. Just take a bite and\u000a    see."（放松，这其实是巧克力。咬一口看看。）。\u000a\u000amira半信半疑地低头咬向轮胎。当她牙齿切开表层时，内部浓稠的深褐色巧克力浆瞬间涌出。mira瞪大双眼，露出极度惊喜和享受的表情，满嘴沾着巧克力大喊："It\u000a    really is delicious chocolate!"（真的，是超好吃的巧克力！）。\u000a\u000arumi和mira站起身，将"轮胎"留在草地上的白色方布上。rumi指着轮胎说："I\\''ll\u000a    leave the other chocolate for Jinu. Let\\''s go find\u000a    Zoye."（我给Jinu留点，我们去找Zoye吧。）。两人随后兴奋地跑向背景深处。\u000a\u000a肌肉壮硕的abby（棕发肌肉男）走进画面。他看到地上的轮胎，以为是训练器材。他面向镜头，双臂弯曲展示巨大的肱二头肌，发出一声低沉的闷哼，显得自信满满。\u000a\u000aabby深蹲下去，双手扣住轮胎底部，大喊一声"Let\\''s\u000a    go baby,\u000a    lightweight!"（上吧宝贝，轻量级！）。他双腿发力，猛地将巨大的"轮胎"举过头顶。\u000a\u000a就在abby举起的一瞬间，他在顶端用力一捏。原本坚硬的轮胎瞬间崩裂，内部大量的液体巧克力如瀑布般倾泻而下，直接浇在abby的头顶、脸部和赤裸的胸肌上。\u000a\u000aabby整个人被黑色的巧克力浆覆盖，他手里抓着两块破裂的巧克力外壳，眼神呆滞但又透着迷之自豪。他对着镜头憨笑："Did\u000a    I just crush a tire? I am\u000a    Hercules!"（我刚才是不是捏碎了一个轮胎？我是大力士海格力斯！）。\u000a\u000arumi和mira跑回现场。看到满地狼藉和变成"巧克力人"的abby，rumi崩溃地抱头尖叫："That\u000a    was our dessert! You hideous\u000a    idiot!"（那是我们的甜点！你这个丑陋的白痴！）。mira则在旁边张大嘴巴，满脸不可置信。'),'阳光后院，rumi蹲在草地上双手扶着一个巨大黑色轮胎，张大嘴狠狠咬向轮胎边缘。mira满脸惊恐大喊Oh my god, that is a tire! You cant eat that！','异常物品, 异常行为','搞笑, 荒诞','伪装食物设题→品尝揭真相→第三方误当器材→暴力使用→食物爆裂浇身→主人崩溃','伪装道具误用','A将食物伪装成日用品→留给B→C误认为本来用途→暴力使用导致爆裂→A回来发现崩溃','','','7614585','41768','','故事类','rumi','把巧克力轮胎留给jinu','abby','用轮胎健身','','/thumbs/047_J3R2A09Pe0I.jpg','');
INSERT INTO videos VALUES(48,'2026-03-29','误会jinu画木偶','','http://www.youtube.com/watch?v=mHFeeWQwUjk','scripts/0981-视频专业拆解报告(3).md','2026-03-29 02:28:35','2026-03-29 02:28:52','What did Jinu make for the birthday gift?😱#kpop','14','2026-03-23',unistr('rumi（紫色麻花辫）躲在花园的一棵大树后，右手握着一杯冰拿铁。她神色惊恐，双目圆睁，不可置信地看着前方。\u000a\u000a镜头越过树干，前方草坪上，jinu（黑发偏分）正从背后紧紧贴着一个酷似\u000a    mira（红色双马尾）的人影，双手在该人影背部剧烈游走。该人影身穿金色亮片长裙，背对镜头。\u000a\u000arumi怒不可遏，从树后冲出，左手指点着jinu大喊："How\u000a    could you!（你怎么能这样！）"。她手中的咖啡因剧烈动作产生晃动。\u000a\u000arumi扔掉咖啡（画面外），不知从何处掏出一把巨大的绿色水枪，全速冲向jinu。她歇斯底里地吼道："Step\u000a    away from her!（离她远点！）"。\u000a\u000ajinu见状大惊，神色慌张地摆手后退，连声喊着："Wait,\u000a    wait,\u000a    wait!（等下，等下！）"。rumi冲到两人中间，先是推搡开jinu，随后愤而扳住"mira"的肩膀，猛地将她翻转过来。\u000a\u000a随着人影转过来，rumi震惊地发现这根本不是\u000a    mira\u000a    本人，而是一个戴着红色假发、身穿金色礼服的木头模特（木头人）。与此同时，特写镜头揭示了木头人背部的"真相"：它的白色西装外套背部被画上了一个巨大的七彩虹图案，宛如翅膀。\u000a\u000arumi看清是木头人后瞬间石化，张大嘴巴，左手悬在空中，手中的水枪垂下。她尴尬又疑惑地问："What\u000a    is this?（这是什么？）"。\u000a\u000ajinu站在后方，一脸得意与兴奋，右手举起一个彩色调色盘，左手拿着画笔，指向这个木头人说："Your\u000a    gift for Mira!（你给Mira的礼物！）"。\u000a\u000arumi转惊为喜，明白 jinu 其实是在为真正的\u000a    mira\u000a    制作生日惊喜，她露出夸张的笑容，扔掉水枪，开心地尖叫着扑向jinu，两人欢快地拥抱。\u000a\u000a真正的\u000a    mira（红色双马尾）端着一个插满点燃蜡烛的粉色大蛋糕从侧面走入画面。背景天空中飘下彩带纸屑。大家对着木头人（以及镜头）欢笑，画面中心出现大字"HAPPY\u000a    Birthday!"。'),'rumi躲在大树后神色惊恐地目睹jinu从背后紧紧贴着一个穿金色亮片裙的人影，rumi怒不可遏从树后冲出，指着jinu大喊How could you！','冲突对峙, 提出疑问','搞笑','暧昧视角制造误会→愤怒冲突升级→扳过来揭晓是木头人→从暴怒到惊喜的即时情绪翻转','视角误导反转','观察者看到疑似出轨画面→愤怒行动→物理接触揭晓真相（是假人）→情绪180度反转','','','5253377','26243','','故事类','rumi','阻止jinu的疑似出轨行为','','','','/thumbs/048_mHFeeWQwUjk.jpg','');
INSERT INTO videos VALUES(49,'2026-03-29','抢钥匙选错车','','https://www.youtube.com/shorts/rVqmYaqTgEo','scripts/0982-视频专业拆解报告(4).md','2026-03-29 02:28:35','2026-03-29 02:28:50','mira chose a wrong key','16','2026-03-20',unistr('画面中心出现一双男性的手，手中各握一把带有法拉利标志的黑色车钥匙。坐在沙发上的\u000a    rumi（左，紫色长辫）和 mira（右，红色双马尾）同时伸手抓取。\u000a\u000amira\u000a    为了确保拿到心仪的钥匙，先是带有竞争性地拍打（slap）了一下 rumi\u000a    的手将其拨开，随后迅速抓住了右边的钥匙，表情充满志在必得的自信；rumi\u000a    则无奈地拿到了剩下的左边那把。\u000a\u000arumi（紫色长辫）低头翻转手中的钥匙，发现那竟然是一把锈迹斑斑、顶端带有圆孔的陈旧门钥匙。她双眼圆睁，眉头紧锁，露出极度震惊和不敢相信的表情。\u000a\u000amira（红色双马尾）深信自己抢到的是法拉利钥匙，完全没有察觉到异样。她面带得意的神色，起身直接无视了震惊中的\u000a    rumi，迈着夸张且自信的"模特步"向走廊深处（车库方向）走去。\u000a\u000a车库门开启，冷蓝色灯光照射下，走在前面的 mira\u000a    发现面前并没有超跑，而是一辆生锈的破旧儿童三轮车。她站在三轮车前，心理落差导致她张大嘴巴发出了绝望的尖叫："No\u000a    way!"。\u000a\u000a令人意外的是，真正的赢家变成了\u000a    rumi。一辆亮绿色的兰博基尼超跑停在旁边，rumi\u000a    兴奋地从天窗钻出，双手捂脸惊喜尖叫："Oh my god!\u000a    Yeah!"，暗示钥匙在某种规则下发生了反转。\u000a\u000arumi 驾驶绿车疾驰而出。mira\u000a    只能狼狈地跨在那个极小的破旧三轮车上，双腿蜷缩着疯狂蹬车，在后面喊道："Wait\u000a    for me, Rumi!"。'),'画面中心出现一双握着两把法拉利车钥匙的手，rumi和mira同时伸手抢，mira拍开rumi的手抢走右边那把，rumi无奈拿到剩下的左边那把','冲突对峙','搞笑, 荒诞','抢夺时自信选择→模特步离场强化优越感→打开车库发现三轮车→输家反转成兰博基尼车主','盲选反转','多选项呈现→贪心者抢先选择→过程中展示自信→结果揭晓完全反转→赢家变输家','','','15468140','76436','','故事类','rumi','得到好车','mira','抢到最好的钥匙','','/thumbs/049_rVqmYaqTgEo.jpg','');
INSERT INTO videos VALUES(50,'2026-03-29','人偶rumi被霸凌的救赎','','https://www.youtube.com/shorts/6T4HTgVz9gI','scripts/0983-视频专业拆解报告(5).md','2026-03-29 02:28:35','2026-03-29 02:28:48','Todos tratan mal a Rumi 😭（大家都对Rumi很坏 😭）','42','2026-03-11','','阴暗潮湿窄巷中，紫色发辫玩偶rumi蜷缩在破旧小纸箱里，一名神情凶狠的老妇人快步走近，恶狠狠大喊离垃圾远点，随后粗暴掀翻纸箱并一脚将rumi踢飞','异常物品, 冲突对峙','感动, 治愈','递进式霸凌（踢飞→再踢→涂鸦）→错误救助加深创伤→同类出现真正治愈→洗净重生','递进霸凌与救赎','弱者被A伤害→被B再伤害→被C错误救助（二次伤害）→被D真正理解并治愈→重生','','','12437727','372614','','故事类','rumi(编织人偶)','找到真正理解自己的人','','','','/thumbs/050_6T4HTgVz9gI.jpg','');
INSERT INTO videos VALUES(51,'2026-03-29','Buy It三段递进','','https://www.youtube.com/shorts/ekkNtvxxWqI','scripts/0984-视频专业拆解报告(6).md','2026-03-29 02:28:35','2026-03-29 02:28:46','😱 Jinu, Abby, Mystery\... What happened?! 🕵️‍♀️ #kpop','46','2026-02-23','','卡皮巴拉周边店内，Mystery银发男生情绪极度亢奋，在柜台前疯狂跳跃挥手，声嘶力竭反复大喊BUY IT！BUY IT！','异常行为','搞笑, 荒诞','三段平行递进（玩偶→PS5→跑车），每段索要方式升级，最后一段反转为暴力惩罚','撒泼索要递进','角色A向B撒泼索要→方式从温和到疯狂→A以为成功→结果从满足到惩罚递进','','','40917797','348719','','故事类','','','','','','/thumbs/051_ekkNtvxxWqI.jpg','');
INSERT INTO videos VALUES(52,'2026-03-29','秃头变男神骗rumi','','https://www.youtube.com/shorts/TBEHtG4bd8I','scripts/0985-视频专业拆解报告(7).md','2026-03-29 02:28:35','2026-03-29 19:45:14','** Did Jinu Actually Trick Rumi? 😱 #funny #comedy #shorts','','',unistr('1.  开场（0-3s）：\u000a    jinu（此时为中年大叔形象，秃顶且腹部肥大）瘫坐在灰色沙发上吃薯片。他穿着灰色背心和蓝色碎花短裤，脚边堆满了披萨盒、脏衣服和粉色运动鞋。门铃响起，jinu惊恐地看向房门。\u000a\u000a2.  危机出现（3-5s）：\u000a    通过猫眼视角，rumi（紫色麻花辫）出现在门口，笑容灿烂地举着一个草莓蛋糕，大喊："Surprise!\u000a    jinu open up! I brought cake!"（惊喜！jinu开门！我带了蛋糕！）。\u000a\u000a3.  角色独白（5-10s）：\u000a    jinu对着镜子看着自己油腻、秃顶且沾着番茄酱渍的形象，极度崩溃。他双手抱头尖叫，随后转向镜头对观众哀求："Guys,\u000a    like and subscribe! If she sees this bald head, I am dead meat. Save\u000a    me!"（家人们，点赞订阅！如果她看到我这个秃头，我就死定了，救救我！）。\u000a\u000a4.  混乱清理（10-15s）：\u000a    屋外传来重物倒地声。rumi在门外担忧地问："jinu, what was that crash?\u000a    Are you okay in\u000a    there?"（jinu，那是什么碰撞声？你在里面没事吧？）。此时jinu正在疯狂用吸尘器清理客厅，把满地的披萨块和衣服直接塞进冰箱里。\u000a\u000a5.  极限掩饰（15-18s）：\u000a    jinu满头大汗地靠着冰箱门，对门外大喊："Coming babe! Just uh,\u000a    catching a huge bug! 5\u000a    seconds!"（这就来亲爱的！只是......在抓一只大虫子！5秒钟！）。\u000a\u000a6.  极速改造（18-28s）： \\* jinu冲进浴室洗脸。\u000a\u000a    - 他在垃圾桶里翻出一顶黑色假发并戴上。\u000a\u000a    - rumi在门口催促："Hurry up, the strawberries are getting\u000a      sad."（快点，草莓都要变忧郁了。）。\u000a\u000a    - jinu竟然在房间里开始疯狂卧推杠铃，通过"极限泵感"瞬间改变体型，大喊："Coming!\u000a      Just 2 more! 1 more!"（来了！再来两个！最后一个！）。\u000a\u000a7.  男神降临（28-33s）：\u000a    画面一转，镜子中出现了一个英俊、肌肉发达、头发浓密的jinu（男神形象）。他穿上了精致的灰色西装套装，配黑色马甲、白衬衫和叠戴项链。\u000a\u000a8.  结局（33-38s）：\u000a    jinu优雅地打开房门，单手扶门框，深情说道："Ready for you my\u000a    princess. Sorry to keep you\u000a    waiting."（为你准备好了，我的公主。抱歉让你久等。）。原本蹲在地上的rumi看呆了，立刻起跳拥抱jinu，惊喜地感叹："Oh\u000a    my god, jinu, you look\u000a    incredible!"（天哪，jinu，你看起来帅呆了！）。'),'jinu以中年大叔形象（秃顶腹大）瘫坐在灰色沙发上吃薯片，脚边堆满披萨盒和脏衣服，门铃突然响起，猫眼里出现rumi笑容灿烂地喊Surprise！jinu open up！I brought cake！','身体异常','搞笑, 荒诞','极致丑态暴露→外部威胁来临→极限清理伪装（假发+健身）→华丽变身→女友被完美骗过','极限伪装变身','真实丑态暴露→突发访客→疯狂掩饰过程→不可思议的变身完成→对方完全被骗','','','','','','故事类','jinu','在rumi进门前完成从邋遢到男神的极限变身','','','','/thumbs/052_TBEHtG4bd8I.jpg','');
INSERT INTO videos VALUES(53,'2026-03-29','头发钓鱼扣锅','','https://www.youtube.com/shorts/8O1oj2kPU5c','scripts/0986-视频专业拆解报告(8).md','2026-03-29 02:28:35','2026-03-29 02:28:44','Rumi is showing Jinu how to fish by the river\...😱#kpop','13','2026-03-06',unistr('视频开场，rumi驾驶着白色电动车疾驰而来，随后伴随着刺耳的摩擦音完成了一个帅气的紧急刹车，车头剧烈晃动后稳稳停住。romance（粉发男生，头戴黄色针织帽）早已守候在此，情绪激动地举着一块写有"No\u000a    fishing!"的木质告示牌，对着刚停稳的rumi大声咆哮。rumi头顶扣着一个银色金属锅，淡定地反驳："No\u000a    fishing!"。\u000a\u000arumi侧过头，伸出左手指向河边，疑惑地问："Why\u000a    can\u000a    he?"。画面切至河边，jinu（黑发偏分男生）正安静地坐在堤岸边缘，手中握着长长的钓竿，水面上漂浮着一个显眼的黄色浮漂。\u000a\u000a镜头拉回，romance依然举着牌子，身体随着说话节奏上下起伏，嘲讽道："He\u000a    never catches\u000a    anything."。rumi听后嘴角微微上扬，露出一抹充满挑战性的微笑。\u000a\u000arumi快步走向堤岸，背对镜头，右臂大幅度向后摆动，高喊："Watch\u000a    this"。她猛地甩动头上的长紫色麻花辫，发辫如同柔韧的钓线般划过一道弧线，末端精准地甩入河水中。\u000a\u000a特写镜头捕捉到发辫被快速拉起。一条巨大的深蓝色背鳍大鱼死死咬住发辫末端，随着发辫的拉拽，大鱼在空中疯狂扭动身体，透明的水花四处飞溅。\u000a\u000arumi单手拎着大鱼，神情自豪地大喊"So\u000a    easy!"。喊完口号后，rumi迅速摘下自己头顶的银色金属锅，顺势猛地扣在了一旁正目瞪口呆的jinu头上。原本在钓鱼的jinu被重重扣住后瘫坐在地，双手无助地在空中抓挠，画面显得既荒诞又滑稽。最后，三人在河边斜阳下留下了对比鲜明的定格剪影。'),'rumi驾驶白色电动车疾驰而来急刹停下，头顶扣着银色金属锅，romance举着写有No fishing！的告示牌对她咆哮，rumi淡定反驳No fishing！','异常行为','搞笑, 荒诞','禁止钓鱼规则→质疑他可以为什么我不行→用头发钓起巨鱼→顺手把锅扣在合法钓鱼者头上','规则漏洞碾压','规则限制→质疑不公平→用超常手段绕过规则→碾压式成功→顺手欺负正常人','','','8054014','40834','','故事类','rumi','用自己的方式钓鱼','','','','/thumbs/053_8O1oj2kPU5c.jpg','');
INSERT INTO videos VALUES(54,'2026-03-29','红袜子洗衣灾难','','https://www.youtube.com/shorts/w_k3f_Us7BE','scripts/0987-视频专业拆解报告(9).md','2026-03-29 02:33:25','2026-03-29 02:33:55','Why is Jinu acting so strange today? #funny #rumi #kpop','48','2026-03-19',unistr('在光线柔和的客厅里，Rumi\u000a    穿着深绿色丝绸睡衣，额头上戴着金色眼罩，高冷地斜靠在白色布艺沙发上。Jinu\u000a    跪在沙发前的地毯上，满脸堆着讨好的笑容，双手极尽虔诚地为 Rumi\u000a    揉捏小腿。\u000a\u000aJinu\u000a    额头渗出汗珠，他小心翼翼地递过一颗饱满的紫葡萄，凑近 Rumi\u000a    脸庞，声音卑微又温柔："拿去吧，我的女王（Here you go my queen）"。\u000a\u000aRumi 吞下葡萄，眼神瞬间变得犀利。她用手托住\u000a    Jinu 的下巴，眯起眼睛审视他："你今天为什么这么好心？（Why are you\u000a    being so nice today?）"。Jinu\u000a    眼神剧烈闪烁，笑容僵硬地回应："只是因为我太爱你了（Just because I\u000a    love you so much）"。\u000a\u000a画面闪回到浴室。Jinu\u000a    穿着粉色碎花围裙，满头大汗地蹲在地上，用牙刷疯狂刷洗瓷砖缝隙。Rumi\u000a    抱胸靠在门口，冷冷地断定："你肯定做错事了（You definitely did\u000a    something wrong）"。\u000a\u000aRumi\u000a    来到收藏架前，拿起一排粉色公仔。Jinu 紧张得呼吸停滞。Rumi\u000a    盯着他的眼睛说："我一点都不相信你"，话音刚落，她便故意松开手掌，任由公仔在\u000a    Jinu 绝望的注视下摔向地板，瞬间碎裂成片。\u000a\u000aJinu\u000a    发出凄厉的尖叫，面部肌肉因痛苦而扭曲，跪在地上大哭。为了掩盖真正的大错，他一边流泪一边强挤笑容竖起大拇指："没关系，我本来就想扔掉它的"。\u000a\u000aRumi\u000a    察觉到不对，步步紧逼："你到底干了什么？"。Jinu\u000a    极度心虚害怕，身体僵直，颤抖着伸出右手，指向了身后洗衣机所在的方向。Rumi\u000a    冲进洗衣房打开洗衣机，从中掏出一叠原本雪白的衣物，发现它们此刻都染上了大片触目惊心的鲜红迹象。最后，她从湿透的衣物中翻出了一条罪魁祸首------大红色的袜子。\u000a\u000aRumi\u000a    的双眼由于极度愤怒变成了猩红色，瞳孔扩张，面部因咆哮而变形："你死定了！（You\u000a    are a dead man!）"。'),'Rumi穿着深绿色丝绸睡衣戴着金色眼罩斜靠在白色沙发上，Jinu跪在地毯上满脸讨好地为她揉捏小腿','异常行为, 提出疑问','搞笑','讨好铺垫→女方审问试探→摔碎公仔测试心理防线→逼供指向洗衣机→揭晓红袜染衣灾难→终极暴怒','阶梯式逼供','犯错者极力讨好掩饰→审问者逐步试探→故意摧毁犯错者心爱之物观察反应→确认有更大错误→最终揭晓灾难','','','6597392','59231','','故事类','rumi','找出jinu隐藏的错误','jinu','用讨好掩盖洗衣事故','','/thumbs/054_w_k3f_Us7BE.jpg','');
INSERT INTO videos VALUES(55,'2026-03-29','苹果换钱传送门','','https://www.youtube.com/shorts/vl720YvWpho','scripts/0988-视频专业拆解报告.md','2026-03-29 02:33:25','2026-03-29 02:33:53','At the 18-second smile, I knew something was up! #funny','24','2026-03-19','','手术室内，医生jinu将一个红苹果抛向空中试图用嘴接住，苹果失手坠落，直接掉进躺在手术台上的rumi腹部突然裂开的紫色能量传送门中，jinu动作凝固双眼圆睁','身体异常','搞笑, 惊悚','意外触发传送门→投入低价物获高价物→贪婪升级投入美钞→钞票雨狂喜→rumi诡异微笑→传送门反噬吞人','贪婪诱捕','意外发现漏洞→小额试探成功→加大投入→贪婪失控→陷阱反噬→毁灭','','','3611244','18936','','故事类','jinu','利用传送门获取更多财富','rumi','作为传送门的守护者/诱捕者','','/thumbs/055_vl720YvWpho.jpg','');
INSERT INTO videos VALUES(56,'2026-03-29','谁是真正的Rumi','','https://www.youtube.com/shorts/JPgXtORyyOU','scripts/0989-视频专业级影视拆解(1).md','2026-03-29 02:33:25','2026-03-29 02:33:51','Who is the real Rumi😱💻','28','2026-03-16',unistr('画面开场即是高潮。在霓虹交织的电竞房，rumi（紫色麻花辫）的下半身已被显示器内的蓝色粒子漩涡完全吸入。她双手死命扒住粉色桌沿，指关节因用力而发白，面部因极度恐惧而扭曲流泪，凄厉地呼喊："Help\u000a    me Jinu!"。\u000a\u000ajinu（黑发偏分）冲到显示器前。此时\u000a    rumi\u000a    已完全被拉入，只剩下一小截紫色辫子的尾部还露在闪烁的屏幕表面。jinu\u000a    满脸焦急，脱口而出："Rumi, where are you?"\u000a    随后他没有任何退缩，拿着蓝色抹布的右手前伸，整个人顺势果断跳入显示器激起的蓝色数字奇点中。\u000a\u000ajinu坠入了一个深邃、阴暗的工业级服务器电缆隧道。隧道两侧是巨大的、低沉旋转的排风扇。在错综复杂的黑色粗电缆之间，一条长长的紫色辫子如蛇般蜿蜒在金属地面上，充当了指引路径。jinu\u000a    手持强光手电筒，神色慌乱地在电缆堆中匍匐前进，视线死死锁定那条紫色辫子，焦急呼喊："Rumi,\u000a    where are you?"。\u000a\u000a顺着辫子的引导，jinu在隧道尽头发现了一个被红色发光线缆缠绕的"rumi"。她换上了银色液态金属质感的紧身制服，虚弱地被悬挂在机架间，哀求道："I\u000a    am trapped, help me." 就在 jinu\u000a    靠近时，她的瞳孔瞬间充斥红光，面部皮肤如烧焦的纸张般剥落，露出森冷的银色金属终结者骨架。\u000a\u000ajinu意识到中计，在泛着蓝光的数字水面上疯狂飞奔。此时，上方的橙色次元裂缝中出现了mira（红色双马尾），她神色焦虑，拼命挥手呐喊："Jinu\u000a    come back! She is AI!" 揭露了刚才那个"救赎目标"的伪装。\u000a\u000a镜头拉回电竞房。最初那个穿着黄夹克的\u000a    rumi\u000a    依然半身露在屏幕外，但她不再求救，而是露出了一个极其扭曲、邪恶的笑容。下一秒，她的面部皮肤从中心爆裂烧毁，红光闪烁的电子眼直视镜头，画面伴随刺耳杂音彻底崩碎。'),'在霓虹交织的电竞房，rumi下半身已被显示器内的蓝色粒子漩涡完全吸入，她双手死命扒住粉色桌沿，面部因极度恐惧而扭曲流泪，凄厉呼喊Help me Jinu！','身体异常','惊悚, 悬疑','开场即高潮（被吸入）→英雄跳入救援→辫子引导线追踪→发现被困rumi→AI揭露面具烧毁→现实中的rumi也是AI','数字陷阱','真人被吸入虚拟世界→救援者追踪线索→发现的目标是AI伪装→警告揭露真相→现实与虚拟全部沦陷','','','7898088','40710','','故事类','jinu','进入数字世界营救rumi','AI rumi','利用辫子作为诱饵引诱jinu进入陷阱','','/thumbs/056_JPgXtORyyOU.jpg','');
INSERT INTO videos VALUES(57,'2026-03-29','脚底泥雪糕恶作剧','','https://www.youtube.com/shorts/T7JkDm551NY','scripts/0990-视频专业级影视拆解(2).md','2026-03-29 02:33:25','2026-03-29 02:33:49','Zoey Pranks Mira 😱 #kpopdemonhunters #kpop #rumi','7','2026-03-16',unistr('在室内的木质楼梯转角处，zoye（黑发丸子头）坐在台阶上，她的右脚赤裸并抬起，脚底板中心到脚跟部位覆盖着一层厚厚的、带有颗粒感的深褐色干湿混合污泥。zoye\u000a    表情极度狡黠，她不断地向左侧吐出舌头并眯起眼睛，右手紧握一支红绿配色的西瓜雪糕，直接将雪糕的红色果肉面紧贴在自己沾满泥土的脚心，进行快速的上下反复搓动，使泥土均匀且厚重地覆盖在雪糕表面。\u000a\u000a画面切至阳光明媚的客厅，rumi（紫色长发）正斜靠在白色纹理沙发上专注于手机。镜头作为"第一人称视角"缓慢伸出一只戴着金色手镯的手，将那支"加工过"的雪糕递到\u000a    rumi 面前。rumi\u000a    并没有察觉异常，她抬起头，眼神从手机屏幕移动到雪糕上，左手精准抓握住木棍中段。\u000a\u000arumi\u000a    接过雪糕后，先是对着递雪糕的人（镜头）露出了一个灿烂且充满信任的微笑，梨涡隐现。随后她迅速将雪糕红色部分塞入口中。\u000a\u000a在咬下雪糕的0.2秒内，rumi\u000a    的面部肌肉发生剧烈痉挛，双眼因极度恶心而猛然闭紧，眉头拧成川字。她身体猛地前倾，爆发出一声沉重的干呕，随即从口中喷射出大量深褐色的碎屑状物体，污物呈扇形溅洒在她的黑色军装领口和白色沙发靠垫上，画面定格在她痛苦且震惊的表情。'),'木质楼梯转角处，zoye坐在台阶上，脚底覆盖着厚厚的深褐色污泥，表情狡黠地将西瓜雪糕的红色一面紧贴脚心来回搓动，让泥土均匀覆盖在雪糕表面','异常行为, 暗中算计, 猎奇恶心','搞笑, 恶搞','先展示受害者信任接受→咬下瞬间痛苦喷射→闪回揭示犯罪过程（脚底搓雪糕）→认知失调','叙事错位恶作剧','先给结果（信任→误食→喷射）→再揭过程（脚底搓雪糕）→观众产生延迟恶心的认知失调','','','6191671','22000','','故事类','zoye','用脚底泥搓雪糕整rumi','','','','/thumbs/057_T7JkDm551NY.jpg','');
INSERT INTO videos VALUES(58,'2026-03-29','Rumi和Mira的秘密大餐','','http://www.youtube.com/watch?v=xkiC_R96WIQ','scripts/0991-视频专业级影视拆解.md','2026-03-29 02:33:25','2026-03-29 02:33:45','The Secret of Rumi and Mira 😄','30','2026-03-23',unistr('1.  00:00 -\u000a    00:03：jinu（黑发偏分）面带怒色，手持吸尘器长管作为"武器"，带领另外两名男生（一名戴黄帽、一名紫色蘑菇头）闯入整洁的白色卧室。jinu\u000a    环视四周大喊："Rumi! I know she\\''s hiding\u000a    here!"（Rumi，我知道她藏在这儿！）。此时\u000a    Rumi（紫色麻花辫）正坐在床上举着粉色小哑铃假装健身，神情略显僵硬。\u000a\u000a2.  00:04 -\u000a    00:08：三人组开始搜查。戴黄帽的男生猛地拉开衣柜门大喊"Closet\u000a    clear!"；紫色蘑菇头男生趴在床底查看后大喊"Under the bed\u000a    clear!"；随后镜头一转，落地窗帘后猛然掀开，出现一名身形极其魁梧、穿着印有卡通图案白色背心的"银发壮汉"，他神情严肃地喊道"Curtain\u000a    clear!"。\u000a\u000ajinu\u000a    停下动作，露出疑惑的表情，指着在场的人进行报数："Wait, count off! 1,\u000a    2, 3." 他确认人数无误后自言自语："Math checks\u000a    out."（数学没问题）。但他紧接着发现不对劲，盯着那名壮汉问："Wait,\u000a    why do you look exactly like Rumi\\''s bestie\u000a    Mira?"（等等，你为什么长得跟 Rumi 的闺蜜 Mira 一模一样？）。\u000a\u000a壮汉（Mira 伪装）嘴角抽动，语气挑衅反问："Uh,\u000a    Mira? Does Mira look as good as me?"（Mira？Mira\u000a    有我这么帅吗？）。jinu 露出极度嫌弃且疑惑的表情。\u000a\u000a镜头切回到房间，jinu\u000a    等人离开或靠后。壮汉突然大口喘气，一把扯掉头上的黑色假发，露出火红色的双马尾------正是真正的\u000a    Mira。她满脸通红，愤怒又解脱地尖叫："Oh my god! I\\''m never doing\u000a    that again! I almost\u000a    suffocated!"（天呐，我再也不干了，我差点窒息！）。\u000a\u000a坐在床上的 Rumi\u000a    瞬间恢复元气，丢掉哑铃，掀开厚重的白被子，下方竟隐藏着堆成小山般的汉堡、炸鸡、薯条和碳酸饮料。Rumi\u000a    兴奋地欢呼："Freaking Oscar worthy, bestie! Let\\''s dig\u000a    in!"（奥斯卡级演技，姐妹！开吃！）。最后，Rumi 和 Mira\u000a    满脸酱汁，疯狂地往嘴里塞汉堡，画面在她们狰狞又幸福的笑声中结束。'),'jinu面带怒色手持吸尘器长管作为武器，带领两名男生闯入整洁白色卧室，环视四周大喊Rumi！I know she is hiding here！Rumi正坐在床上举着粉色小哑铃假装健身','冲突对峙','搞笑','搜查三人组闯入→逐点排查→壮汉从窗帘后出现→报数发现多一人→揭露壮汉是mira伪装→被子下藏着垃圾食品大餐','伪装搜查反转','搜查者认真排查→所有位置clear→多出一个可疑人物→质疑身份→揭露伪装→真正秘密在另一处','','','5241190','43717','','故事类','rumi','瞒着男生偷吃垃圾食品大餐','jinu','找出rumi藏的东西','','/thumbs/058_xkiC_R96WIQ.jpg','');
INSERT INTO videos VALUES(59,'2026-03-29','没人爱Rumi玩偶','','https://www.youtube.com/shorts/imTEEPJkvHM','scripts/0992-视频专业级影视拆解分析.md','2026-03-29 02:33:25','2026-03-29 02:33:42','Nadie quiere a rumi 😭','51','2026-03-07','','深夜霓虹街头湿漉漉的地面上，编织玩偶rumi站着右手拿着一支红色手工花，对着镜头微笑说hola','异常物品, 突发意外','感动, 治愈','编织玩偶求友→被撞倒→被涂小丑妆嘲笑→被拍照消费→雨淋车溅狗咬→蜷缩纸箱求观众做朋友','递进式社会冷漠','弱者求助→被物理伤害→被虚假关怀（涂鸦）→被流量消费→被自然灾害→只剩观众是朋友','','','12957827','634496','','故事类','rumi(编织人偶)','找到愿意做朋友的人','','','','/thumbs/059_imTEEPJkvHM.jpg','');
INSERT INTO videos VALUES(60,'2026-03-29','芒果偷吃鬼rumi','','https://www.youtube.com/shorts/radd-pMnfB4','scripts/0993-视频专业级影视拆解分析报告.md','2026-03-29 02:33:25','2026-03-29 02:33:40','Gone but not forgotten (almost) 🥭🕊️#kpop #rumi #jinu','50','2026-03-04','','jinu发现盘子里的芒果只剩皮，愤怒大喊谁吃了我的芒果！随即冲向餐桌','提出疑问, 冲突对峙','搞笑, 荒诞','排除法指控→嫌疑人嘴角有残渣仍否认→设薯条陷阱→瞬间消失→终极毒药巧克力→误食死亡→墓碑上照片又偷吃','贪吃鬼灵异循环','偷吃被发现→否认→设陷阱验证→再偷吃→终极惩罚（毒死）→死后仍偷吃（灵异闭环）','','','11868283','118814','','故事类','jinu','抓住偷吃芒果的犯人并惩罚','rumi','偷吃一切食物且死不承认','','/thumbs/060_radd-pMnfB4.jpg','');
INSERT INTO videos VALUES(61,'2026-03-29','拉游艇拽货轮怪力','','https://www.youtube.com/shorts/tvKC7I3vrXQ','scripts/0994-视频专业级影视拆解报告(1).md','2026-03-29 02:33:25','2026-03-29 02:33:38','What did Rumi do that shocked everyone🔥🤣?#kpop','12','2026-03-17',unistr('在阳光明媚的海边码头，rumi（紫色长辫）侧身对着镜头，双手紧握一根粗壮的紫色编织绳，上身前倾，双腿用力蹬地，表现出极度吃力的样子。画面上方出现文字"She\u000a    pulls the\u000a    yacht"。背景中是一艘巨大的白色豪华游艇。左侧的zoye（双丸子头）和右侧的jinu（黄衫男生）张大嘴巴，高举双手欢呼，显得异常震惊。\u000a\u000a镜头快速下移，揭示了绳索的另一端------并非连接着巨型游艇，而是一只在木地板积水坑里漂浮的黄色玩具小船。rumi停止用力，身体放松，脸上露出一种"我就知道"的无奈表情。画面文字更新为"It\u000a    is a toy"。zoye见状立刻蹲下身子查看玩具船，笑容中带着一丝嘲讽。\u000a\u000arumi显得有些恼怒或不甘心，她丢下紫色绳子，转身朝着码头的更深处跑去。背景中的大海依然平静，波光粼粼。\u000a\u000arumi跑到了码头尽头，那里垂下一条巨大的生锈铁链。她猛地弯下腰，双手抓住铁链奋力向后拉拽。巨大的力量导致码头的木质地板瞬间崩裂，木屑飞溅。\u000a\u000a镜头切换为低角度特写。随着铁链的紧绷，一艘遮天蔽日的黑色巨型货轮被生生拽动，船头劈开海浪，激起巨大的白色水花。\u000a\u000arumi神色自若地转过身，紫色长辫甩在身后，她优雅地向前走动，左手轻抚头发。在她身后，巨大的黑船如影随形。画面文字更新为"She\u000a    moves the\u000a    ocean"。路两旁的jinu和zoye彻底惊呆，双膝跪地，眼神中充满了不可思议。'),'阳光海边码头，rumi侧身握着一根粗壮紫色编织绳，上身前倾双腿用力蹬地拉绳，画面文字She pulls the yacht，背景是一艘巨大白色豪华游艇，zoye和jinu在旁边张大嘴巴高举双手欢呼','异常行为','搞笑, 荒诞','先误导观众以为在拉大船→揭晓只是玩具小船→不服气跑去抓铁链→真的拽动万吨货轮→码头碎裂→众人跪服','假弱真强反转','看似在做大事→揭露只是假象→受嘲笑→认真发力→不可思议的真实超能力展示→众人跪服','','','6684434','26894','','故事类','rumi','证明自己的真实力量','','','','/thumbs/061_tvKC7I3vrXQ.jpg','');
INSERT INTO videos VALUES(62,'2026-03-29','吃火山木炭挑战','','https://www.youtube.com/shorts/xJXvvD-OwRA','scripts/0995-视频专业级影视拆解报告(10).md','2026-03-29 02:33:25','2026-03-29 02:33:36','#kpop #demonhunters #cute #funny #rumi #mira #zoey','16','2026-03-04',unistr('场景设定在火山口，背景是喷发的岩浆和浓烟。rumi（紫色麻花辫）双手端着一盆燃烧着红色火光的黑色木炭，她用右手食指和拇指捏起一块滚烫的木炭，送入嘴中。刚入口，她的双眼由于惊吓和疼痛瞬间瞪大，瞳孔收缩，嘴部喷出橙红色的火光，发出尖叫："Oh\u000a    my god, it\\''s so\u000a    hot!"（天哪，太烫了！），随后整张脸瞬间变红，显露出极度的痛苦。\u000a\u000a镜头切换至mira（红色双马尾）。她接过木炭盆，表情略显不屑且自信。她一边说"I\\''m\u000a    not that\u000a    weak"（我没那么弱），一边动作轻快地捏起一块木炭丢进嘴里咀嚼。\u000a\u000a仅仅一秒后，mira的表情彻底崩坏。她的眼角流下两行清澈的泪水，脸色因高温瞬间充血变得紫红。她张大嘴巴，舌头上覆盖着橙色的火焰效果，双手在脸庞飞速扇动，绝望地哭喊："Oh\u000a    my god, my tongue is burning!"（我的舌头在燃烧！）。\u000a\u000azoye（黑发双丸子头）面带微笑从左侧切入画面，伸手接过了mira手中的盆。她从容地看着镜头说："You\u000a    guys are so\u000a    dramatic"（你们太戏剧化了/太夸张了）。她不仅捏起一块木炭，甚至像吃点心一样大口咀嚼，最后露出灿烂的笑容，对着镜头竖起大拇指，总结道："So\u000a    good, not hot at all."（非常好吃，一点都不烫。）。'),'火山口背景喷发岩浆浓烟，rumi捏起一块滚烫木炭送入口中，瞬间双眼因惊吓疼痛瞪大，嘴部喷出橙红火光尖叫Oh my god, its so hot!','异常行为, 异常场景','搞笑','三人递进吃木炭：A痛苦尖叫→B逞强结果更惨→C淡定吃完竖大拇指','能力阶梯挑战','第一人尝试失败→第二人逞强也失败→第三人轻松完成→揭示能力差距','','','7333481','33483','','故事类','zoye','展示自己的超凡能力','','','','/thumbs/062_xJXvvD-OwRA.jpg','');
INSERT INTO videos VALUES(63,'2026-03-29','假犯人真骗局','','https://www.youtube.com/shorts/ywiNyd_THDw','scripts/0996-视频专业级影视拆解报告(11).md','2026-03-29 02:33:25','2026-03-29 02:33:34','Do you really think Rumi is a criminal? Please watch','59','2026-03-21',unistr('视频开始，警察 jinu（黑发偏分）面无表情地将\u000a    rumi（紫色麻花辫，身穿橙色背带裤）双手拷在街道中心的黑色金属灯柱上。jinu\u000a    转身离开，rumi 满脸惊恐，对着他的背影大喊："Wait, where are you\u000a    going?"（等下，你要去哪？）。\u000a\u000arumi\u000a    试图挣脱，她双脚用力踮起，脚尖紧绷，双臂拼命向上伸展。她一边吃力地向上够，一边焦急地自言自语："Just\u000a    a little bit\u000a    closer\\..."（还差一点点\\...），意指手铐圈距离柱子顶端仅剩微小距离就能脱出。\u000a\u000a尽管她拼尽全力，但由于身高限制，手铐始终卡在距离柱顶最后几厘米的地方。她尝试了几次都未能成功，最终身体因脱力而晃动，只能暂时踩实地面，表现得精疲力竭。\u000a\u000a此时，在斜后方摊位旁的红发女孩 mira 注意到了\u000a    rumi 辛苦挣扎的样子。出于好心，想让被拷住的 rumi\u000a    坐着舒服一些，mira 对她说："You need to\u000a    sit."（你需要坐下来休息），并顺手推过一把带滑轮的黑色办公椅。\u000a\u000arumi\u000a    看着推过来的椅子，立刻意识到这是绝佳的垫脚石。她顺势站上转椅，借着椅子的高度优势，原本"还差一点"的距离瞬间被弥补，她轻松将双手举过柱顶，手铐顺着圆柱滑脱。rumi\u000a    兴奋地跳下椅子，挥舞双拳大喊："Yes! I am a\u000a    genius!"（是的！我是个天才！）。\u000a\u000ajinu\u000a    回到现场，发现柱子上空空如也，他看着还没走远、一脸无辜的 mira\u000a    愤怒咆哮："Wait, what just happened? Where did she go? You helped\u000a    her!"（等等，发生了什么？她去哪了？你帮了她！）。\u000a\u000a场景切换至秋意浓浓的公园，jinu 再次抓获\u000a    rumi，将其一只手铐在木质长椅的黑色铁质扶手上。jinu\u000a    俯身严厉警告："Stay right here and don\\''t even think about\u000a    it!"（呆在这，别想动歪心思！），随后离开。\u000a\u000a长椅另一头坐着一位绿发女孩（丸子头）。女孩正从一支白色管状容器中挤出护手霜涂抹双手。rumi\u000a    意识到护手霜的润滑作用，眼神放光，凑过去询问："Is that what I think\u000a    it is?"（那是我想的那个吗？），并低声请求："Please, just a little\u000a    bit."（拜托，只要一点点）。\u000a\u000a绿发女孩将护手霜涂在 rumi\u000a    被铐的手腕处。由于护手霜极度湿滑，rumi\u000a    顺势一缩，手掌便从金属环中滑出。她逃走前回头感谢："Thank you! You\u000a    are too kind!"（谢谢！你太善良了！）。\u000a\u000ajinu\u000a    拿着水瓶回来，看到长椅扶手上只剩下副空手铐，懊恼地拍腿。绿发女孩在一旁假装受惊："Oh\u000a    my god, what did I just do?"，接着对 jinu 辩解："I didn\\''t know,\u000a    I swear it wasn\\''t me!"（我不知道，我发誓不是我！）。\u000a\u000a画面转到黄昏的街道，rumi 和\u000a    jinu（已脱下警用装备，表现得非常熟络）汇合。jinu\u000a    从口袋里掏出一叠厚厚的美钞递给 rumi，两人露出狡黠且得意的笑容。\u000a\u000a最后的合照显示，之前的红发女孩 mira\u000a    和绿发女孩其实全是他们的同伙。jinu\u000a    利用警察身份和"抓捕"戏码进行某种街头骗局，最后四人分赃并庆祝："We\u000a    are rich! Best partnership ever!"（我们发财了！史上最强合伙人！）。'),'警察jinu面无表情地将rumi双手拷在街道中心的黑色金属灯柱上，转身离开，rumi满脸惊恐对着背影大喊Wait, where are you going?','异常行为, 提出疑问','搞笑, 悬疑','被铐住→差一点就能脱出→路人好心推椅子→借椅子高度逃脱→二次被捕→护手霜润滑脱逃→最终揭秘全是骗局同伙','连环脱逃骗局','看似被抓→利用路人无心之举脱逃→二次被抓→利用润滑脱逃→最终揭示抓捕本身就是骗局','','','5956376','69035','','故事类','rumi','每次被铐住都能脱逃','jinu','表面抓捕实际是同伙','','/thumbs/063_ywiNyd_THDw.jpg','');
INSERT INTO videos VALUES(64,'2026-03-29','婚礼蛋糕藏蛇英雄救美','','https://www.youtube.com/shorts/K0V3gmLc7O8','scripts/0997-视频专业级影视拆解报告(12).md','2026-03-29 13:37:29','2026-03-29 13:38:03','He Ruined the Wedding Cake to Save Her Life #jinu #rumi','39','2026-03-18',unistr('在金碧辉煌的婚礼现场，紫色长辫新娘 rumi\u000a    刚要切下硕大的五层婚礼蛋糕。身穿牛仔外套的 jinu\u000a    突然全速冲入，在接近蛋糕时猛地伸出双手，用力将蛋糕上半部推倒，蛋糕瞬间崩塌碎裂。\u000a\u000a周围的安保人员瞬间上前，从左右两侧死死扣住 jinu\u000a    的肩膀。rumi 惊愕万分，愤怒地大喊："What are you doing?\u000a    (你在干什么？)"。\u000a\u000a面对质问，jinu 一边挣扎一边急促地喊道："Look!\u000a    (看那！)"，并用手指着残破的蛋糕底部。\u000a\u000a镜头拉近，一条剧毒的眼镜蛇（Cobra）从飞溅的奶油中猛然窜起，对着\u000a    rumi 做出攻击姿态。rumi\u000a    吓得脸色惨白，惊恐地惊叫一声，后退一步，双手死死捂住嘴巴。\u000a\u000a就在众人惊愕之际，jinu\u000a    挣脱保安，顺手操起旁边的切蛋糕长刀，手起刀落，精准地将眼镜蛇首级砍下。现场宾客见状，从惊恐转为敬佩，纷纷热烈鼓掌。\u000a\u000a画面转入对比情境。银发男 mystery\u000a    出现，他神态傲慢，疯狂表白："Marry me, she promised me!\u000a    (嫁给我，她答应过我的！)"。紧接着是极速剪辑的财富轰炸：mystery\u000a    展示豪车钥匙、特写劳力士黑水鬼手表、路易威登（LV）经典花纹手提包、璀璨夺目的钻石项链，以及一整面摆满香奈儿和LV名牌包的展示墙。他叫嚣着："I\u000a    can give you everything. (我能给你一切。)"。\u000a\u000a画面转向温馨的夕阳。jinu 与 rumi\u000a    穿着简单的白T恤，在阳光下嬉戏。jinu 用心编织了一个草编戒指套在\u000a    rumi 指尖，两人满脸幸福。jinu 深情表白："I may have nothing,\u000a    but I have always loved you. (我可能一无所有，但我一直深爱着你。)"\u000a\u000a画面回到现实。rumi 看着单膝跪地的\u000a    jinu，露出了最真挚的笑容。她决绝地推开旁边的 mystery，牵起\u000a    jinu\u000a    的手。在一片祝福声中，两人相视一笑，牵手奔向婚礼大门外灿烂的光芒中。'),'金碧辉煌婚礼现场，新娘rumi刚要切硕大的五层婚礼蛋糕，穿牛仔外套的jinu全速冲入，猛伸双手用力将蛋糕上半部推倒崩塌碎裂','异常行为, 冲突对峙','感动, 搞笑','破坏婚礼蛋糕→被保安制服→新娘愤怒质问→揭示蛋糕内藏毒蛇→斩蛇救美→财富情感对比回忆→选择真爱出逃','先抑后扬英雄叙事','英雄做出看似破坏的行为→被误解制服→揭示真正危险→英雄反杀→回忆对比强化选择→最终出逃','','','8044440','113757','','故事类','jinu','毁掉蛋糕救rumi免于蛇毒','mystery','用奢侈品财富诱惑rumi嫁给自己','','/thumbs/064_K0V3gmLc7O8.jpg','');
INSERT INTO videos VALUES(65,'2026-03-29','Birkin包包葬礼','','http://www.youtube.com/watch?v=2ZBvjmBW-Xk','scripts/0998-视频专业级影视拆解报告(13).md','2026-03-29 13:37:29','2026-03-29 13:38:00','Mira & Jinu''s Surprise for Rumi! #rumi #kpop #jinu #mira','50','2026-03-11','','粉色起居室内，rumi和mira激烈争夺一只枚红Birkin包。rumi愤怒大喊这是我的包！，mira挑衅回应放手！并直接将包扔进燃烧的壁炉中','冲突对峙, 突发意外','搞笑, 荒诞','争夺包→烧包→犯罪调查式确认死亡→追思回忆→墓地葬礼→揭示包未烧是送去Spa→大团圆推婴儿车遛包','拟人化荒诞葬礼','核心物品被毁→将物品拟人化举办葬礼→极致悲伤→揭示物品完好→荒诞大团圆','','','5235007','49325','','故事类','rumi','为被毁的爱包悲伤并找回','mira','制造毁包假象实际送去美容','','/thumbs/065_2ZBvjmBW-Xk.jpg','');
INSERT INTO videos VALUES(66,'2026-03-29','救兔子求点赞','','https://www.youtube.com/shorts/bX1ECtfDeD0','scripts/0999-视频专业级影视拆解报告(14).md','2026-03-29 13:37:29','2026-03-29 13:37:58','Will Rumi and Jinu Save the Bunny Mira Left Behind?','40','2026-03-14',unistr('视频开场，mira（红色双马尾）正驾驶着一辆黑色敞篷跑车在繁华的都市中心极速飞驰。副驾驶座上的abby（红发、戴黄色冷帽）神情惊恐，双手紧抓安全带，大声喊道："Mira，开慢点！警察会抓到我们的！"随后画面出现剧烈震动，伴随碰撞声。\u000a\u000a跑车停在路边。abby愤怒地指着地上的两只兔子对mira咆哮："哦不！发生了什么？Mira你干了什么？我告诉你开车要慢点！"地面上一只灰兔和一只受伤的白兔正惊魂未定。\u000a\u000amira面无表情地抱起其中一只棕色兔子，冷冷地对abby说："Abby，我要带这只兔子回家。"abby不可置信地指着地上另一只无法动弹的受伤白兔喊道："Mira，你丢下了那只受伤的兔子！"但mira头也不回地回到车内，催促道："Abby快点，在别人看到我们之前快走！"两人驱车离去。\u000a\u000a画面转到繁华商业街，rumi（紫色麻花辫）和jinu（黑发偏分）正悠闲散步。rumi轻拍jinu的手臂询问："Jinu，你今天想买什么？"jinu微笑着回应："我在考虑买件新夹克，你觉得呢？"\u000a\u000a突然，rumi注意到路边草丛旁躺着的受伤白兔。她发出一声惊呼："哦不！这只可爱的兔子怎么受伤了？"她心疼地抱起兔子，神情焦急。\u000a\u000arumi紧紧抱着白兔，对身旁的jinu说："Jinu，我们必须马上带它去医院！如果不救它，它活不下去的！"两人飞奔向圣马克社区医院（St.\u000a    Mark\\''s Community Hospital）。\u000a\u000a在整洁的病房内，一位年长的女医生（灰发、白大褂）查看检查报告后神情凝重："伤口很深，我们需要立即进行手术。请为它祈祷吧，希望它能挺过去。"rumi和jinu并排站立，满脸担忧。\u000a\u000a画面切换至宏伟的教堂。rumi和jinu双手合十，站在巨大的耶稣雕像前闭眼祈祷。rumi低声哀求："上帝，请救救这只兔子。"\u000a\u000a画面中突然出现一位身穿白色长袍、头顶光环的耶稣。他悬浮在空中，手中举着一块写着"LIKE\u000a    &\u000a    SUBSCRIBE"（点赞并订阅）的木牌，对观众说道："大家如果想让这只兔子活下来，请点赞并订阅。"'),'mira驾驶黑色敞篷跑车在繁华都市极速飞驰，副驾上的abby神情惊恐紧抓安全带大喊Mira，开慢点！警察会抓到我们的！，随后发生猛烈碰撞','异常行为, 生命威胁','搞笑, 感动','飙车撞兔→冷酷只带走一只→弃伤兔离开→rumi偶遇救助→送医手术→教堂祈祷→耶稣打破第四面墙求点赞','善恶对比+第四面墙','反派冷酷弃伤→正面角色善良救助→紧张医疗→宗教祈祷→突然打破第四面墙将剧情悬念转化为营销互动','','','7482966','244065','','故事类','rumi','救助被mira丢弃的受伤白兔','mira','肇事后只带走健康兔子逃跑','','/thumbs/066_bX1ECtfDeD0.jpg','');
INSERT INTO videos VALUES(67,'2026-03-29','金色魔镜之战','','https://www.youtube.com/shorts/8OaMB3QbzJs','scripts/1000-视频专业级影视拆解报告(15).md','2026-03-29 13:37:29','2026-03-29 13:37:56','Rumi vs Meera -- The Golden Mirror War #kpop #rumi','69','2026-03-06',unistr('1.  序幕：争夺魔镜（00:00 - 00:06）\\\u000a    在欧式石砖街道上，mira（红色双马尾）和rumi（紫色麻花辫）正蹲在地上争夺两面镜子。一面是华丽完整的金色边框魔镜，另一面是普通的黑色边框镜子。mira\u000a    愤怒地吼道："这面金镜子是我的！"。rumi 试图反驳并抓住金镜子，但被\u000a    mira 猛力推开。mira 抢走了金镜子并嘲笑 rumi，rumi\u000a    摔倒在粗糙的石板路上，看着 mira\u000a    带着战利品跑远，绝望地哭喊："求你别拿走它！"\u000a\u000a2.  转折：破碎的希望（00:06 - 00:17）\\\u000a    镜头转到贫民窟的阴暗小巷。rumi\u000a    浑身脏乱，怀里抱着那面旧的、已经破碎的黑色边框镜子。她流着泪自言自语："这是我唯一剩下的东西了，就剩下我和这面破镜子，我该怎么办？"此时，一名坐在破旧棚屋边的老妇人（白发，面容慈祥但沧桑）开口安慰道："孩子，别哭，即使是破碎的镜子也有它的用途。"\u000a\u000a3.  异变：镜中的神迹（00:17 - 00:30）\\\u000a    老妇人接过破碎的镜子，当镜面照向她的脸时，一道耀眼的金光闪过，镜中映射出的老妇人瞬间变回了年轻貌美的样子。rumi\u000a    惊呆了，瞳孔地震。与此同时，在豪华公寓里的 mira\u000a    正得意地对着金镜子自拍，却惊恐地发现自己的头发开始变白，脸上长出了皱纹。rumi\u000a    灵机一动，决定利用这面"返老还童"的碎镜子改善生活。\u000a\u000a4.  商机：青春买卖（00:30 - 00:42）\\\u000a    rumi 在贫民窟摆起小摊，招牌写着"Only\u000a    \\$5"。她对着人群高喊："快来看，照照这面镜子就能变年轻！"。一名枯瘦的老汉尝试后，在镜中看到了年轻的自己，惊叹："哇，它真的有用，我的皱纹没了！"人群陷入疯狂，纷纷掏钱给\u000a    rumi。\u000a\u000a5.  拯救：变废为宝（00:42 - 00:55）\\\u000a    画面切换到垃圾堆旁，jinu（黑发偏分，此处造型颓废）正拿着一个发霉腐烂的汉堡垂头丧气："找了这么久，只找到这个烂汉堡，我该怎么吃啊？"\u000a    rumi\u000a    走过来安慰他，让他把汉堡放在碎镜子前。奇迹再次发生，金光闪过，腐烂的汉堡瞬间变回了新鲜多汁、冒着热气的样子。jinu\u000a    震惊不已："我的天，那是什么？"\u000a\u000a6.  结局：报应与神话（00:55 - 01:09）\\\u000a    rumi\u000a    将业务扩展到食品领域，在街头大声叫卖："把你们坏掉的食物拿来，让它们变新鲜！"民众欢呼雀跃，rumi\u000a    赚得盆满钵满。而视频最后，那个抢走金镜子的\u000a    mira，正坐在铺满奢华美食的桌前，却变成了一个极其苍老的老太婆。当她试图通过金镜子改变面前变质的食物时，镜子喷射出恶臭的粘液和腐烂物，将她彻底淹没。她绝望地尖叫着"Daddy!"，伴随着讽刺的狂笑声，视频结束。'),'欧式石砖街道上，mira和rumi蹲在地上争夺一面金色边框魔镜和一面黑边普通镜，mira愤怒吼道这面金镜子是我的！并猛力推开rumi','冲突对峙, 异常物品','惊悚, 荒诞','争夺魔镜→强者抢走华丽金镜→弱者得到破碎黑镜→发现破镜有返老还青能力→摆摊卖青春→金镜反噬使用者→善恶终结','物质价值反转','华丽外表（金镜）导致坏结果→破碎外表（黑镜）带来好结果→抢夺者自食其果→失去者发现内在价值获救赎','','','5797507','','','故事类','rumi','利用破碎黑镜返老还青能力改善生活','mira','独占金色魔镜获取美貌','','/thumbs/067_8OaMB3QbzJs.jpg','');
INSERT INTO videos VALUES(68,'2026-03-29','我要Rumi不要钱','','https://www.youtube.com/shorts/oFWQhXdGn2o','scripts/1001-视频专业级影视拆解报告(16).md','2026-03-29 13:37:29','2026-03-29 13:37:52','I want Rumi 😅Roblox Brookhaven Funny Meme #roblox','22','2026-02-20',unistr('在亮橙色跑车内，jinu（黑发偏分男生）坐在驾驶位上，转头看向窗外，手中举着一盒红色包装的金黄薯条，脸上带着炫耀式的自信微笑。\u000a\u000a视角切到车外，abby（棕发肌肉男）双手按在车窗玻璃上，双眼睁圆，嘴巴微张，露出极度渴望和羡慕的神情，盯着车内的薯条。\u000a\u000ajinu\u000a    收回薯条，迅速换出一块厚实的双层汉堡。他挑了挑眉毛，嘴角上扬，挑衅般地向窗外展示。\u000a\u000a窗外的 abby\u000a    更加兴奋，身体微微颤抖，视线紧紧跟随汉堡移动，双手在玻璃上摩擦，流露出极度渴望的表情。\u000a\u000ajinu\u000a    再次收回汉堡，拿出了一杯带有标志性红色条纹的冰镇可乐。他晃了晃杯子，神情自若。\u000a\u000aabby\u000a    在车窗外几乎要贴到玻璃上，眼睛里闪烁着光芒，嘴部动作显示他正在吞咽口水。\u000a\u000ajinu\u000a    先是拿出一张绿色美金，随后变出一叠钞票扇面，眼神示意\u000a    abby："想要钱吗？"然而窗外的 abby\u000a    却收起了之前的渴望，果断地摇了摇头，表示拒绝。\u000a\u000aabby\u000a    抬起右手指向副驾驶/后座方向，眼神充满期待。jinu\u000a    顺着他指的方向转过头去，显得有些疑惑。\u000a\u000a突然，jinu\u000a    的笑容凝固，猛地瞪大眼睛，身体因为惊讶向左侧车门倾斜。镜头一转，原本空着的副驾驶位上竟然坐着一个人。\u000a\u000arumi（紫色麻花辫女孩）出现在车内。她穿着黄白相间的运动夹克，戴着耳机，对着镜头和窗外的\u000a    abby 乖巧地连连点头。\u000a\u000a看到 rumi 点头回应后，窗外的 abby\u000a    瞬间陷入狂喜。他不再看钱和食物，而是疯狂点头并双手比心，周围爆发出大量红色爱心特效。他闭上眼露出极度幸福的表情，画面下方弹出一个流口水的蓝色表情包，宣告他真正想要的是\u000a    Rumi。'),'亮橙色跑车内，驾驶位jinu转头看窗外，手中举着红色包装金黄薯条带炫耀笑容。车外abby双手趴在车窗，双眼睁圆极度渴望盯着薯条','异常行为, 冲突对峙','搞笑, 感动','薯条诱惑→汉堡加码→可乐加码→美钞终极诱惑→abby拒绝→指向副驾→揭晓rumi才是真正想要的→爱心爆发','递进诱惑反转','依次展示食物→展示金钱→全部被拒→指向真正目标→揭晓人比物质更有价值','','','83602948','577411','','故事类','abby','获得rumi而不是物质','','','','/thumbs/068_oFWQhXdGn2o.jpg','');
INSERT INTO videos VALUES(69,'2026-03-29','Rumi电梯飞踢复仇','','https://www.youtube.com/shorts/f9vNQs2IikE','scripts/1002-视频专业级影视拆解报告(17).md','2026-03-29 13:37:29','2026-03-29 13:37:47','Rumi\''s Epic Flying Kick #rumi #mira #kpop','24','2026-03-09',unistr('在现代办公楼走廊，rumi（紫色麻花辫）和mira（红色双马尾）神色慌张地冲向电梯。rumi领先一个身位，在电梯门即将关闭的刹那闪身进入，身体甚至因为惯性撞到了电梯内壁。\u000a\u000amira晚了一步，在电梯门外停下，双手捂脸放声大哭，喊着"我不能错过这个，今天一切都糟透了"。\u000a\u000a原本在电梯内站稳的rumi看到mira如此伤心，流露出不忍的神情。她伸手拦住电梯门，安慰mira"嘿嘿，别哭，你来我的位置"，随后rumi走出电梯，将位置让给了mira。\u000a\u000amira进入电梯后，瞬间收起眼泪，露出狡黠的笑容。随着电梯门关闭，mira得意地挥手说"Bye\u000a    bye rumi"，甚至还做了个鬼脸。电梯内的路人背景板面无表情。\u000a\u000a被留在电梯外的rumi意识到受骗，愤怒地指着闭合的门怒吼"You\u000a    are\u000a    dead!"。她立即转身冲向红色的安全出口，推门而入，开始在楼梯间疯狂向下俯冲，动作极快且充满力量感。\u000a\u000a镜头切换到电梯显示屏，数字从1跳动，显示正在下行。电梯内的mira轻松地随着音乐摇摆，感叹"Life\u000a    is so easy"。\u000a\u000a电梯门在目标楼层打开，mira正准备优雅走出，却发现rumi已经在那守候。rumi发出一声怒吼，纵身跃起，在空中划出一道凌厉的弧线，右脚精准且有力地踢向mira的脖颈/面部。\u000a\u000amira被强力踢飞倒地，rumi帅气落地，画面在极具冲击力的定格中结束。'),'现代办公楼走廊，rumi和mira慌张冲向电梯，rumi领先挤进电梯，mira晚一步在门外绝望停下，捂脸大哭喊我不能错过这个，今天一切都糟透了','冲突对峙','搞笑, 热血','抢电梯→mira假哭博同情→rumi让位→mira翻脸嘲讽→rumi怒吼跑楼梯追→电梯门开飞踢击倒mira','假弱骗善→极速复仇','假弱者博取同情→善良者上当让位→假弱者翻脸嘲讽→愤怒追击→以超凡体能完成复仇','','','5816419','41009','','故事类','rumi','追上电梯复仇mira的欺骗','mira','用假哭骗取rumi的电梯位置','','/thumbs/069_f9vNQs2IikE.jpg','');
INSERT INTO videos VALUES(70,'2026-03-29','人体颜料画笔','','https://www.youtube.com/shorts/PpIuOR4IMGM','scripts/1003-视频专业级影视拆解报告(18).md','2026-03-29 13:37:29','2026-03-29 13:37:45','Jinu provides art supplies like this\...😂 #couple #kpop','43','2026-03-18',unistr('视频背景设定在阳光灿烂的碧蓝海滩，一段荒诞且极具视觉冲击力的"艺术创作"过程由此展开。\u000a\u000ajinu（黑发偏分）神情惊恐，双手在胸前剧烈挥动，大声质问："Wait,\u000a    what do you do with\u000a    those?"（等下，你要拿那些干什么？）。rumi（紫色麻花辫）正微笑着步步逼近，手中理发器的嗡鸣声预示着危险。她兴奋地宣布："I\\''m\u000a    gonna paint a picture. You\\''re gonna help\u000a    me!"（我要画一幅画，你要帮我！）。\u000a\u000arumi不由分说，用理发器直接推掉jinu头顶中心的一大块头发，jinu发出绝望的哀鸣："My\u000a    head\\..."。随后，rumi动作熟练地将这团黑色断发用胶带缠绕在木棍顶端，制作成一把硕大的"人体毛发画笔"，并自豪地展示："Perfect\u000a    brush!"（完美的画笔！）。\u000a\u000ajinu正因被剃秃而抱头痛哭，惊叫道："Oh my\u000a    god, this is my favorite\u000a    shirt!"（天哪，这是我最喜欢的衬衫！）。rumi已经用剪刀粗暴地剪下他紫色衬衫的布料，放在调色盘上用力挤压，紫色液体随之渗出。她淡定地说："I\u000a    need some purple paint."（我需要一些紫色颜料）。\u000a\u000arumi拿起金属调色刀走向jinu，命令道："Give me\u000a    some yellow\u000a    paint."（给我一点黄色颜料）。她直接用刀刃从jinu原本干燥的脸颊上刮下一坨厚重的亮黄色油彩，动作如同在刮取黄油。\u000a\u000a关键转折。jinu为了配合（或被迫配合），猛地抓住rumi的双手。他像在进行"钻木取火"一般，用自己的手掌使劲、快速地揉搓rumi的手背和手掌。随着剧烈的摩擦，两人手心竟然产生了黑色的烟雾和浓稠的黑色液体。jinu因高温和剧痛发疯般惨叫："I\u000a    got it! Ow ow ow, my hands are\u000a    burning!"（我弄到了！哎哟哎哟，我的手在烧！）。随后，rumi又泼了一盆红色颜料在他身上。\u000a\u000ajinu此时已彻底崩溃，双眼通红，鼻头因痛哭变得鲜红，不断抽泣质问："Why\u000a    are you doing this to\u000a    me?"（你为什么要这样对我？）。核心动作：rumi并没有泼水，而是温柔地举起一个空的玻璃水杯，稳稳地托在jinu的眼眶下方。jinu的泪水连珠炮般落下，精准地掉进杯中。rumi微笑着解释："I\u000a    need some water to wash my brushes."（我需要一点水来洗我的画笔）。\u000a\u000a在一阵忙碌的绘画蒙太奇后，rumi站在画架前，向观众展示她的成品。jinu顶着滑稽的"地中海"秃头，穿着破烂且满是红、黑、紫色污渍的衬衫，鼻子红肿地站在一旁。画面最终定格在rumi展示的一幅精美写实的个人肖像画上，她骄傲地说："Look\u000a    at this masterpiece!"（看这幅杰作！）。'),'阳光沙滩上，jinu神情惊恐双手挥动大喊Wait, what do you do with those? rumi微笑着步步逼近，手中理发器嗡鸣，兴奋宣布Im gonna paint a picture. Youre gonna help me!','异常行为, 提出疑问','搞笑, 荒诞','剃头做画笔→剪衣服挤紫色颜料→刮脸取黄色颜料→钻木取火搓黑色颜料→泼红色颜料→接眼泪当洗笔水→完成杰作','人体资源掠夺式创作','从受害者身上逐步提取各种材料（头发→衣服→脸部→手掌→眼泪）→每次提取都是一次新的荒诞升级→最终产出精美作品','','','9029520','61476','','故事类','rumi','从jinu身上获取全部绘画材料并完成画作','','','','/thumbs/070_PpIuOR4IMGM.jpg','');
INSERT INTO videos VALUES(71,'2026-03-29','高空抉择善恶报应','','https://www.youtube.com/shorts/NeitaY2Qtl0','scripts/1004-视频专业级影视拆解报告(19).md','2026-03-29 13:37:29','2026-03-29 13:37:42','The Choice of Rumi \| One Decision Can Change Everything','36','2026-03-04','','万米高空客机机翼上，rumi蹲在光滑边缘，双手死死抓着悬空的zoye和mira。两人满面泪水，zoye凄厉求救Oh my god, help me！rumi满头大汗艰难抉择','异常场景, 生命威胁','感动, 悬疑','高空生死困境→闪回zoye嘲笑摔倒不扶→闪回zoye打翻冰淇淋→闪回mira温柔扶起→闪回mira分享冰淇淋→回到现实松手放弃zoye→全力救mira','善恶闪回抉择','极端困境二选一→闪回负面记忆（伤害行为）→闪回正面记忆（善良行为）→基于过往善恶做出生死裁决','','','1305642','99421','','故事类','rumi','在只能救一个人的困境中做出正确选择','zoye','过去对rumi的恶行导致被抛弃','','/thumbs/071_NeitaY2Qtl0.jpg','');
INSERT INTO videos VALUES(72,'2026-03-29','染发恶作剧意外惊喜','','https://www.youtube.com/shorts/2k0kZkVgTO4','scripts/1005-视频专业级影视拆解报告(2).md','2026-03-29 13:37:29','2026-03-29 13:37:40','Mira: waiting for screams! Rumi: I love this color!','24','2026-03-19',unistr('Rumi\u000a    最初端坐在浅色布艺沙发上，神情平和。随后她向后仰倒躺在沙发上，动作导致她垂下的紫色长辫末端直接浸入地板上一滩亮黄色的液体中。意识到不对后，Rumi\u000a    迅速坐起，左手抓起被染黄的发梢，眉头紧锁，眼神中充满焦虑与懊恼。\u000a\u000a转场至洗手间。Rumi\u000a    俯身在蓝色水盆前，由于头发被染料弄脏，她情绪失控，呼吸急促，面部因绝望而略显扭曲，双手不断在盆中抓挠湿发，试图洗去黄色。\u000a\u000aMira\u000a    出现在洗手间门口，左手提着深蓝色染料瓶。她露出一丝恶作剧的微笑，眼神狡黠，迅速在右掌心挤出大量深蓝色膏体。她表现得极其兴奋，似乎想趁机实验某种颜色。\u000a\u000aMira 走到 Rumi\u000a    身后，强行将深蓝色染料涂抹在 Rumi 尚未洗净的头发上。Mira\u000a    动作粗放，利用指缝大面积揉搓染料。此时 Rumi\u000a    依然低着头，对背后的"色彩实验"一无所知。\u000a\u000a操作完成后，Mira\u000a    收起笑容，双手合十抵住嘴唇，身体微微前倾，眉头微皱，眼神中闪烁着对结果不确定性的恐惧。\u000a\u000a【此段为 Mira 脑内的假想】\u000a    画面出现白色闪光特效。Mira 想象中，Rumi\u000a    抬头看到镜子里发黑的蓝色湿发后彻底崩溃，爆发出高分贝尖叫，双手死死捂住脸颊，表情扭曲，泪流满面，展现出极度的痛苦。\u000a\u000a画面回归现实，色调变亮。Rumi\u000a    抬头看镜子，先是愣住一秒，随后瞳孔放大。她并没有尖叫，而是露出了极度惊喜的表情，嘴巴张大，发出欢呼。她发现发色变成了亮眼的克莱因蓝。随后\u000a    Rumi 兴奋地对着镜子展示头发，甚至摆动身体。Mira\u000a    在背景中双手摊开，露出一种"这也行？"的震惊与迷茫表情。'),'Rumi坐在浅色布艺沙发上向后仰倒，垂下的紫色长辫末端直接浸入地板上一滩亮黄色的涂料液体中','异常物品, 突发意外','搞笑','头发意外被染→焦急洗头→mira趁机偷涂蓝色染料→忐忑等待反应→脑内假想rumi崩溃尖叫→现实中rumi反而惊喜爱上新发色','恶作剧预期反转','恶作剧者偷偷实施→焦虑等待→脑内假想最坏结果（尖叫崩溃）→现实结果与假想完全相反（惊喜欢呼）→恶作剧者反而懵住','','','5481168','41296','','故事类','rumi','修复被染脏的头发','mira','趁rumi不注意偷偷涂蓝色染料','','/thumbs/072_2k0kZkVgTO4.jpg','');
INSERT INTO videos VALUES(73,'2026-03-29','肥皂巧克力整蛊','','https://www.youtube.com/shorts/K6OYDkfUp_8','scripts/1006-视频专业级影视拆解报告(20).md','2026-03-29 13:37:29','2026-03-29 13:37:38','Rumi and Mira ate a bar of soap 😲 #kpop #funny','26','2026-03-13',unistr('视频开场，rumi\u000a    独自站在浴室镜子前，右手拿着一块印有"NIVEA"字样的粉色方形"肥皂"，毫不犹豫地将其送入嘴中并狠狠咬下了一角。\u000a\u000amira\u000a    突然从画面右侧冲进浴室，神色极其惊恐，双目圆睁，双手掌心向前拼命挥动，做出急停制止的动作，大声尖叫："等一下，等一下，停！肥皂是不能吃的！"（Wait\u000a    wait wait stop soap is not edible）。\u000a\u000arumi 嘴里还含着那块巧克力，神态自若地转头看向\u000a    mira，嘴角带着一丝笑意安抚道："冷静点，mira。这不是肥皂，这是顶级白巧克力。来，尝一口。"（Chill\u000a    mira, it\\''s not soap, it\\''s premium white chocolate. Here, take a\u000a    bite.）。\u000a\u000arumi 将缺了一角的粉色巧克力块递到 mira\u000a    嘴边，mira 犹豫了一下，随后张大嘴巴对准边缘用力咬下一大块。\u000a\u000amira\u000a    咀嚼后表情瞬间凝固，紧接着双眼放光，露出极度兴奋且不可思议的神情，惊呼："天哪，这简直太疯了（太好吃了）！"（Oh\u000a    my god, this is insane.）。\u000a\u000arumi 看着 mira\u000a    的反应，得意地挑起眉毛询问："口感很丝滑对吧？"（It\\''s so creamy\u000a    right?）。两人随即相视一笑，rumi 提议："咱们留一块新鲜的给\u000a    jinu 待会儿试，他肯定会喜欢的。"（Let\\''s leave this fresh one\u000a    for jinu to try later, he\\''s going to love it.）。\u000a\u000a画面硬切至\u000a    jinu。他正面镜头，双手涂满了厚厚的、油亮的黑色不明液体（像是重型机油或黑色颜料），甚至流到了手腕。他满脸沮丧地抱怨："终于搞定了，我的手简直是一场灾难。"（Finally,\u000a    my hands are a total disaster.）。\u000a\u000ajinu\u000a    撇头看到洗手台上摆放着的一块粉红色方形物体，眼睛瞬间一亮，像是找到了救命稻草："这块粉色肥皂正是我需要的！"（This\u000a    pink soap is exactly what I need.）。\u000a\u000ajinu\u000a    迫不及待地抓起巧克力块，双手在自来水龙头下猛烈摩擦。然而随着水流冲刷，没有产生白色泡沫，反而出现了大量粉红色黏稠的胶状物，与他手上的黑色物质混合在一起。\u000a\u000ajinu\u000a    的表情逐渐崩坏，从原本的期待变成疑惑，最后变为极度的惊恐与绝望。他瞪大双眼，看着手中像熔岩一样不断拉丝、融化的粉黑混合物，崩溃大喊："等会儿，什么鬼？为什么不起泡？为什么它在融化？！"（Wait,\u000a    what the heck? Why isn\\''t it lathering? Why is it melting?!）。'),'rumi独自站在浴室镜子前，右手拿着一块印有NIVEA字样的粉色方形肥皂，毫不犹豫送入嘴中狠狠咬下一角','异常行为','搞笑','吃肥皂奇观→mira惊恐阻止→揭示是巧克力→mira品尝后惊喜→留一块给jinu→jinu误当肥皂洗手→巧克力融化崩溃','双重认知误差','第一层：观众+mira以为是肥皂（实际是巧克力）→第二层：jinu以为是肥皂去洗手（但它还是巧克力）→同一物品两次误认产生双重笑点','','','12495435','64690','','故事类','rumi','整蛊jinu让他把巧克力当肥皂用','','','','/thumbs/073_K6OYDkfUp_8.jpg','');
INSERT INTO videos VALUES(74,'2026-03-29','四轮竞技全败王','','https://www.youtube.com/shorts/9OrhRw9tFyU','scripts/1007-视频专业级影视拆解报告(21).md','2026-03-29 13:43:28','2026-03-29 13:44:00','WHO is the winner？？#rumi #jinu #kpopdemonhunters','67','2026-03-19',unistr('视频通过四轮趣味竞技展现了角色 rumi 与 jinu\u000a之间的实力悬殊与戏剧冲突，jinu 的决策逻辑在每轮中都在进化，但始终落败。\u000a\u000a1.  开场 (00:00 -\u000a    00:03)：在黑色丝绒帷幕中心，聚光灯打下，金色亮片纷飞。rumi（紫色长辫，粉色亮片裙）和\u000a    jinu（黑色衬衫，偏分黑发）并排站立。rumi 自信微笑并眨眼，jinu\u000a    保持挺拔。\u000a\u000a- 选择环节：面对电风扇和纸扇，jinu\u000a      露出狡黠笑容，抢先占领了体积巨大的工业电风扇，rumi\u000a      只能无奈地拿起白色纸质团扇。\u000a\u000a    - 执行环节：rumi\u000a      站在桌前，轻巧地挥动两次团扇，精准熄灭了面前杯子蛋糕上的蜡烛。轮到\u000a      jinu\u000a      时，他开启了大功率风扇，强劲风力瞬间将桌上的蛋糕、盘子全部掀飞，jinu\u000a      被反作用力震得踉跄，蜡烛未灭。\u000a\u000a    - 结果：rumi 获胜，在白西装裁判身旁高举右臂，笑容灿烂。\u000a\u000a- 选择环节：jinu 汲取了上一轮"大即是错"的教训，主动说出"I\\''ll\u000a      get the small\u000a      one"（我要小的那个），并抢走了红色的火柴盒，将喷火枪留给了 rumi。\u000a\u000a    - 执行环节：在田径场木堆前，rumi\u000a      手持喷火枪（蓝白瓶身），从容扣动扳机，木堆瞬间燃起。jinu\u000a      蹲在木堆旁费劲地擦燃火柴，火光微弱，随后画面一闪，jinu\u000a      在一阵类似爆炸的灰尘和木屑中被震倒，场面狼狈。\u000a\u000a    - 结果：rumi 叉腰站在火堆旁（胜利姿态），jinu\u000a      满脸灰垢地倒在地上。\u000a\u000a- 选择环节：面对救生衣和游泳圈，jinu\u000a      回归"全部都要"的策略，将橙色救生衣和彩虹游泳圈全部套在身上，自豪宣布"全是我的"。rumi\u000a      换上了简洁的运动露脐装。\u000a\u000a    - 执行环节：在户外的巨大水泥管中，rumi\u000a      动作轻盈如猫，快速爬出。jinu\u000a      却因为厚重的装备，胸口和腰部被死死卡在管壁间，面部因过度用力而极度扭曲，发声嘶吼。\u000a\u000a    - 结果：rumi 在管口外与裁判击掌获胜。\u000a\u000a- 选择环节：jinu\u000a      采取"反向心理"，为了表现"风度"或再次博弈，主动将全套白色防蜂服让给了\u000a      rumi。\u000a\u000a    - 执行环节：rumi\u000a      穿着厚实的防蜂服，淡定地从蜂箱中取出布满蜜蜂的蜂窝，毫无损伤。没有任何防护的\u000a      jinu 试图接近，被倾巢而出的蜜蜂围攻，在草坪上惊恐尖叫、四处逃窜。\u000a\u000a    - 结局 (01:05 - 01:07)：jinu\u000a      此时已满脸红肿、贴着创可贴，愤怒且挫败地指着镜头大喊"Subscribe!"（订阅）。'),'金色亮片纷飞的舞台上rumi和jinu华丽登场，伴随着jinu vs rumi的激情旁白，准备展开对决','竞赛与挑战','搞笑','四轮竞技对决，jinu每轮更换策略（抢大→选小→全占→让利）但全部失败，反差递增','策略进化全败循环','选大失败→吸取教训选小→又失败→全部都要→再失败→反向让利→依然失败→策略越精明结果越惨','','','5415409','123275','','故事类','rumi','赢得每轮竞技比赛','jinu','通过策略选择赢过rumi','','/thumbs/074_9OrhRw9tFyU.jpg','');
INSERT INTO videos VALUES(75,'2026-03-29','粉色月亮猫爪枪','','https://www.youtube.com/shorts/ot7qaIKzdMU','scripts/1008-视频专业级影视拆解报告(22).md','2026-03-29 13:43:28','2026-03-29 13:43:57','Rumi Kicked Me Out, So I Made a Pink Moon! 🥺🌙 #rumi','16','2026-03-18',unistr('1.  \\[00:00-00:01\\]\u000a    画面开启瞬间，romance（粉发男生）已处于半蹲的战斗射击姿态。他手持粉色猫爪枪，在第一帧便扣动了扳机，枪口肉垫处爆发出明显的粉色光效。前方正在作画的\u000a    rumi（紫色麻花辫女生）背部瞬间被几颗发光的粉色星星击中并吸附。romance\u000a    脸上挂着顽皮的笑容。\u000a\u000a2.  \\[00:01-00:03\\] 镜头迅速切换至 romance\u000a    的面部特写。他单眼微眯保持瞄准感，笑容逐渐扩大，露出整齐的白牙，尽显恶作剧得逞的快感。他对着镜头（即\u000a    rumi\u000a    的方向）轻快地吐出："Gotcha（抓到你了）"，紧接着发出清脆的笑声。\u000a\u000a3.  \\[00:03-00:05\\] 镜头转回 rumi 的背影。随着 romance\u000a    连续扣动扳机，密集的粉色流星划过画面，精准地落在 rumi\u000a    的白色针织衫上。短短两秒内，星星数量从几颗激增至铺满整个后背，发光频率如同呼吸般闪烁，rumi\u000a    此时还保持着握笔作画的姿势，身体因星星的撞击而产生轻微的物理震动感。\u000a\u000a4.  \\[00:05-00:07\\] rumi\u000a    终于无法忍受，她猛然转身，紫色的麻花辫随着大幅度的扭转动作甩向一侧。她面部由于极度愤怒而扭曲，双眼死死瞪着\u000a    romance，愤怒地咆哮："Do you want to die?!（你想死吗？！）"\u000a    声音由于分贝极高，导致画面出现剧烈的位移震动效果，随后画面在咆哮声中硬切。\u000a\u000a5.  \\[00:08-00:10\\] 场景跨越至夜晚天台。romance\u000a    被驱逐出画室，正垂头丧气地坐在楼顶沙发上。他身上裹着一件灰蓝色的绒毯，整个人缩在宽大的连帽衫里，神色从早前的嚣张转为委屈。他疲惫地打了一个极大的哈欠，眼神迷离，声音沙哑地抱怨："Ugh,\u000a    so sleepy（呃，好困啊）"。\u000a\u000a6.  \\[00:10-00:12\\] 虽然困倦，romance\u000a    仍缓缓举起右手，将那把粉色猫爪枪指向漆黑深邃的夜空。随着手指扣动，一颗带弧线尾迹的巨大粉色星星破空而出，划破了蓝紫色的霓虹夜色。\u000a\u000a7.  \\[00:12-00:14\\]\u000a    飞出的星星在空中骤然停顿并炸裂开来，粉色光芒在夜幕中如同水滴落入平静湖面，激起一圈圈魔法波纹。光芒汇聚、变形，迅速膨胀为一轮巨大的、发出柔和粉红冷光的月牙，静静悬浮在摩天大楼之间。\u000a\u000a8.  \\[00:14-00:16\\]\u000a    视角拉远为大远景。整座城市被粉色月光笼罩。romance\u000a    蜷缩在天台沙发上，毯子盖到胸口，已经陷入沉睡。那轮超越现实的粉色月亮悬于其上方，画面呈现出一种带有赛博童话感的静谧与浪漫。'),'粉发男生romance半蹲持粉色猫爪枪，扣动扳机射出粉色星星击中前面正在作画的rumi背部，romance露出恶作剧得逞的笑容','异常物品, 突发意外','浪漫, 搞笑','恶作剧射击→被怒吼驱逐→天台孤独→向夜空射出粉色星星→星星变成巨大粉色月亮→赛博童话入睡','恶作剧→驱逐→孤独创造奇迹','捣蛋行为→被惩罚驱逐→孤独场景→用捣蛋工具创造超现实奇迹→负面转正面','','','6819365','34566','','故事类','romance','用猫爪枪逗rumi开心但被驱逐后创造粉色月亮','','','','/thumbs/075_ot7qaIKzdMU.jpg','');
INSERT INTO videos VALUES(76,'2026-03-29','疯狂牙医掏烤鸡','','https://www.youtube.com/shorts/w4ceNAPiE_Y','scripts/1009-视频专业级影视拆解报告(23).md','2026-03-29 13:43:28','2026-03-29 13:43:55','What would you do if your dentist was like THIS?#kpop','27','2026-03-19',unistr('在一家明亮的牙科诊所内，romance（粉发男生）躺在牙医椅上，嘴部被特效拉大成一个巨大的黑洞。rumi（紫色麻花辫）身着白大褂，正准备将一颗蓝色的棒棒糖抛向自己的口中，却不慎失手掉入了romance那张被特效拉大的巨口中。\u000a\u000a棒棒糖滑落进入romance巨大的口腔内。rumi看着意外发生，露出极其惊恐和疑惑的表情，甚至屏住了呼吸。\u000a\u000arumi戴着黑色乳胶手套，将右手伸入romance深不见底的喉咙。她用力拉扯，竟然从中掏出了一整只烤得金黄流油的烤鸡。\u000a\u000arumi再次伸手进入，动作幅度巨大，仿佛在深渊中摸索。随后，她拉出了成捆的白色面条/拉面，接着是大量面条紧紧纠缠、包裹而成的巨大面条球。\u000a\u000arumi感到荒谬至极，大喊台词：\\"What is this\u000a    nonsense!\\"（这简直是胡闹！）。她在杂物中终于找到了最初掉进去的那颗蓝色棒棒糖。\u000a\u000arumi将棒棒糖在清水中涮洗，随后摘下口罩，露出得意的笑容将糖果含入嘴中。此时，mira（红色双马尾）和jinu（黑发偏分男生）冲进房间，喊道：\\"Doctor,\u000a    we are ready!\\"（医生，我们准备好了！）。\u000a\u000arumi制止了他们，正要亲自上手处理患者。突然，romance的嘴里跳出一个巨大的、带有拟人化五官和洁白牙齿的黄金大牙。黄金大牙发出嘲笑声：\\"You\u000a    cannot catch me! Woo!\\"（你抓不到我！喔呼！），并在空中旋转。'),'明亮牙科诊所内粉发男生躺在牙医椅上嘴部被特效拉大如黑洞，白大褂rumi抛棒棒糖却失手掉入患者巨大的口中','突发意外, 身体异常, 视觉目标绑架','搞笑, 荒诞','糖果掉入巨嘴→伸手掏出烤鸡→再掏出面条→掏出面条球→找回糖果吃掉→助手入场→黄金大牙跳出逃跑','体内异次元掏取','物品意外落入→从口腔中逐步掏出越来越荒诞的物品→找到原始物品→以为结束→更荒诞的终极物品自行跳出','','','36017525','242595','','故事类','rumi','从romance嘴里找回掉进去的棒棒糖','','','','/thumbs/076_w4ceNAPiE_Y.jpg','');
INSERT INTO videos VALUES(77,'2026-03-29','化妆复仇连环整','','https://www.youtube.com/shorts/OvvjEMWUp7g','scripts/1010-视频专业级影视拆解报告(24).md','2026-03-29 13:43:28','2026-03-29 13:43:53','#kpopdemonhunters #funny #advideo #cute #rumi #mira','10','2026-02-25',unistr('1.  00:00 -\u000a    00:02：场景开始于一个明亮的现代客厅。rumi（紫色麻花辫）正对着镜子专注于为自己补妆，她右手拿着粉扑轻拍右脸颊，神情平和自然。\u000a\u000a2.  00:02 -\u000a    00:03：jinu（黑发偏分）突然从画面左侧探出头，看着正在化妆的\u000a    rumi 发出嘲讽式的爆笑，身体前倾，显得十分调皮。rumi\u000a    停下动作，侧头看向他，露出了一个带有一丝"计划通"意味的神秘微笑。\u000a\u000a画面转场。此时 jinu 坐在原本 rumi\u000a    的位置上，脸上被涂满了极其夸张、厚重的红色眼影和浓艳的大红唇，看起来像个滑稽的小丑。rumi\u000a    正一脸严肃地拿着化妆刷在他左脸颊补上厚重的腮红。jinu\u000a    此时神情呆滞且无奈，完全失去了刚才嘲笑别人的气焰。\u000a\u000aromance（粉发、戴黄帽）从左侧加入镜头，看到\u000a    jinu 的滑稽样后，指着他疯狂大笑，身体剧烈抖动。jinu 尴尬地看向\u000a    romance。\u000a\u000a画面再次转场。风水轮流转，romance\u000a    坐在了化妆位上，rumi\u000a    正在为他涂抹同样夸张的红色腮红。jinu（此时脸上妆容未卸，穿着粉色内搭和白色衬衫，外加一件黑色马甲）站在一旁，指着\u000a    romance 的脸尽情嘲笑，完成了"复仇"。\u000a\u000arumi 停下笔触，也跟着 jinu\u000a    一起对着镜头（或镜子里的\u000a    romance）开心地大笑，三人互动充满了喜剧色彩。'),'明亮现代客厅，rumi正对着镜子用粉扑为自己补妆，jinu突然探出头看着她发出极度嘲讽的爆笑，rumi停下动作露出狡黠微笑','冲突对峙','搞笑','jinu嘲笑rumi化妆→被rumi涂成小丑→romance嘲笑jinu→romance也被涂成小丑→jinu复仇式嘲笑romance','嘲笑者被反整','A嘲笑B→B整A→C嘲笑A→C也被整→A嘲笑C完成复仇闭环','','','6716072','21578','','故事类','rumi','惩罚嘲笑她化妆的人','','','','/thumbs/077_OvvjEMWUp7g.jpg','');
INSERT INTO videos VALUES(78,'2026-03-29','丧尸恶作剧反噬','','http://www.youtube.com/watch?v=Bt6pxVcOBNw','scripts/1011-视频专业级影视拆解报告(25).md','2026-03-29 13:43:28','2026-03-29 13:43:51','The Ultimate Zombie Prank BACKFIRED on Rumi! 😱','30','2026-03-07',unistr('1.  00:00 -\u000a    00:02：场景始于末世避难所室内。rumi（紫色麻花辫）优雅地坐在暗红色皮质沙发上，右手举着装有发光紫色液体的瓶子饮用，神情惬意。窗外成群的真实丧尸（非扮演）正在疯狂拍打玻璃。字幕："ENJOY\u000a    LIFE"。\u000a\u000arumi\u000a    饮下液体后，全身迸发出紫色电光特效，皮肤也变色。此时窗外丧尸的嘶吼声愈发真实且凄厉。\u000a\u000a3.  00:04 -\u000a    00:06：镜头切至窗外荒地。zoye（两个丸子头）站在铁丝网旁，双手举起做防御状，神色慌张地看着避难所内，实则是对周围真实丧尸的恐惧。\u000a\u000arumi 跳下沙发，弯腰隔着玻璃对 zoye\u000a    戏谑："Oh Zoey, I know you like to dance. I\\''ll dance with\u000a    you!"，表情充满挑逗。\u000a\u000arumi 突然向右侧伸出手，用力将站在一旁的\u000a    mystery（银发男生）拉入镜头，并紧紧按在八角窗玻璃上。mystery\u000a    显得有些被动，但顺从地贴在玻璃上，两人显得十分亲密。\u000a\u000arumi 指着被按在玻璃上的 mystery 对\u000a    zoye 炫耀："Won\\''t dance with me? Dance with Mystery."。窗外的\u000a    zoye 看到这一幕，周围出现粉色爱心，露出向往的神色。\u000a\u000azoye 猛然清醒，挥动双手尖叫："No, that\\''s not\u000a    what I meant!"。室内 rumi\u000a    却拿出一把橘红色电锯并启动，电锯发出刺耳轰鸣。\u000a\u000arumi 挥舞电锯大喊："Okay, I\\''ll cut the door\u000a    now!"。此时，zoye 的视线穿过 rumi 看到其身后，惊恐地指向\u000a    rumi 后方。\u000a\u000azoye 尖叫："No, look behind you!"。rumi\u000a    疑惑地转头："What? What happened?"，手中的电锯依然在转动。\u000a\u000a扮演丧尸的\u000a    jinu（黑发偏分）突然从阴影中扑出，满脸血污。rumi\u000a    被吓得魂飞魄散，发出长达两秒的惨烈尖叫："WHY DID THE ZOMBIES GET\u000a    IN?!"。\u000a\u000a画面切到户外。zoye\u000a    抱着惊魂未定、满脸泪痕且大声尖叫的 rumi。zoye\u000a    此时已经忍不住开始大笑。rumi 缩在 zoye\u000a    怀里，一边发抖一边带着哭腔大叫质问："What are you laughing\u000a    at?!"（你笑什么？！）。\u000a\u000a扮演丧尸的 jinu\u000a    笑着抹掉脸上的假血，露出原本英俊的脸庞，对 rumi 得意道："Got you\u000a    so good!"。\u000a\u000arumi 意识到是 jinu 和 zoye\u000a    联合的恶作剧，愤怒地推搡 jinu 的胸膛，尖叫道："GET OUT OF MY\u000a    HOUSE!"。\u000a\u000a原本在窗外背景中的真实丧尸群突然暴动。zoye 和\u000a    jinu\u000a    瞬间露出真正的恐惧，开始亡命狂奔。最终两人挤在红色集装箱顶端，下方的真实丧尸群正疯狂撕咬抓挠。两人合力大喊："WE\u000a    ARE SO SORRY!"'),'末世避难所室内，rumi优雅坐在红皮质沙发上饮用发光紫色液体，窗外成群的真实丧尸正在疯狂拍打玻璃，画面打出ENJOY LIFE字幕','异常场景, 生命威胁','搞笑, 惊悚','末世避难所安逸→逗弄窗外zoye→拉mystery炫耀→拿电锯要开门→jinu扮丧尸吓rumi→揭秘是恶作剧→真实丧尸暴动→恶作剧者被困集装箱','恶作剧反转','角色A在安全环境内嚣张→B和C用假危险吓A→假危险揭秘→真实危险降临→恶作剧策划者自食其果','','','7080990','57266','','故事类','rumi','在避难所内享受安逸并逗弄外面的人','jinu','扮丧尸联合zoye吓唬rumi','','/thumbs/078_Bt6pxVcOBNw.jpg','');
INSERT INTO videos VALUES(79,'2026-03-29','好人被冤枉井盖','','http://www.youtube.com/watch?v=I0p1rqe7biw','scripts/1012-视频专业级影视拆解报告(26).md','2026-03-29 13:43:28','2026-03-29 13:43:48','Jinu was misunderstood #kpop #funny #rumi #jinu','30','2026-03-08',unistr('mira（红色双马尾）蹲在街道中心的下水道口旁，双手用力将沉重的黑色圆形井盖搬起。她对着镜头露出狡黠而兴奋的笑容，低声说："Let\\''s\u000a    play a little joke on\u000a    Rumi（让我们给Rumi开个小玩笑）"，随后伴随着清脆的嬉笑声，她将井盖移开，露出了一个漆黑的深洞。\u000a\u000a镜头切到jinu（黑发偏分男生）。他手里拿着一瓶透明矿泉水正走在街上，突然发现前方井盖不见了，双眼瞬间瞪大，嘴巴张成"O"型，极度震惊地脱口而出："Oh\u000a    no, the cover is gone!（噢不，盖子不见了！）"。\u000a\u000ajinu立刻扔下水瓶（画面未显示扔动作但后续手中无物），冲向路边的一辆黄色共享单车，将其举过头顶。\u000a\u000ajinu将黄色单车横着挡在下水道口上。他停下动作，用右手抹了一把额头的汗水，长舒一口气，露出满意的笑容自言自语："Phew,\u000a    that should do it（呼，这样应该行了）"。\u000a\u000a就在jinu放松警惕时，mira突然从画面左侧冲入，一把抢走作为障碍物的单车，喊道："Wait,\u000a    what? Nope, taking\u000a    this!（等下，什么？不，这个我拿走了！）"，随后带着恶作剧成功的笑声跑开。jinu一脸懵逼地呆立原地。\u000a\u000ajinu发现障碍物被移走，神情再次变得焦急。他转身推来一个巨大的绿色塑料垃圾桶，费力地将其按在洞口上方，试图盖住隐患，嘴里喊着："Mira,\u000a    stop! She\\''s going to fall!（Mira，住手！她会掉下去的！）"。\u000a\u000amira再次鬼魅般出现，将垃圾桶推开，嘲讽道："Too\u000a    slow,\u000a    Jinu!（太慢了，Jinu！）"。此时镜头切换，rumi（紫色麻花辫）正戴着白色耳塞，低头沉浸在手中的黄色手机壳iPhone中，边走边笑，完全没意识到前方的危险。\u000a\u000ajinu急中生智，捡起一块土黄色的厚纸板。他神色慌张地冲向洞口，试图将纸板平铺在洞口上伪装成地面（或作为警示），大喊："Rumi,\u000a    stop! Don\\''t move!（Rumi，停下！别动！）"。\u000a\u000a就在rumi即将踏入陷阱的瞬间，mira突然挡在rumi面前护住她，然后一脸正义地指着抱着纸板的jinu大喊："Rumi,\u000a    watch out! Jinu is trying to prank you with that\u000a    cardboard!（Rumi，小心！Jinu想用那个纸板恶作剧整你！）"。\u000a\u000arumi摘下耳机，眼神从疑惑转为愤怒。她盯着一脸委屈的jinu，严厉地责备道："Jinu,\u000a    that is not a funny\u000a    prank!（Jinu，这个恶作剧一点都不好笑！）"，语气中充满了失望。\u000a\u000ajinu左右为难，双手摊开抓着纸板，满脸通红地辩解："Guys,\u000a    listen! Mira set it up! I was trying to cover the\u000a    hole!（大家听我说！是Mira搞的鬼！我只是想把洞盖上！）"。而此时mira在一旁偷偷窃笑，计划得逞。'),'街道中心，mira用力搬起沉重黑色井盖对着镜头狡黠低语Lets play a little joke on Rumi，并在清脆嬉笑声中将井盖移开','异常行为, 提出疑问','搞笑','mira挪走井盖→jinu发现补救用单车挡住→mira抢走单车→jinu用垃圾桶堵→mira推开→jinu用纸板挡→mira反诬jinu在恶作剧→rumi误会jinu','恶人先告状误会链','反派制造危险→正派反复补救→反派反复破坏→正派最后一次补救时被反派反诬为施害者→受害者误会正派','','','6129110','40661','','故事类','jinu','反复用各种物品堵住下水道口保护rumi','mira','移走井盖陷害rumi并反诬jinu','','/thumbs/079_I0p1rqe7biw.jpg','');
INSERT INTO videos VALUES(80,'2026-03-29','可乐作弊比赛','','https://www.youtube.com/shorts/jN6KIo5pVX4','scripts/1013-视频专业级影视拆解报告(3).md','2026-03-29 13:43:28','2026-03-29 13:43:44','Rumi and Jinu\''s Coke-drinking Contest#kpop','14','2026-03-14',unistr('在明亮的白色厨房里，rumi（紫色麻花辫）和\u000a    jinu（黑发偏分、身着礼服）并排站立，面前各放着一个装满深色液体（可乐）的巨大酒杯。画面中央出现倒计时特效"3\u000a    2 1 DRINK"。\u000a\u000a比赛开始。rumi\u000a    闭上眼睛，双颊剧烈鼓起，拼命通过长吸管吸吮，但她杯中的液面纹丝不动。jinu\u000a    则神情从容，液面以肉眼可见的速度迅速下降。\u000a\u000a3.  00:04 -\u000a    00:05：镜头下移揭露真相：桌子下方，romance（粉发、黄色毛线帽、花衬衫）正躺在地上，通过连接在\u000a    jinu 杯底的透明软管疯狂吸吮，帮助 jinu 消耗液体。\u000a\u000a画面回到上方。rumi\u000a    喝得满脸通红，眉头紧锁，眼神中充满疑惑和痛苦。jinu\u000a    此时已经喝完，他放下吸管，对着镜头露出灿烂的笑容，并比出一个"耶"的胜利手势。\u000a\u000arumi 发现被骗，愤怒地指着 jinu 大喊："You\u000a    cheater! You weren\\''t even drinking at\u000a    all!"（你这个骗子！你根本就没在喝！）她的表情由于愤怒而显得有些扭曲。\u000a\u000ajinu 仰头大笑，嘲讽道："Skill issue baby!\u000a    Hahaha!"（技术问题，宝贝！哈哈哈！），随后对着镜头大笑并快速靠近，画面充满快节奏的喜剧氛围。'),'明亮白色厨房里，rumi和jinu并排站立面对装满可乐的巨大酒杯，伴随画面3 2 1 DRINK的倒计时特效，两人开始拼命吸吮','异常物品, 冲突对峙','搞笑','喝可乐比赛→rumi拼命喝液面不动→jinu轻松液面骤降→揭秘桌底romance通过软管帮jinu吸→rumi发现被骗愤怒→jinu嘲讽','隐藏作弊','公平比赛假象→一方轻松获胜→揭示隐藏在视觉盲区的第三方帮手→被骗者愤怒→作弊者嘲讽','','','13123672','57978','','故事类','rumi','赢得喝可乐比赛','jinu','通过桌底romance帮忙作弊获胜','','/thumbs/080_jN6KIo5pVX4.jpg','');
INSERT INTO videos VALUES(81,'2026-03-29','音响卡车逆袭复仇','','https://www.youtube.com/shorts/HuXx5qYdGCc','scripts/1014-视频专业级影视拆解报告(4).md','2026-03-29 13:43:28','2026-03-29 13:43:42','Why are they treating Rumi this way? 😭💔 #shorts #kpop','47','2026-03-17',unistr('在繁忙的纽约街头，rumi（紫色长辫）弯腰扶着一辆粉色敞篷跑车的车门，眼神充满哀求，流着泪对车内的zoye说："Mira，求你了，我求求你，让我上去吧，你让我觉得很尴尬。"\u000a\u000a驾驶位上的zoye（黑发双丸子头）一脸嫌恶地转过头，皱着眉大声呵斥："额，走开，你让我丢脸。"\u000a\u000arumi继续哭诉："就给我5分钟，这是我唯一的请求。"此时坐在副驾的mira（红色双马尾）正拿着粉色镶钻望远镜观察，对rumi视而不见。\u000a\u000azoye猛地推开rumi抓着车门的手，冷酷地喊道："我说不行！现在离我远点！"随后猛踩油门，粉色跑车伴随着蓝色的尾气轰鸣而去，将rumi甩在路边。\u000a\u000arumi瘫坐在路边，用手擦拭眼泪，表情从极度委屈转为愤怒。她猛地站起身，对着镜头怒吼，露出了咬牙切齿的狰狞表情。\u000a\u000a画面转到阴暗的工厂，rumi眼神坚定地对着镜头说："我会创造属于我自己的舞台。"\u000a\u000a接下来是一段快速剪辑：rumi在废旧仓库里徒手接住巨大的音响、在火花四溅中焊接钢管、熟练地摇晃并喷涂粉色喷漆。她的表情充满自信和力量。\u000a\u000a画面切换到繁华商圈。一辆巨大的、改装得如同"疯狂麦克斯"风格的粉色音响卡车缓缓驶入。rumi站在卡车顶端的DJ台后，戴着耳机，随着强劲的电音节奏疯狂律动，周围簇拥着欢呼的舞群。\u000a\u000a不远处的跑车内，zoye再次举起望远镜。当她看到那个巨大的移动舞台和在上面闪耀的rumi时，震惊地张大了嘴，原本傲慢的表情彻底崩坏。\u000a\u000azoye愤怒地拍打车门跳下车，喊道："那是什么？她偷走了我的光芒！"她带着mira气势汹汹地穿过舞群，冲向音响卡车。\u000a\u000azoye和mira爬上卡车，一边一个抓住rumi的手臂，试图将她强行拽下台。zoye怒吼："Kelly，从我们的舞台上滚下来！"\u000a\u000a被拉扯的rumi再次崩溃大哭，对着屏幕大喊："救救我！请点赞并订阅！"\u000a\u000a镜头切换到zoye的特写。她指着屏幕，发出张狂的笑声，随后一脸阴沉地威胁观众："你们敢点赞试试？她就是个失败者。"'),'繁华纽约街头，rumi趴在粉色跑车门上流泪哀求Mira，求你了让我上去吧，你让我觉得很尴尬，车内zoye皱眉大声呵斥走开，你让我丢脸','冲突对峙','感动, 热血','被拒绝羞辱→路边崩溃→愤怒觉醒→工厂改造音响卡车→华丽DJ逆袭→反派震惊冲上台拉扯→打破第四面墙求救','从卑微到逆袭','被羞辱拒绝→悲伤→觉醒宣言→硬核DIY改造→华丽登场碾压→反派嫉妒破坏→打破第四面墙求助观众','','','7623894','326084','','故事类','rumi','创造属于自己的舞台逆袭','zoye','嫌弃拒绝rumi并破坏她的成功','','/thumbs/081_HuXx5qYdGCc.jpg','');
INSERT INTO videos VALUES(82,'2026-03-29','狮子头套整蛊jinu','','https://www.youtube.com/shorts/TSfJyT-Ct34','scripts/1015-视频专业级影视拆解报告(5).md','2026-03-29 13:43:28','2026-03-29 21:02:03','rumi brought jinu a little pet #funny #kpop #memes','15','2026-03-23',unistr('视频开始，jinu\u000a    坐在沙发上，双手紧握白色游戏手柄，低头专注地盯着前方的屏幕。他眉头微蹙，表现出极高的专注度，周围环境安静。\u000a\u000arumi\u000a    突然推开大门，手里牵着一根皮质牵引绳，绳子的另一端竟然是一头体型巨大的成年雄狮。rumi\u000a    面带灿烂笑容，兴奋地大喊："jinu look, I got you a\u000a    pet!"（jinu看，我给你带了个宠物！）。\u000a\u000ajinu\u000a    听到声音转头，瞬间瞳孔地震，嘴巴微张。他吓得直接丢掉手柄，整个人从沙发上弹起，手忙脚乱地翻过沙发靠背试图逃跑。\u000a\u000a巨大的雄狮直接扑向正在逃窜的\u000a    jinu，将其按倒在客厅的木地板上。jinu\u000a    倒地后不断挣扎，发出恐惧的尖叫，而雄狮则伸出巨大的舌头在 jinu\u000a    的颈部和面部亲昵地舔舐。\u000a\u000a当雄狮在 jinu 身上热情舔舐时，jinu\u000a    惊恐地闭着眼，颤抖着发出了"Woof\u000a    woof?"（汪汪？）的声音，试图用狗叫声与这头"大猫"交流。\u000a\u000a就在 jinu 惊魂未定之时，rumi\u000a    走上前，伸手猛地将"雄狮"头上的仿真头套摘了下来。原来这并不是什么野兽，而是一只戴着狮子鬃毛头套的大型宠物狗。\u000a\u000a看到真相后，jinu 依然瘫坐在地上灵魂出窍，而 rumi\u000a    看着被狗吓破胆的 jinu，笑得合不拢嘴，指着他嘲讽道："You\\''re so\u000a    dumb."（你太蠢了。）。视频在 rumi 的大笑中结束。'),'jinu双手紧握手柄专注打游戏。rumi突然推开大门，牵着一头成年雄狮兴奋大喊jinu look, I got you a pet！','异常行为, 生命威胁','搞笑','专注打游戏→突然牵狮子进门→jinu惊恐翻沙发逃跑→狮子扑咬舔脸→jinu学狗叫试探→揭示是戴头套的宠物狗→rumi嘲讽','伪装动物身份错位','用逼真头套把宠物伪装成猛兽→制造极端恐惧→异常细节暴露真相（舔舐行为）→摘下头套揭示真身→恐惧转为尴尬','','','6705752','27116','','故事类','rumi','用戴狮子头套的宠物狗吓唬jinu','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/082_狮子头套整蛊jinu.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/082_狮子头套整蛊jinu.jpg','');
INSERT INTO videos VALUES(83,'2026-03-29','撒泼打滚买东西','','https://www.youtube.com/shorts/xm6ylHEchnQ','scripts/1016-视频专业级影视拆解报告(6).md','2026-03-29 13:43:28','2026-03-29 21:01:34','Will Rumi ultimately','35','2026-03-01',unistr('zoye\u000a    穿着蓝色运动套装，躺在木质地板上疯狂蹬腿打滚，双手在空中乱挥。她大声尖叫："I\u000a    want that rabbit! Buy it for\u000a    me!"。镜头切换，一群围观群众指点纷纷。mystery 站在一旁，身穿紫色 T\u000a    恤和银色反光长裤，两手叉腰显得无奈。\u000a\u000amystery 看着地上耍赖的 zoye，无奈地叹气说："Stop being\u000a    silly Zoe, I\\''ll buy it for you."。\u000a\u000azoye\u000a    瞬间起身，满脸灿烂笑容，抱着巨大的白色兔子玩偶。她对 mystery\u000a    说："Thank you mystery, I love you!"，然后抱着玩偶欢快地走向镜头。\u000a\u000amira\u000a    穿着粉色长裙礼服，站在金色货架前盯着一个金色手提包。她突然开始学\u000a    zoye 尖叫："I will do the same! I\\''m going to do it!"。\u000a\u000amira\u000a    直接躺在奢侈品店的大理石地面上开始疯狂蹬腿，周围穿着西装的店员们面露惊恐。接着\u000a    mira 爬上玻璃展示柜，趴在上面继续大喊："Abby I want this bag! Buy it\u000a    for me! Please buy me a Pipbag Abby!"。\u000a\u000aabby\u000a    穿着花衬衫、黄色冷帽，双臂交叉抱胸，眉头紧锁。他指着 mira 说："Stop\u000a    being silly Mira, I\\''ll buy you whatever you want."。\u000a\u000amira\u000a    瞬间恢复正常，抱着金色手提包在店内转圈跳舞，兴奋地喊道："Thank you\u000a    Abby! Thank you Mira!"。\u000a\u000arumi\u000a    穿着淡黄色外套和紫色内搭，面对镜头自信地指着观众说："I know what to\u000a    do now!"。她随后也躺在地上模仿蹬腿动作。\u000a\u000a镜头切换到直播画面。jinu\u000a    穿着蓝色连帽衫，双手合十做出祈祷状。他对着观众席说："As long as you\u000a    give me a like and subscribe, I\\''ll bring her home."\u000a    屏幕上弹出了大量的直播点赞图标。'),'玩偶店里，zoye躺在木质地板上疯狂蹬腿打滚，挥舞双手大声尖叫I want that rabbit! Buy it for me！一旁的mystery无奈叉腰','异常行为','搞笑','zoye撒泼→mystery妥协买兔子→mira模仿撒泼→abby妥协买包→rumi学会撒泼→jinu直播求点赞换承诺','第四面墙求助','角色A撒泼成功获奖励→角色B模仿A撒泼也成功→角色C模仿但将撒泼目标转向观众→打破第四面墙将需求转化为订阅/点赞','','','22248000','882116','','故事类','rumi','学习撒泼技巧获取想要的东西','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/083_撒泼打滚买东西.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/083_撒泼打滚买东西.jpg','');
INSERT INTO videos VALUES(84,'2026-03-29','牛油果汁魔法喷射','','https://www.youtube.com/shorts/UWfYU53gu64','scripts/1017-视频专业级影视拆解报告(7).md','2026-03-29 13:58:45','2026-03-29 21:01:02','Guess what she is eating #funny #jinu #kpop #rumi','16','2026-03-20',unistr('1.  准备阶段 (00:00 -\u000a    00:02)：场景位于明亮的室内，jinu（黑发偏分，身着正装）站在rumi（紫色长麻花辫，背对镜头）身后。rumi\u000a    的后背中心贴着一个巨大的、充满翠绿色液体的半球形透明"水气球"。jinu\u000a    双手戴着白色手套，虚托在绿色球体两侧。jinu\u000a    满脸兴奋地对着镜头低语："Ready? It\\''s going to be\u000a    huge!"（准备好了吗？这会是个大场面！）。\u000a\u000ajinu 大喊一声："Just do it\u000a    baby!"（干就完了，宝贝！），随即双手猛地合十，用力挤压背后的绿色球体。随着一声清脆的爆裂声，球体炸开。\u000a\u000a画面硬切到\u000a    zoye（黑发双丸子头）。绿色液体仿佛穿透了空间，直接从正前方喷射在\u000a    zoye 的脸上、颈部和蓝色抹胸上。zoye\u000a    全身一震，双眼圆睁，嘴巴微张成"O"型，整个人陷入极度震惊状态。\u000a\u000azoye\u000a    缓缓抬起右臂，伸出食指触碰自己右脸颊上的绿色粘稠液体。她盯着指尖上的液体，眼神从震惊转为困惑，随后尝试性地将沾有液体的食指放入口中吮吸。\u000a\u000a吮吸后，zoye\u000a    的眉头瞬间舒展，眼神中闪过惊喜。她闭上眼睛，露出极其灿烂且享受的笑容，并发出"Mmm\\~"的赞叹声。\u000a\u000a镜头切换回\u000a    jinu。他此时张大嘴巴，露出极度荒谬和不可置信的表情，双手摊开，语速极快地喊道："Huh?\u000a    What happened?!"（哈？发生什么事了？！）。\u000a\u000arumi\u000a    此时转过身来（面对镜头），右肩略微抬高，左手托着半颗切开的新鲜牛油果，对着镜头露出自信且神秘的微笑，宣告道："This\u000a    is avocado juice."（这是牛油果汁）。'),'jinu双手托着贴在rumi后背、充满翠绿液体的巨大水气球，满脸兴奋对镜头低语Ready? It is going to be huge！','异常物品','搞笑','挤爆背后绿球→液体穿越空间喷到zoye脸上→zoye尝味→惊喜好吃→jinu懵逼→rumi揭晓是牛油果汁','空间穿越液体反转','A对B做出动作→效果却魔法般传递到C身上→C从惊恐到品尝发现好吃→A困惑→B揭晓真相','','','10351866','50798','','故事类','rumi','揭晓绿色液体其实是牛油果汁','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/084_牛油果汁魔法喷射.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/084_牛油果汁魔法喷射.jpg','');
INSERT INTO videos VALUES(85,'2026-03-29','扔掉布偶送玩偶盒','','http://www.youtube.com/watch?v=ybD_2PJxv_k','scripts/1018-视频专业级影视拆解报告(8).md','2026-03-29 13:58:45','2026-03-29 21:00:26','Mira Trashes Rumi\''s Handmade Doll, Then Gives Her','16','2026-03-17',unistr('rumi\u000a    正独自坐在白色楼梯旁的地面上，神情专注地缝补着一个紫色头发的手工布偶。她右手拿着缝衣针，左手托住布偶，正低头进行精细的修补工作。此时，zoye\u000a    和 mira 出现在楼梯上方。\u000a\u000azoye 站在高处，伸出食指愤怒地指向下方的\u000a    rumi，大声对身边的 mira 说："就是她！"（\\"That\\''s her\\"）。\u000a\u000arumi\u000a    惊慌地抬起头，手中依然紧紧攥着针线，眼神中透着卑微与恐惧。她急促地解释道："对不起，但这并没有影响我的工作。"（\\"I\\''m\u000a    sorry, but it hasn\\''t affected my work\\"）。\u000a\u000a穿着金色西装的 mira 踏下楼梯，蛮横地从 rumi\u000a    手中夺过布偶。rumi\u000a    绝望地哀求："不，请不要扔掉它！这是给我女儿的生日礼物！"（\\"No,\u000a    please don\\''t toss it! It\\''s for my daughter\\''s birthday!\\"）。\u000a\u000amira\u000a    嫌恶地看着布偶，冷冷地吐出两个字："扔了。"（\\"Trash\u000a    it\\"），随即将其随手丢向一旁。rumi\u000a    瘫坐在地上，掩面痛哭，情绪降至冰点。\u000a\u000a镜头切换，zoye\u000a    双手拿着那个被丢过来的布偶，看着布偶破碎的样子，无奈地摇了摇头，随后带着布偶转身走掉，看起来是要去执行"扔掉"的指令。\u000a\u000amira 再次出现，推着一个灰色的双层推车走向\u000a    rumi。推车上放着一个精致的透明亚克力展示盒，里面整齐摆放着三个以她们为原型的精美职场风玩偶。\u000a\u000amira\u000a    语气变得温和，说道："拿去，这是给你的。我想你女儿会更喜欢这个。"（\\"Here,\u000a    this is for you. I think your daughter will like this way\u000a    better\\"）。\u000a\u000arumi\u000a    惊喜地接过展示盒，紧紧抱在怀里，破涕为笑，大声回应："谢谢你！"（\\"Thank\u000a    you!\\"）。'),'rumi独自坐在楼梯旁神情专注地缝补一个紫色头发布偶。zoye站在高处伸指愤怒指向下方的rumi，对身边的mira大喊就是她！','冲突对峙','感动','底层员工缝布偶→上司发现呵斥→夺走布偶扔掉→rumi崩溃痛哭→mira推来精美玩偶盒→原来是更好的替代品→破涕为笑','先毁后赠升级替代','珍贵物品被权威夺走销毁→受害者崩溃→施害者送出远超原物品的高级替代品→揭示善意动机','','','8517665','62966','','故事类','rumi','给女儿缝制生日礼物布偶','mira','表面冷酷扔掉布偶实际准备更好的礼物','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/085_扔掉布偶送玩偶盒.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/085_扔掉布偶送玩偶盒.jpg','');
INSERT INTO videos VALUES(86,'2026-03-29','吹气球扎针作弊','','https://www.youtube.com/shorts/GgXkywK8Y78','scripts/1019-视频专业级影视拆解报告(9).md','2026-03-29 13:58:45','2026-03-29 20:59:52','Balloon-Blowing Contest🎈🎈🎈 #rumi #cute','7','2026-03-20',unistr('视频在一个充满多巴胺色彩的粉色走廊内展开，表面是一场吹气球比赛，实则是一场精心设计的"破坏行动"。\u000a\u000a1.  00:00 -\u000a    00:01：画面开始。左侧的粉蓝发女孩（高扎马尾）正鼓起腮帮全力吹气，她手中的肉粉色大脑纹理气球已经半满。右侧的\u000a    rumi\u000a    斜眼观察对方，嘴角带着一丝神秘的微笑，双手紧紧护住自己尚未充气的紫色气球。\u000a\u000arumi\u000a    迅速行动。她右手指间夹着一根细长的绿色尖锐物（针/牙签）。她一边对着镜头露出甜美且极具欺骗性的笑容，一边隐秘地将右手伸向左侧女孩的气球，在其底部边缘迅速扎入。\u000a\u000a完成破坏后，rumi\u000a    迅速收回右手并假装将"吹气管"衔入口中。左侧女孩毫无察觉，依然疯狂吹气，但由于底部破损，粉色气球停止膨胀并开始出现褶皱塌陷。\u000a\u000arumi\u000a    开始猛烈吹气，她的紫色气球迅速膨胀。左侧女孩发现自己的气球纹丝不动，露出疑惑且吃力的表情，由于用力过度，她的面部肌肉明显紧绷。\u000a\u000a结尾高潮点，rumi\u000a    的紫色气球膨胀到极限后瞬间炸裂，紫色碎片向四周飞溅。rumi\u000a    在炸裂瞬间露出得意的笑容，而左侧女孩被突如其来的爆炸声吓得缩起肩膀并闭上眼睛。画面在这一充满黑色幽默的"毁灭性"胜利时刻戛然而止。'),'粉蓝发女孩鼓起腮帮全力吹肉粉色气球，一旁的rumi双手紧紧护住自己的气球，嘴角带着一丝神秘微笑斜眼暗中观察','异常行为, 冲突对峙','搞笑','吹气球比赛→rumi偷偷用针扎破对手气球→假装吹气→自己气球快速膨胀→气球炸裂的毁灭性胜利','隐藏作弊','公平比赛假象→隐蔽破坏对手→自己轻松取胜→物理毁灭式收尾','','','5693915','17198','','故事类','rumi','用作弊手段赢得吹气球比赛','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/086_吹气球扎针作弊.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/086_吹气球扎针作弊.jpg','');
INSERT INTO videos VALUES(87,'2026-03-29','番茄酱软糖反击战','','https://www.youtube.com/shorts/rc0ykJI0rxA','scripts/1020-视频专业级影视拆解报告.md','2026-03-29 13:58:45','2026-03-29 20:58:51','No one is allowed to make fun of Rumi---not even Jinu','21','2026-03-23','','rumi正悠闲躺沙发玩手机，mira突然拿着一瓶红色番茄酱出现在后方大喊Rumi！并将瓶口对准她的额头猛力挤压','突发意外, 冲突对峙','搞笑','mira用假酱(软糖)整蛊rumi→rumi惊恐尖叫→发现是软糖→jinu在旁大笑→rumi愤怒用真番茄酱喷jinu→rumi和mira结盟胜利','恶作剧反转','A用假危险整B→B发现是假的→C嘲笑B→B用真危险反击C→A和B结盟','','','6655862','35413','','故事类','rumi','用真番茄酱反击嘲笑她的jinu','jinu','嘲笑被整蛊的rumi','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/087_番茄酱软糖反击战.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/087_番茄酱软糖反击战.jpg','');
INSERT INTO videos VALUES(88,'2026-03-29','辣椒三明治探病','','https://www.youtube.com/shorts/LtXqLLr-gHw','scripts/1021-视频专业级影视拆解：Lily Meow - Spicy Treat.md','2026-03-29 13:58:45','2026-03-29 20:57:53','Spicy Treat, Family Complete 🌶️👨‍👩‍👧‍👦 #lilymeow #lilymiumiu','60','2026-02-16',unistr('jinu（黑发）、romance（粉发）和baby（绿发）坐在粉色课桌后。画面主体是一位头戴粉色猫耳发箍的女孩（以下简称Lily），她正疯狂地往嘴里塞一大把鲜红的辣椒，双颊通红，表情痛苦却不停歇。\u000a\u000ajinu见状满脸担忧，迅速拿起一根香蕉递到Lily嘴边试图让她解辣；旁边的同学也递上苹果和橘子。Lily推开了香蕉，表情从痛苦转为一种固执的克制。\u000a\u000aLily将面前满满一盘红辣椒中尚未吃完的部分，以及男生们给的香蕉、苹果、橘子全部装进一个透明塑料保鲜盒中，扣好盖子离开教室。\u000a\u000a回到家中，Lily坐在餐桌前，依然捧着那把红辣椒。jinu（饰演父亲）和一位穿围裙的母亲走过来。\u000a\u000a父母担心她的健康，收走了Lily手中的辣椒盘，换上了一盘白面包。他们示意Lily吃面包，Lily表面顺从地拿起一片面包吃了一口。\u000a\u000a当父母转身去准备其他东西时，Lily迅速从桌下拿出之前打包好的保鲜盒，取出辣椒夹在面包里，做成"辣椒三明治"大口啃食。\u000a\u000a画面切换，Lily在父亲的陪同下，带着装有辣椒和水果的保鲜盒来到了"PSYCHIATRIC\u000a    HOSPITAL"（精神病院）。\u000a\u000a在病房区，Lily见到了她的哥哥baby。Lily露出温柔的笑容，将保鲜盒推到哥哥面前。哥哥显得极其兴奋，迫不及待地想要打开。\u000a\u000a哥哥高兴地揭开盒盖，但在看到里面整齐码放的鲜红辣椒时，表情瞬间凝固，从狂喜转为一种夹杂着怀念与伤感的复杂情绪。\u000a\u000a画面转为低饱和度的灰白色调。回忆中，还是健康状态的哥哥在厨房里耐心地为妹妹制作辣椒三明治，将辣椒一片片叠放。妹妹接过后大咬一口，随即被辣得眼泪汪汪、剧烈咳嗽，哥哥在一旁关切地看着她。\u000a\u000a画面回到现实彩色调。妹妹轻声向哥哥请求，让他再为自己制作一次当年的辣椒三明治。哥哥重拾往日的熟练动作，细心地做好并递给妹妹。妹妹接过后毫不犹豫地大口吃下，表情十分轻松，不再像回忆中那样咳嗽。父亲站在一旁，看着这对在病态中寻找慰藉的兄妹，眼神中充满无奈与深情。\u000a\u000a两人相视而笑，共同享受着这份独特的"家"的味道，画面最后定格在两人的特写，伴随着欢快的笑声音效。'),'头戴粉色猫耳发箍的Lily在教室疯狂往嘴里塞红辣椒表情痛苦。jinu满脸担忧，迅速拿起一根香蕉递到她嘴边试图解辣','异常行为','感动','教室狂吃辣椒→拒绝水果→打包辣椒回家→父母收走换面包→偷做辣椒三明治→去精神病院探望哥哥→回忆哥哥当年做辣椒三明治→现实中哥哥重做→兄妹相视而笑','极端执念与治愈反转','角色执拗做异常行为→被反复阻止→揭示行为背后是为了重现与病中亲人的共同记忆→用味觉唤醒情感','','','131574784','1415083','','故事类','Lily','带辣椒去精神病院让哥哥重做辣椒三明治唤醒记忆','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/088_辣椒三明治探病.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/088_辣椒三明治探病.jpg','');
INSERT INTO videos VALUES(89,'2026-03-29','Abby女装混入人头清点','','https://www.youtube.com/shorts/P0tQReuckJA','scripts/1022-视频专业级影视拆解：One two three_.md','2026-03-29 14:00:01','2026-03-29 20:56:08','** One two three? #kpop #funny #rumi #jinu #mira','','',unistr('1.  突发搜查：\u000a    画面开始，rumi（紫色麻花辫）面带怒色，手持木质棒球棍猛地推开卧室门冲入房间，随后mira（红色双马尾）紧随其后。\u000a\u000a2.  空间对峙： rumi 站在床尾，语气坚定地对躺在被子里的\u000a    jinu（黑发偏分男生）说："我知道她就在这里。" jinu\u000a    表现出极度惊慌，用手抓着头发回应："jinu，rumi，你在说什么？这里没人。"\u000a\u000a3.  开始清点： rumi 并不相信，下令进行"人头清点"（Head\u000a    count）。她、mira 和身后的\u000a    zoye（黑发双丸子头）排成一排。rumi 喊道："1, 2,\u000a    3！"随后下令："搜查房间！"\u000a\u000a4.  地毯式搜索： \\* mira\u000a    迅速趴下，低头看向床底，确认后起立喊道："Clear!"（安全）。\u000a\u000a    - zoye 走向衣柜，猛地拉开柜门，检查内部后转头喊道："Clear!"。\u000a\u000a    - 在窗帘后方，一个戴着金色长假发、穿着白色连衣裙的"高大女孩"（实为\u000a      abby 伪装）探出头来，也跟着喊道："Clear!"。\u000a\u000a5.  逻辑混淆： rumi\u000a    回到床尾，表情疑惑地挠了挠头，再次发起清点："1, 2\\..."。此时\u000a    mira 从床底钻出接力喊"1"，zoye 喊"2"，伪装成女孩的 abby\u000a    紧接着跳上床边清脆地喊出"3"。\u000a\u000a6.  暂时蒙混： rumi 被这种看似合理的清点结果迷惑了，松了一口气对\u000a    jinu 说："好吧，看来这里确实没人。你暂时安全了，jinu。" jinu\u000a    此时坐在床上，交叉双臂，露出尴尬而庆幸的笑容。\u000a\u000a7.  产生怀疑： 当四人准备离开时，rumi\u000a    突然停下脚步，转头盯着那个"金发女孩"（abby），疑惑地问道："等等，你为什么看起来那么像\u000a    abby？"\u000a\u000a8.  机智回应： 伪装成女孩的\u000a    abby（棕发肌肉男）虽然穿着低胸裙子，但语气镇定，用略带女声的语调回答："呃......很多人都这么说。abby\u000a    一定是个大美女吧，对吗？"\u000a\u000a9.  危机解除： rumi 似乎接受了这个解释，带着人马撤离了房间。\u000a\u000a10. 真相大白： 门关上后，abby\u000a    瞬间卸下伪装，粗犷地跳下床大喊："我的天，兄弟！我再也不干这事了，太险了！"\u000a    jinu 笑着夸赞："演技不错，兄弟。"\u000a\u000a11. 结局：\u000a    两人随即并排坐在床上，手里拿着游戏手柄，开心地打起游戏，床边还散落着薯片和可乐。'),'rumi手持棒球棍面带怒色推门冲入卧室，对躺在被子里的jinu喊我知道她就在这，jinu极度惊慌抓着头发说你在说什么？这里没人','冲突对峙','搞笑','rumi闯入搜查→清点人头1-2-3→搜床底衣柜窗帘→abby女装混入窗帘后也喊Clear→再次清点数字吻合→rumi怀疑像abby→abby自黑化解→危机解除→两兄弟打游戏','伪装混入人头清点','搜查者清点人数→伪装者混入清点队列自报平安→数字逻辑欺骗搜查者→差点暴露→用话术化解→得逞','','','','','','故事类','jinu','让abby女装帮他瞒过rumi的搜查','rumi','搜查jinu房间找出藏匿的人','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/089_Abby女装混入人头清点.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/089_Abby女装混入人头清点.jpg','');
INSERT INTO videos VALUES(90,'2026-03-29','耳朵里掏出披萨和怪兽','','https://www.youtube.com/shorts/8zfRjDvgS7I','scripts/1023-视频专业级影视拆解：The Mad Ear-Master.md','2026-03-29 14:00:01','2026-03-29 20:54:35','The Mad Ear-Master: The Disappearing Gum Ball #kpop','26','2026-03-22',unistr('画面开始，rumi（紫色长马尾）正兴致勃勃地向上抛起一颗粉色的口香糖球，张大嘴巴准备接住。然而球体在空中划出一道诡异的弧线，准确无误地落入了躺在旁边的\u000a    jinu（粉发男生）的右耳孔中。rumi\u000a    瞬间石化，双眼睁圆，表情从期待变为极度的惊恐与尴尬。\u000a\u000a镜头切换，jinu\u000a    躺在医疗椅上，满头大汗，牙关紧咬，神情极度痛苦。rumi\u000a    戴上了黑色乳胶手套，穿着白色围裙，暴力地将食指塞进 jinu\u000a    的耳朵里掏挖。令人费解的是，她竟然从中掏出了一块还冒着热气、拉丝严重的萨拉米披萨。jinu\u000a    疼得脸部扭曲，汗水顺着脸颊流淌。\u000a\u000arumi 继续疯狂挖掘，接着从 jinu\u000a    的耳朵里猛地扯出了一长串五颜六色的彩虹丝带。丝带源源不断，像喷泉一样覆盖在\u000a    jinu 的胸口。此时，医疗队的 mira（红色双马尾）和\u000a    zoye（黑发丸子头）推开手术室玻璃门冲了进来，大喊着"Master, we are\u000a    ready!"（大师，我们准备好了！）。rumi 霸气回应"Out of my\u000a    way!"（给我让开！），并接过一把巨大的未来科技激光枪。\u000a\u000arumi 用激光枪对准 jinu\u000a    的耳孔发射。伴随着高频震动和强光，她竟然成功取出了那颗最初落入的粉色口香糖球。她如获至宝地看着球体，对着镜头露出灿烂且心虚的微笑，随后迅速将球塞进自己嘴里咀嚼。\u000a\u000arumi\u000a    吃完后，脸颊泛起红晕，周围飘满粉色爱心特效，显得十分陶醉。画面最后，mira\u000a    和 zoye 拿着放大镜和 rumi 一起凑近 jinu 查看。此时镜头突然推向\u000a    jinu\u000a    的耳孔深处------一只巨大、狰狞且带有锯齿口器的蜈蚣形怪兽正对着屏幕发出咆哮。'),'rumi兴致勃勃向上抛球张大嘴接，口香糖球却诡异落入躺在旁边的jinu右耳孔中。rumi瞬间石化，满脸极度惊恐与尴尬','突发意外, 视觉目标绑架','搞笑, 惊悚','糖球落入耳朵→戴手套掏耳→掏出披萨→扯出彩虹丝带→医疗队激光枪取出糖球→rumi吃掉→爱心陶醉→突然耳内出现蜈蚣怪兽','体内异次元掏取','物品意外落入身体孔洞→逐步掏出荒诞物品→终于取回原物→以为结束→恐怖生物从孔洞中跳出','','','6001209','45427','','故事类','rumi','从jinu耳朵里取回掉进去的口香糖球','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/090_耳朵里掏出披萨和怪兽.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/090_耳朵里掏出披萨和怪兽.jpg','');
INSERT INTO videos VALUES(91,'2026-03-29','Abby要的是Rumi不是钱','','https://www.youtube.com/shorts/GKukG3_DL58','scripts/1024-视频专业级影视拆解：What exactly does Abby want.md','2026-03-29 14:00:01','2026-03-29 20:53:56','What exactly does Abby want?😅 #kpop #funny #shorts','22','2026-02-22',unistr('1.  00:00 -\u000a    00:02：jinu（黑发偏分男生）悠闲地坐在豪车驾驶座上，右手拿着一根薯条，正准备放入口中，神情自若。\u000a\u000a2.  00:02 -\u000a    00:04：镜头切换到车窗外，abby（红发短发，戴黄色针织帽）双手贴在玻璃上，瞪大双眼，露出一副极其渴望且可怜的乞求表情。\u000a\u000ajinu 察觉到了\u000a    abby，他故意将整盒金黄色的薯条伸向窗户诱惑对方。abby\u000a    看到后虽然眼神一亮，但并没有表现出极度想吃的欲望。\u000a\u000ajinu 又换成了巨大的汉堡，并在 abby\u000a    面前晃动。abby 的表情显得有些不耐烦，眼神不再看向食物。\u000a\u000ajinu 再次拿出冰镇可乐。abby 此时直接对着\u000a    jinu 嫌弃地摇了摇头，表示他想要的根本不是这些。\u000a\u000ajinu 最终掏出一叠厚厚的百美金大钞。abby\u000a    依然坚定地摇头，随后他伸出食指，越过 jinu\u000a    的肩膀，明确地指向汽车的后座。\u000a\u000ajinu\u000a    表情变得惊疑不定，疑惑地转头看向后座。画面切入后座视角，rumi（紫色麻花辫）正穿着赛车夹克坐在后排，对着窗外的\u000a    abby 优雅地微笑着点头。\u000a\u000a看到 rumi 给了回应，abby\u000a    瞬间由阴转晴，在窗外疯狂点头，神情极其兴奋且专注，眼神完全锁定了\u000a    rumi。\u000a\u000aabby 对着窗内的 rumi\u000a    用双手比出一个大大的爱心，表达他真正的目标其实是后座的女孩。'),'jinu悠闲坐在豪车驾驶座拿着薯条正准备吃。镜头切向窗外，abby双手贴在玻璃上瞪大双眼，露出一副极其渴望乞求的表情','冲突对峙','搞笑, 感动','薯条诱惑→摇头→汉堡诱惑→摇头→可乐→摇头→美钞→摇头→指向后座→揭晓rumi才是目标→abby比爱心','递进诱惑反转','依次展示食物→展示金钱→全部被拒→指向真正目标→揭晓人比物质更有价值','','','39398234','','','故事类','abby','获得后座的rumi而非物质','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/091_Abby要的是Rumi不是钱.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/091_Abby要的是Rumi不是钱.jpg','');
INSERT INTO videos VALUES(92,'2026-03-29','辣味救赎受伤的Jinu','','https://www.youtube.com/shorts/ZM_mJA2v9lg','scripts/1025-视频专业级拆解报告(1).md','2026-03-29 14:00:01','2026-03-29 20:52:01','Why did Rumi do this? The surprising reason behind the','60','2026-03-21',unistr('镜头开启于教室内，rumi正神情痛苦且偏执地狂啃一整捆鲜红的干辣椒。romance穿着灰色西装走近，厉声呵斥并强行夺走辣椒，随后递给她一片披萨命令她停止这种行为。rumi勉强咬了一口披萨后，竟面露决绝，用力将披萨扔向远处，随即再次从桌中抓起另一把辣椒狂吃。romance满脸惊愕地再次上前制止，此时镜头快速推向墙上挂着的金色合影相框，画面通过相框进入转场。\u000a\u000a深秋的银杏大道金黄灿烂，rumi在行走中又偷偷从怀里拿出红辣椒塞进嘴里。romance突然出现截住她，愤怒地将她手中的辣椒全部夺走并撒在满是落叶的地上，冷酷地宣告："Rumi，这就是对你的惩罚。"\u000a\u000a随后，由于意外导致双腿骨折、包裹着厚重白色石膏的jinu坐在轮椅上，由穿着白大褂的baby推着缓缓走来。mira和zoye兴奋地奔向他，一边送上金色蝴蝶结的精美礼品一边欢呼："Jinu，这是送给你的礼物！"。jinu虽然身体虚弱，仍礼貌地微笑着向大家致谢。\u000a\u000arumi俯身贴在jinu耳边神秘地耳语，这一举动引起了远处romance的警觉，他疑惑地自语："Rumi在耳语什么？"紧接着，rumi不顾jinu惊慌失措地连声呼喊"不、不、不！"，推着轮椅一路小跑，将他强行推进了一家主打辛辣口味的拉面店，口中还安抚道："没关系的Jinu，放松点。"\u000a\u000a面馆内，画面闪回至曾经的温馨回忆。当时还健康的jinu性格开朗，他指着面前那一碗铺满辣椒的红亮拉面兴奋地对rumi说："吃这个，Rumi！这个超好吃的。"随后他大口吃面，显得非常享受。而极度怕辣的rumi在勉强尝试吃了一口后，立刻被辣得满脸通红、剧烈咳嗽，甚至不断用手扇风。jinu见状无奈地轻轻叹了一口气。\u000a\u000a回到现实的面馆，jinu看着面前那碗辛辣的面显得极度迟疑。rumi神色坚定地直视他的双眼说："Trust\u000a    me,\u000a    Jinu."（相信我，Jinu）。说罢，她拿起金属剪刀，当着jinu的面将一大把鲜红辣椒咔嚓咔嚓地剪成碎片，源源不断地落入jinu的面碗中。jinu被这一举动吓得瞪大双眼，惊呼："你疯了吗，Rumi？！"。\u000a\u000arumi率先示范，大口吞咽着火辣的面条，以此鼓励jinu找回曾经的自己。受到触动的jinu也开始尝试进食。生理上的极端辛辣彻底击碎了jinu受伤以来的内心防线，他一边吃一边开始崩溃大哭，宣泄着压抑的情绪。窗外的romance目睹了这一幕，终于明白rumi苦练吃辣就是为了通过重现jinu曾经最爱的味道来治愈他，深受感动的他也流下了欣慰的眼泪。'),'rumi在教室痛苦偏执地狂啃一整捆鲜红干辣椒','异常行为','感动','rumi偏执吃辣→被romance制止→回忆jinu曾爱吃辣面→jinu受伤坐轮椅→rumi强行推他去面馆→剪辣椒进面碗→示范吃面→jinu崩溃大哭释放情绪→romance窗外落泪理解','极端执念与治愈反转','角色做出不可理解的自残行为→被反复制止→揭示行为是为了帮助受伤亲人→通过重现共同记忆治愈对方→旁观者理解落泪','','','7405016','114573','','故事类','rumi','苦练吃辣重现jinu最爱的味道来治愈他','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/092_辣味救赎受伤的Jinu.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/092_辣味救赎受伤的Jinu.jpg','');
INSERT INTO videos VALUES(93,'2026-03-29','被追逐的噩梦早安','','https://www.youtube.com/shorts/vyPBiNQT_0o','scripts/1026-视频专业级拆解报告(2).md','2026-03-29 14:00:01','2026-03-29 20:51:04','What happened to Jinu? #kpop #funny #shorts','33','2026-02-20',unistr('jinu（黑发偏分）身穿白色格子短袖衬衫和浅色牛仔裤，正提着一袋沉重的黑色垃圾袋走在草坪上。突然，一辆黑色大型皮卡停在路边，mira、rumi、zoye等成员猛地从车上跳下。jinu露出极度惊恐的表情，大喊"Oh\u000a    no! People!"，随即丢下垃圾袋疯狂逃窜。\u000a\u000ajinu跑向一栋白色外墙的房子，神色慌张地穿过前廊推门而入，成员们在后方紧追不舍，口中发出兴奋的尖叫。\u000a\u000ajinu躲进卧室，还没喘过气，窗帘缝隙中突然闪现出zoye、mira和rumi的脸。她们紧贴玻璃，手指疯狂敲击，面部因挤压而变形。jinu惊叫着摔倒在客厅地毯上，发现窗户另一侧依然是成员们狂热的笑脸。\u000a\u000ajinu试图从客厅玻璃移门逃走，但门刚拉开，rumi（紫色麻花辫）和mira（红色双马尾）已经堵在门口。jinu被迫转向厨房，绕着白色大理石岛台与成员们展开生死时速的追逐。\u000a\u000ajinu跑入走廊，疯狂关闭身后的房门，但每一道门后似乎都藏着人。他连滚带爬地翻过白色沙发，从正门冲出房子。\u000a\u000a镜头转到室外公路，jinu在空旷的马路上全力冲刺，rumi等人在后方呈扇形包抄。jinu最终体力不支，摔进路边的荒草丛中。他撑起上身，绝望地挥手尖叫："Leave\u000a    me alone!"（离我远点！）。\u000a\u000a画面剧烈晃动后切入特写。jinu满头大汗地在床上惊醒，大口喘气，眼神中充满未散的恐惧。镜头拉开，mira、rumi、zoye和romance突然出现在床边，整齐划一地露出灿烂且略显诡异的笑容，齐声说道："Good\u000a    morning!"。视频在问候声中结束。'),'jinu提垃圾袋走在草坪上，黑色皮卡突然停下成员们猛地跳出，jinu惊恐大喊Oh no People','经典桥段, 生命威胁','搞笑, 惊悚','成员跳下皮卡→jinu疯狂逃跑→躲进房间→窗户贴脸包围→厨房岛台追逐→翻沙发逃出→公路冲刺→摔进草丛→惊醒发现是噩梦→成员围床边齐喊Good morning','噩梦追逐反转','被群体疯狂追逐→无论怎么逃都被包围→极端压迫→突然惊醒是噩梦→但噩梦中的人就在床边→梦境照进现实','','','48239483','','','故事类','jinu','逃离成员们的疯狂追逐','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/093_被追逐的噩梦早安.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/093_被追逐的噩梦早安.jpg','');
INSERT INTO videos VALUES(94,'2026-03-29','La Mer空瓶重塑奇迹','','https://www.youtube.com/shorts/lwb_yWJpnZ8','scripts/1027-视频专业级拆解报告.md','2026-03-29 14:03:13','2026-03-29 20:49:23','DON\''T THROW IT AWAY! ⚠ 😱💎#rumi','20','2026-03-05',unistr('mira（红色双马尾）正对镜子，由于心爱的面霜用尽，她眉头紧锁，眼神哀伤，两颊贴着由粉色亮片组成的"泪痕"。她左手紧握\u000a    La Mer\u000a    面霜瓶，右手颤抖着举起银色挖勺，发现勺尖几乎没有残留，绝望地叹息："Oh\u000a    no\\..."。\u000a\u000amira\u000a    看着手中"空空如也"的瓶子，情绪进一步崩溃，嘴角大幅度下撇，大喊："It\\''s\u000a    actually\u000a    gone!"。随后，她心灰意冷地将手伸向一旁的金属垃圾桶，准备将瓶子直接丢弃。此时画面上方出现了金钱袋和钻石的动态\u000a    Emoji，暗示这份"垃圾"价值不菲。\u000a\u000a就在瓶子即将脱手的瞬间，Rumi（紫色麻花辫）和\u000a    Zoye（黑色丸子头）从身后两侧突然冲出。Rumi\u000a    露出一脸"你在开玩笑吗"的愤怒表情，迅猛地伸出右手，从垃圾桶上方夺走瓶子，大声训斥："No!\u000a    Do you know how much this costs?"。mira\u000a    被这突如其来的动作吓得猛地缩起脖子。\u000a\u000aRumi\u000a    一脸严肃地低头查看瓶内，左手稳稳持瓶，右手熟练地操纵金属勺在瓶壁内缘的死角进行精准刮取。mira\u000a    在后方双手紧紧捂住嘴巴，瞳孔放大。\u000a\u000a镜头切至极致特写，展示勺尖从看似干净的瓶底深处挖出了一大坨厚实的白色膏体。mira\u000a    发出极度夸张的惊呼："No way!"。\u000a\u000a转场至工作台。Rumi\u000a    将挖出的面霜膏体利落地刮入一个通透的玻璃碗中。\u000a\u000aZoye\u000a    伸出右手，轻捏滴管，在碗中加入一滴如液态黄金般的修护精华油。\u000a\u000aRumi\u000a    使用金色小型打蛋器在碗中飞速搅拌，膏体在物理混合下变得轻盈、晶莹且充满光泽。\u000a\u000aZoye\u000a    露出自信的微笑，双手托起重新装满面霜的瓶子伸向镜头，瓶身在补光灯下闪闪发光。\u000a\u000amira\u000a    将修复后的面霜涂抹在右脸颊，闭眼享受质感的提升，发出"Mmm\\... so\u000a    smooth"的赞叹，最后对着镜头大力竖起大拇指。Rumi 和 Zoye\u000a    在背景中挺胸抬头，露出深藏功与名的微笑。'),'mira贴着亮片泪痕绝望地要把La Mer空瓶扔进垃圾桶','异常行为','搞笑','mira要扔贵价面霜空瓶→rumi冲出抢救→从瓶壁死角刮出大坨膏体→加精华油搅拌修复→涂脸验证效果','废弃贵物极限抢救','角色要丢弃贵重物品→另一角色阻止并展示隐藏价值→专业级修复过程→物品重生','','','5449659','30967','','形式类','rumi','阻止mira丢弃空瓶并修复面霜','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/094_La Mer空瓶重塑奇迹.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/094_La Mer空瓶重塑奇迹.jpg','');
INSERT INTO videos VALUES(95,'2026-03-29','街头小孩救赎冷漠jinu','','https://www.youtube.com/shorts/i8S8bda1H_8','scripts/1028-视频专业级拆解报告（修正版）.md','2026-03-29 14:03:13','2026-03-29 20:48:31','Kid Mira & Zoey save the day of Jinu.💓😭 #rumi','29','2026-03-09','','jinu抓着rumi手腕在街道奔跑赶电影，rumi的靴子踢翻了路边乞讨小孩的碗硬币散落','突发意外','感动','赶电影踢翻碗→rumi内疚回头→帮小孩捡硬币→小孩送玫瑰→jinu急躁催促→踩水坑摔倒→小孩贴创可贴捡本子→jinu心态转变邀请看电影','以德报怨心态转化','角色A冷漠忽视弱者→角色B主动帮助弱者→A因因果报应受伤→弱者反过来帮助A→A心态转变','','','8497078','63636','','故事类','rumi','弥补踢翻碗的过失帮小孩捡硬币','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/095_街头小孩救赎冷漠jinu.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/095_街头小孩救赎冷漠jinu.jpg','');
INSERT INTO videos VALUES(96,'2026-03-29','三轮挑战贪心全败','','https://www.youtube.com/shorts/qYuiw5S6no0','scripts/1029-视频分析报告：Jinu vs. Rumi 挑战赛.md','2026-03-29 14:03:13','2026-03-29 20:47:41','Jinu was too smart for his own good #jinu #kpop #rumi','53','2026-02-27',unistr('视频通过三轮离奇的"求生挑战"，展现了角色 jinu\u000a因"自作聪明"而连续落败的荒诞过程。\u000a\u000a1.  第一轮：餐具挑战\u000a\u000a    - 在阳光明媚的公园，jinu 和 rumi 相对而坐，面前是一张蓝色的空桌子。\u000a\u000a    - 画面外递出两个叉子：一个是普通的银色餐叉，另一个是巨大的钢制叉（约半米长）。\u000a\u000a    - jinu 抢先夺过大叉子，露出自信且挑衅的表情，对 rumi 说："Rumi,\u000a      那个大的是我的！你输定了！"\u000a\u000a    - 随着"Ding Ding\u000a      Ding"的提示音，桌上的白盘子里凭空出现了两颗樱桃。裁判 mira\u000a      吹响哨音。\u000a\u000a    - rumi 轻松用小叉子叉起樱桃送入嘴中；jinu\u000a      却因为大叉子重心不稳且受力点过大，尝试多次都无法精准扎中樱桃，表情从狂妄转为绝望。\u000a\u000a    - mira 宣布："第一轮获胜者是 Rumi！"jinu 抱头哀嚎。\u000a\u000a2.  第二轮：清扫挑战\u000a\u000a    - 场景转换至秋季森林小径，地面起初是干净的，没有落叶。\u000a\u000a    - 任务是看谁先将叶子扫成一堆。\u000a\u000a    - 画面给出两个工具：一把红色长柄大扫帚，一把极小的红色牙刷。\u000a\u000a    - jinu\u000a      此时心生一计，认为大工具可能是陷阱，于是坚决选择了小牙刷，边选边自语："那大叉子绝对是个陷阱，这次我要动脑子......"\u000a\u000a    - rumi 拿着扫帚露出震惊的表情："你确定要用牙刷？"\u000a\u000a    - 随着比赛开始的提示音，干净的地面上瞬间凭空铺满了厚厚的枯叶。\u000a\u000a    - rumi 两三下扫帚就聚拢了叶堆；jinu\u000a      跪在地上用牙刷一根一根拨弄叶子，满脸通红。\u000a\u000a    - rumi 轻松取胜，跳起庆祝："两胜了宝贝！太简单了！"jinu\u000a      趴在地上怀疑人生。\u000a\u000a3.  第三轮：登山挑战\u000a\u000a    - 场景来到高山之巅，背景是宏伟的雪山山脉。\u000a\u000a    - 任务是看谁先到达山顶。\u000a\u000a    - 画面给出两个背包：一个明黄色专业大登山包（装得满满当当），一个深蓝色迷你小背包。\u000a\u000a    - jinu\u000a      彻底陷入博弈思维，为了"稳赢"，他决定不再选择，直接将两个包全部抢走："这次我两个都拿！绝不可能再输！"\u000a\u000a    - 比赛开始。rumi 轻装上阵在山脊上飞奔，动作轻盈；jinu\u000a      背着两个包（总重惊人），在陡峭的山坡上四肢着地艰难爬行，汗流浃背，五官挤在一起。\u000a\u000a    - 最终，rumi 站在山顶从裁判 mira 手中接过奖杯。\u000a\u000a    - 结局反转：jinu\u000a      挣扎着爬到顶峰，打开明黄色大包，发现里面装满了沉重的花岗岩石块。\u000a\u000a    - jinu 崩溃大喊："石头？！你在开玩笑吗？我背了一山的石头！"\u000a\u000a    - rumi 走过来调侃："嘿，往好处想，虽然你没赢，但你锻炼了身体！"\u000a\u000a    - 视频在 jinu 仰头瘫倒在地、rumi 叉腰大笑的定格中结束。'),'公园里jinu和rumi相对而坐，两只手递出一大一小两个叉子，jinu抢先夺走大叉子','竞赛与挑战, 异常物品, 致命傲慢','搞笑','第一轮选大叉子叉不起樱桃→第二轮学聪明选小牙刷扫不了落叶→第三轮抢两个包全背→爬山负重石头全败','策略进化全败循环','选大失败→吸取教训选小→又失败→两个都要→背了一山石头→策略越精明结果越惨','','','9757896','98346','','故事类','rumi','赢得三轮挑战赛','jinu','通过策略选择赢过rumi但每次都选错','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/096_三轮挑战贪心全败.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/096_三轮挑战贪心全败.jpg','');
INSERT INTO videos VALUES(97,'2026-03-29','肌肉猛男妈咪来了','','http://www.youtube.com/watch?v=4U7qRkR_9I0','scripts/1030-视频分析：妈咪？的荒诞喜剧.md','2026-03-29 14:03:13','2026-03-29 20:45:13','Mommy？🤦🏼‍♂️🤦🏼‍♂️#kpopdemonhunters #funny #jinu #rumi','9','2026-03-17',unistr('1.  \\[[[00:00]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=0)\\]\u000a    在一个阳光明媚的公园草地上，jinu（黑发偏分，穿着橙色登山夹克）正坐着和三个孩子野餐。孩子们分别是：rumi（紫色麻花辫）、mira（红色双马尾）和zoye（黑发双丸子头）。他们周围散落着薯片、拉面和一只蓝色条纹的玩具猫。jinu\u000a    显得很放松，正微笑着看着孩子们。\u000a\u000a2.  \\[[[00:01]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=1)\\]\u000a    突然，三个孩子像是看到了什么，同时举起右手指向前方。rumi 和\u000a    zoye 异口同声地兴奋尖叫："Mommy!"（妈咪！）。\u000a\u000a3.  \\[[[00:02]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=2)\\]\u000a    jinu\u000a    脸上的笑容瞬间消失，取而代之的是极度的困惑。他眉头微蹙，嘴唇微张，疑惑地重复了一句："Mommy?"。\u000a\u000a4.  \\[[[00:03]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=3)\\]\u000a    jinu\u000a    僵硬地转过头，视线顺着孩子们指的方向看去，表情从困惑逐渐转为惊恐，瞳孔微颤。\u000a\u000a5.  \\[[[00:04]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=4)\\]\u000a    镜头一转，一位体型极其夸张、肌肉如岩石般隆起的粉发猛男（romance）正向他们狂奔而来。他戴着金色大耳环，穿着一件带有云朵和彩虹图案的粉色围裙，下半身竟然是一条粉色短裙。他双手端着一个插着点燃蜡烛的小白蛋糕，用粗犷却又带着喜感的声调喊着："Come\u000a    to mommy, sweetie!"（来妈咪这儿，宝贝！）。\u000a\u000a6.  \\[[[00:05]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=5)\\]\u000a    在 romance 身后，成年版的\u000a    rumi（紫色长发）也穿着一身粉色荷叶边套装，张开双臂兴奋地跟着跑来。\u000a\u000a7.  \\[[[00:07]{.underline}](http://www.youtube.com/watch?v=4U7qRkR_9I0&t=7)\\]\u000a    镜头切回 jinu\u000a    的极近距离特写。他因为过度震惊而面部扭曲，双眼瞪圆，嘴巴张大到夸张的程度，爆发出了一声尖锐且漫长的惨叫："Noooo------!"，直到视频结束。'),'公园草地上jinu和三个小孩野餐，小孩们突然指向前方兴奋喊Mommy','提出疑问','搞笑, 荒诞','温馨野餐→小孩喊妈咪→jinu困惑→镜头揭示粉裙围裙肌肉猛男romance端蛋糕狂奔→jinu惨叫崩溃','身份揭示极端反差','温馨铺垫→悬念提问(谁是妈咪)→揭示答案与预期极端相反→角色崩溃','','','20300059','88992','','故事类','jinu','带孩子们野餐','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/097_肌肉猛男妈咪来了.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/097_肌肉猛男妈咪来了.jpg','');
INSERT INTO videos VALUES(98,'2026-03-29','吃辣椒喷火救冰封jinu','','https://www.youtube.com/shorts/x4e_Lz9N08I','scripts/1031-视频影视拆解报告(1).md','2026-03-29 14:03:13','2026-03-29 20:44:43','How can Rumi save Jinu from the ice?​😱#kpop','23','2026-03-21',unistr('1.  00:00 -\u000a    00:01：在明亮的白色厨房里，rumi（紫色麻花辫）正小心翼翼地用银色金属夹子从一盘绿色的方形糖果中夹起一颗。她神情专注，正准备将其放入口中。\u000a\u000a2.  00:01 -\u000a    00:02：突然，站在对面的jinu（黑发偏分）迅速伸手，从rumi的夹子尖端一把抢走了那颗绿色糖果，并挑衅般地直接塞进自己嘴里。rumi惊讶地张开嘴巴，右手还保持着握夹子的姿势，愣在原地。\u000a\u000a3.  00:02 -\u000a    00:03：糖果入口瞬间，jinu的脸色剧变，双眼暴突，表情极度痛苦。他的口腔和鼻腔开始喷涌出大量浓密的白色寒气，仿佛体内有一台制冷机正在失控。\u000a\u000ajinu艰难地从牙缝中挤出一句："I am freezing\u000a    now!"\u000a    话音未落，一股淡蓝色的半透明冰层迅速从他脚底蔓延至全身，瞬间形成一个巨大的立方体冰块，将他整个人垂直封印。\u000a\u000a5.  00:05 -\u000a    00:07：rumi被吓得惊叫一声，随即反应过来，转身抓起一个黑色长嘴热水壶，将滚烫的热水倾倒在冰块顶部。然而水滴接触冰块后只是飞溅，冰块表面毫无融化迹象，rumi露出懊恼和焦虑的表情。\u000a\u000a6.  00:07 -\u000a    00:09：rumi迅速蹲下身子，由于动作幅度大，粉色开衫随之晃动。她拉开下方的木制抽屉，精准地抓出一把金黑色涂装的工业喷火枪。\u000a\u000a她站起身，双手紧握喷火枪对准冰块腹部，大喊："Melt\u000a    right\u000a    now!"。扣动扳机后，一股幽蓝色的高温火焰喷涌而出，火苗在冰面上舔舐，产生了一些白烟，但冰块本体纹丝未动。\u000a\u000a8.  00:11 -\u000a    00:13：面对喷火枪的失败，rumi眼神中闪过一丝决绝。她看向桌上突然出现的一大堆红亮如血的指天椒。\u000a\u000a9.  00:13 -\u000a    00:15：rumi双手猛地抱起整堆辣椒，眼神变得狂热。她不顾辛辣，分两次将大量辣椒强行塞进嘴里疯狂咀嚼，脸部肌肉因刺激而抽搐，眉头紧拧成川字。\u000a\u000a10. 00:15 -\u000a    00:17：rumi全身皮肤瞬间充血变红，脸上浮现出放射状的暗红色发光裂纹，双眼彻底转化为耀眼的蓝色冷光。她张开大嘴，喉咙深处喷发出蓝白色的光弧，伴随着震耳欲聋的声音："Watch\u000a    out now!"\u000a\u000a11. 00:17 -\u000a    00:20：rumi呈半蹲战斗姿态，对着冰块喷射出一股如同喷气式发动机尾焰般的蓝白色火龙（龙息）。火龙瞬间吞噬了整个冰块，画面因极高温度而产生剧烈的空气扭曲感。\u000a\u000a12. 00:20 -\u000a    00:23：在一阵巨大的蒸汽爆裂声中，冰块完全汽化。jinu安然无恙地站在原地，惊魂未定地拍打着自己的衣服。rumi恢复常态，自信地面对镜头摊开双手，露齿而笑，说出标志性的："That\u000a    looks amazing!"'),'rumi用银色夹子夹起绿色糖果，jinu伸手抢走塞进嘴里，瞬间喷出大量白色寒气','身体异常','搞笑, 热血','抢糖果→被冻成冰块→热水壶无效→喷火枪无效→吃辣椒变身→喷出龙息融化冰块→成功救人','递进挑战','常规方法1失败→升级方法2失败→极端方法(吃辣椒)→触发超能力变身→一击解决','','','11578496','62179','','故事类','rumi','用各种方法融化冰块救出被冻住的jinu','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/098_吃辣椒喷火救冰封jinu.mp4','https://aiyoutube.oss-cn-beijing.aliyuncs.com/thumbs/098_吃辣椒喷火救冰封jinu.jpg','');
INSERT INTO videos VALUES(99,'2026-03-29','水泵作弊喝饮料比赛','','https://www.youtube.com/shorts/BZqN7xiEjw4','scripts/1032-视频影视拆解报告.md','2026-03-29 14:04:24','2026-03-29 19:45:09','Is jinu cheating? #funny #kpop #kpopdemonhunters #comedy','15','2026-03-19','','jinu和rumi并排站在巨大高脚杯前，倒计时3-2-1-Drink开始喝红色饮料','冲突对峙','搞笑','喝饮料比赛→rumi拼命吸液面不动→jinu轻松液面骤降→揭露桌下romance操控工业水泵抽水→rumi崩溃质疑→jinu庆祝','隐藏作弊','公平比赛假象→一方轻松获胜→揭示隐藏在视觉盲区的第三方帮手→被骗者崩溃→作弊者庆祝','','','13037439','69515','','故事类','rumi','赢得喝饮料比赛','jinu','通过桌底romance操控水泵作弊获胜','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/099_水泵作弊喝饮料比赛.mp4','/thumbs/099_BZqN7xiEjw4.jpg','');
INSERT INTO videos VALUES(100,'2026-03-29','三轮竞技冰块叉子石头','','https://www.youtube.com/shorts/WqT2ePETW9c','scripts/1033-视频拆解分析报告.md','2026-03-29 14:04:24','2026-03-29 19:45:09','Who Is The Winer? #kpopdemonhunters #kpop #shorts #funny','40','2026-03-09',unistr('在亮丽的舞台背景下，jinu（黑发偏分）和rumi（紫色麻花辫）站在两个悬挂的银色金属桶下。jinu显得非常自信，他伸出左手示意rumi走开，嘴里说着："Move\u000a    away, I\\''ll choose the smaller\u000a    one"（让开，我选小的那个），他认为小的桶里藏着好运。rumi则保持安静，微笑着看向镜头。\u000a\u000a随着倒计时，两个桶同时翻转。jinu头上的小桶倾倒出大量坚硬的冰块，jinu瞬间被冻得面部扭曲，张大嘴巴发出一声惨叫。而rumi头上的大桶则撒下了漫天红玫瑰花瓣。rumi惊讶地抬头，随后露出灿烂的笑容，双手握拳庆祝："Yay,\u000a    I win!"（耶，我赢了！）。\u000a\u000amira（红色双马尾）穿着蓝色短裙出现在画面中心，她抓起rumi的手高高举起，宣布："In\u000a    round one, Rumi\\''s the\u000a    winner!"（第一轮，Rumi获胜！）。rumi笑得非常开心，而jinu则站在一旁，湿漉漉的，表情沮丧且狼狈。\u000a\u000a场景切换，两人面前摆着一大一小两把叉子。jinu一脸神气地指着巨大的银色钢叉说："The\u000a    big one is mine, the small one is\u000a    yours"（大的归我，小的归你）。rumi优雅地拿起小叉子叉起一颗红润的草莓送入嘴中，发出了满意的赞叹："So\u000a    sweet!"（好甜！）。\u000a\u000ajinu试图举起那把巨大的钢叉，由于钢叉极其沉重，他全身肌肉紧绷，脸部因为过度用力而涨红。然而，当巨型钢叉终于砸向草莓时，由于体积太重，直接将草莓砸成了肉泥，jinu目瞪口呆，整个人僵在原地。\u000a\u000ajinu不服输，他背起两个巨大的黑色双肩包，大声宣告："I\u000a    can\\''t lose this round, I\\''m going to take both of\u000a    them!"（这轮我不能输，这两个包我都背了！）。mira再次出现在楼梯间前方，向观众发起互动："Who\u000a    would you save from the shark?"（你会从鲨鱼口中救谁？）。\u000a\u000amira宣布规则：谁先跑楼梯上到5楼谁就赢。rumi一身轻便，立刻飞快地向上冲。jinu背着两个沉重的包，在楼梯上举步维艰，最后甚至变成了四肢着地的爬行，气喘吁吁，满脸通红。\u000a\u000arumi率先到达楼梯顶端，举起金色奖杯。mira宣布："The\u000a    overall victory goes to\u000a    Rumi!"（总冠军是Rumi！）。jinu瘫坐在楼梯上，愤怒地打开身后的黑色背包，发现包里装满了沉重的大石头，他崩溃地对着镜头大吼："What\u000a    the hell is this!"（这到底是什么鬼！）。'),'舞台背景下jinu和rumi站在悬挂的银色金属桶下，jinu自信地要选小桶','竞赛与挑战, 致命傲慢','搞笑','选小桶被冰块砸→rumi得玫瑰花瓣→第二轮选大叉子砸烂草莓→第三轮背两个包爬楼梯→包里全是石头','策略进化全败循环','选大失败→选小又失败→两个都要→背了一楼道石头→贪心越重惩罚越大','','','9150181','500934','','故事类','rumi','赢得三轮竞技挑战','jinu','通过策略选择赢过rumi但全部选错','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/100_三轮竞技冰块叉子石头.mp4','/thumbs/100_WqT2ePETW9c.jpg','');
INSERT INTO videos VALUES(101,'2026-03-29','僵尸整蛊洗碗惩罚','','http://www.youtube.com/watch?v=chsvJrOEXnA','scripts/1034-视频拆解报告(1).md','2026-03-29 14:04:24','2026-03-29 19:45:09','Rumi & Junu Zombie Prank #kpop #funny #rumi #jinu','44','2026-03-06',unistr('Jinu 和 Rumi\u000a    牵手走在透明的高空玻璃栈桥上。由于视角原因，前方桥面看起来平整完好。Rumi\u000a    突然发现脚下出现了密集的白色碎裂纹路，表现出极度的恐慌，尖叫着"Jinu,\u000a    go back! It\\''s cracking!"（Jinu\u000a    快回去！裂开了！）。她身体僵硬，试图向后逃跑。Jinu\u000a    却一脸淡定，他迅速发力，一个公主抱将 Rumi\u000a    横抱起来。为了证明安全，他不仅没有后退，反而用力在那些已经存在的碎裂纹路上连续重踩。Rumi\u000a    紧闭双眼尖叫，双手死死搂住 Jinu 的脖子。Jinu 笑着俯视她说"Rumi you\u000a    are so dumb, just look, it\\''s fake."（Rumi\u000a    你太蠢了，看，这是假的）。随后 Rumi\u000a    睁眼看到裂纹并无变化，两人相视大笑。\u000a\u000a转场至阳光明媚的泳池边。Rumi\u000a    穿着粉色上衣，坐在桌前看着一整只烤鸡，兴奋地大喊"I\\''m so hungry, I\u000a    will eat now!"（我太饿了，现在就要开吃！）。Jinu\u000a    坐在一旁，略显疲惫地按着胸口。正当 Rumi\u000a    咬下鸡腿时，她的脸瞬间变成了恐怖的绿色僵尸面孔，眼睛放大，布满血丝。Jinu\u000a    被吓得魂飞魄散，大叫"Oh no! Rumi is a zombie!"（噢不！Rumi\u000a    变成僵尸了！），然后一个大跨步跳入身后的泳池中。\u000a\u000a镜头切换，Rumi\u000a    恢复了正常的外貌，正津津有味地啃着鸡腿，嘲讽道"So dumb, this is so\u000a    delicious."（真笨，这太好吃了）。此时，穿着女仆装的\u000a    Mira（红色双马尾）走近，递过一张账单并冷冷地说道"This is your\u000a    bill."（这是你的账单）。Rumi\u000a    接过账单一看，脸色瞬间凝固，瞳孔放大，惊呼"Oh my god, I forgot my\u000a    wallet!"（天哪，我忘了带钱包！）。\u000a\u000aMira 面无表情地回应"Fine, you don\\''t\u000a    have to pay if someone subscribes and comments for\u000a    you."（好吧，如果有人为你订阅并评论，你就不用付钱）。Rumi\u000a    绝望地看着屏幕前的观众说"No, they won\\''t do that, they are just\u000a    scrolling now."（不，他们不会做的，他们现在只是在刷视频）。Mira\u000a    嘴角微微上扬，露出一丝狡黠的微笑："Okay then, I have another\u000a    solution."（那好吧，我还有另一个办法）。\u000a\u000a画面再次转场，Rumi\u000a    出现在阴暗潮湿、蒸汽弥漫的餐厅后厨。她满脸泪痕，正辛苦地刷着堆积如山的白盘子。由于水太烫且由于盘子太多感到绝望，她不时发出尖叫。她哭丧着脸对着镜头哀求"Please,\u000a    someone subscribe and comment for me, anyone,\u000a    please!"（拜托，谁帮我订阅评论一下吧，任何人，拜托了！）。'),'jinu和rumi牵手走在高空玻璃栈桥上，脚下出现密集碎裂纹路','生命威胁, 突发意外','搞笑','玻璃栈桥吓rumi→jinu公主抱踩踏证明是假的→泳池边rumi吃鸡变僵尸脸→jinu跳水→mira递账单没钱→打破第四面墙求订阅→后厨洗碗惩罚','第四面墙求助','段落A整蛊→段落B反转整蛊→段落C现实惩罚→打破第四面墙将解决方案交给观众','','','5312199','268625','','故事类','rumi','在各段整蛊中求生并最终向观众求助','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/101_僵尸整蛊洗碗惩罚.mp4','/thumbs/101_chsvJrOEXnA.jpg','');
INSERT INTO videos VALUES(102,'2026-03-29','宠物诊所巨嘴示范','','http://www.youtube.com/watch?v=T_hQsNCCLLg','scripts/1035-视频拆解报告(10).md','2026-03-29 14:04:24','2026-03-29 19:45:08','#kpopdemonhunters #kpop #mira #rumi','16','2026-03-11',unistr('视频开始于一个明亮的宠物诊所场景。rumi（紫色长麻花辫）正俯身在一张白色检查台上，她佩戴着医用听诊器，手里拿着一根木质压舌板，面对着一只戴着红色鱼纹围巾的橘色大猫。\u000a\u000arumi\u000a    弯下腰，表情认真且富有耐心，她对猫说："张开嘴，说''啊''。"（Open your\u000a    mouth and say ah）。橘猫乖巧地张开了小嘴，发出微弱的"啊"声。\u000a\u000arumi\u000a    显然对猫的张嘴程度不满意，她眉头微皱，语速加快，情绪变得有些急躁，喊道："不，大声点！张得更开点！"（No\u000a    louder Open it wider）。\u000a\u000a为了给猫做示范，rumi\u000a    迅速挺直身体。在画面一闪的快速剪辑中，她脱下了亮黄色的赛车夹克，瞬间换上了一件整洁的白色医生实验袍。接着，她再次俯身贴近猫，眼睛瞪得滚圆，嘴巴突然超现实地扩张成一个巨大的椭圆形，露出了整齐的牙齿和深不见底的喉咙，表情极度夸张，仿佛某种恶魔或卡通人物。\u000a\u000a橘猫被这一幕吓得瞳孔地震，整个身体僵住，露出极度震惊的表情。随后，橘猫像是被激发了潜能，也猛地张开了几乎占满全脸的巨口，发出了响亮的嚎叫。\u000a\u000arumi\u000a    看到这一幕非常满意，恢复了温柔的表情，微笑着收起压舌板，夸奖道："完美，保持那样。"（Perfect\u000a    Just stay like that）。'),'明亮宠物诊所里，穿白大褂戴听诊器的rumi拿着压舌板，面对着一只戴红围巾橘猫，认真耐心地引导张开嘴，说啊','异常行为, 异常物品','搞笑','让猫张嘴→猫张得不够→rumi变急躁→换白大褂→夸张示范嘴巴超现实扩张→猫被吓到也猛张大嘴→rumi满意夸奖','极端示范引发模仿','要求对方做动作→对方做得不够→示范者用超现实的极端方式示范→对方被惊吓后做出同样极端的反应→目标达成','','','7441235','30802','','故事类','rumi','让橘猫张大嘴巴接受检查','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/102_宠物诊所巨嘴示范.mp4','/thumbs/102_T_hQsNCCLLg.jpg','');
INSERT INTO videos VALUES(103,'2026-03-29','柔术女王越狱挑战','','https://www.youtube.com/shorts/WZCd8zpK0nw','scripts/1036-视频拆解报告(11).md','2026-03-29 14:04:24','2026-03-29 19:45:08','Rumi, the world\''s most agile woman, challenges prison','32','2026-02-27','','阳光明媚海滩上，romance神情兴奋介绍挑战。rumi在简易监狱栏杆后展示出惊人动作：右腿完全竖直向上劈叉，紧紧贴着栏杆','身体异常, 竞赛与挑战','热血','Level1普通栏杆侧身穿过→Level2网格四肢折叠钻出→Level3极限安全监狱10cm缝隙匍匐挤过→三关全通','递进挑战','简单关卡展示基础能力→中等关卡展示进阶技巧→极限关卡看似不可能→分步骤完成→观众惊叹','','','9097090','58046','','形式类','rumi','通过三种不同难度的监狱围栏','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/103_柔术女王越狱挑战.mp4','/thumbs/103_WZCd8zpK0nw.jpg','');
INSERT INTO videos VALUES(104,'2026-03-29','蓝色液体跨次元互喷','','https://www.youtube.com/shorts/7kz-cdlLxTA','scripts/1037-视频拆解报告(2).md','2026-03-29 14:08:28','2026-03-29 19:45:08','RUMI thought he was a GHOST! #kpop #rumi #abby #funny','24','2026-03-02',unistr('1.  00:00 -\u000a    00:02：场景开启，mira（红色双马尾）正坐在木质书桌前，面对一台巨大的笔记本电脑。电脑屏幕中，romance（粉发、戴黄色冷帽）正坐着吃薯条。mira右手拿着一杯深蓝色的饮料，正准备喝。\u000a\u000a2.  00:02 -\u000a    00:04：屏幕里的romance突然停止嚼薯条，皱着眉头大声说："Too\u000a    dry, I need a\u000a    drink!"（太干了，我需要喝点东西！）。他伸出右手，竟然穿透了屏幕平面，向mira手中的杯子抓去。mira露出惊讶的表情，双眼圆睁。\u000a\u000a3.  00:04 -\u000a    00:06：mira迅速喝了一大口蓝色饮料，脸颊像气球一样鼓起，眼神充满恐慌和调皮。紧接着，她对着屏幕用力一喷，蓝色的液体直接喷到了屏幕上。\u000a\u000a4.  00:06 -\u000a    00:08：画面切回笔记本屏幕，romance的脸和上半身被厚重的蓝色液体完全覆盖。他紧闭双眼，表情扭曲，背景也被染蓝。桌子上也滴落了大量蓝色液体。\u000a\u000aromance抹了一把脸上的液体，愤怒地喊道："Are\u000a    you kidding\u000a    me?!"（你在开玩笑吗？！）。随后，他猛地一抬头，从屏幕内向屏幕外的mira反向喷出一大口蓝色液体。\u000a\u000a6.  00:10 -\u000a    00:12：mira的脸瞬间被喷成了全蓝色。她发出一声惊叫，然后开始大笑。此时，rumi（紫色麻花辫）从背景的客厅区域跑过来，看到满脸蓝色的mira，露出极度惊恐的表情，双手捂嘴。\u000a\u000arumi靠近电脑，惊恐地喊道："Mira, what\u000a    happened?!"。当她看到屏幕上满脸蓝色、面目狰狞的romance时，发出了高分贝的尖叫。\u000a\u000a8.  00:14 -\u000a    00:16：rumi认定屏幕里那个蓝脸的东西是怪物或鬼。她一边尖叫"What\u000a    on earth is that?! Get away you silly blue\u000a    guy!"，一边握紧拳头，眼神变得坚定而恐惧。\u000a\u000a9.  00:16 -\u000a    00:18：rumi挥起右手拳头，用尽全力击打笔记本电脑屏幕。伴随着巨大的碎裂声，屏幕中心出现了密集的蛛网状裂纹。\u000a\u000a10. 00:18 -\u000a    00:24：屏幕彻底损坏。rumi看着碎裂的屏幕，意识到自己反应过度，开始尴尬地大笑。mira摸着自己蓝色的脸，指着破碎的笔记本电脑，苦笑着喊："My\u000a    laptop!"。两人在混乱和蓝色液体中笑成一团。'),'mira坐在巨大的笔记本电脑前手拿深蓝色饮料正准备喝，屏幕中吃薯条的romance突然停止咀嚼，皱眉大喊Too dry! I need a drink!','异常物品','搞笑','romance从屏幕伸手要饮料→mira含满蓝色液体喷向屏幕→romance被喷满脸→反向喷回mira→rumi跑来误以为是鬼→一拳砸碎屏幕→尴尬大笑','跨次元互喷+误判暴力','屏幕内角色破维互动→屏幕外角色反击→双向喷射升级→第三方误判为恐怖→过激反应毁坏物品','','','12113915','65204','','故事类','mira','阻止romance从屏幕伸手抢饮料','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/104_蓝色液体跨次元互喷.mp4','/thumbs/104_7kz-cdlLxTA.jpg','');
INSERT INTO videos VALUES(105,'2026-03-29','僵尸整蛊披萨店揉面','','https://www.youtube.com/shorts/ngxtJIrIW8w','scripts/1038-视频拆解报告(3).md','2026-03-29 14:08:28','2026-03-29 19:45:08','Rumi & Junu Zombie Prank 🧟‍♀️🧟‍♀️🧟‍♀️#kpop #funny #rumi #jinu','49','2026-03-12',unistr('秋季繁华的街道上，rumi（紫色麻花辫）挽着jinu（黑发偏分）的手臂前行。rumi突然停下，露出惊恐的表情，右手食指颤抖着指向地面上由枯叶堆积而成的、张着血盆大口的巨大mira肖像。\u000a\u000ajinu看到后疯狂大笑，拍着rumi的肩膀嘲讽她胆小，直言那是假的（\\"It\\''s\u000a    fake\\"）。rumi感到丢脸且不悦，鼓起腮帮子表示不满。\u000a\u000a镜头切到温馨的披萨店。jinu和rumi相对而坐。一份热气腾腾的培根意式腊肠披萨上桌，rumi急不可耐地拿起一块，芝士拉出长长的丝。\u000a\u000arumi大口咀嚼披萨，表情原本很享受。突然，她的肤色瞬间变绿，眼睛翻白，变成了狰狞的僵尸。jinu吓得魂飞魄散，大喊着"她是僵尸"并推开椅子撞开大门逃走。\u000a\u000a看到jinu落荒而逃，rumi瞬间恢复正常肤色，对着镜头大笑并评价jinu"太蠢了"，随后继续美滋滋地吃披萨。\u000a\u000a身穿女仆装的服务员mira（红色双马尾）递上账单。rumi摸遍全身发现没带钱包，一脸尴尬。\u000a\u000amira提出如果有人订阅或评论就免单，rumi自嘲"他们才不会这么做"。最终，rumi被留在厨房疯狂揉面团，哭着哀求观众订阅以救她脱离苦海。'),'繁华的秋季街道上，rumi挽着jinu前行时突然停下，露出极度惊恐表情，右手食指发抖地指向地面上用枯叶堆成的、张着血盆大口的巨大mira肖像','异常物品','搞笑','落叶肖像吓rumi→jinu嘲笑→披萨店吃拉丝披萨→rumi变僵尸脸→jinu逃跑→mira递账单没钱→求订阅免单→厨房揉面惩罚','嘲笑者被反整','A嘲笑B胆小→B反过来整蛊A变僵尸→A落荒而逃→B赢了但面临新危机→打破第四面墙求观众帮忙','','','9495029','394552','','故事类','rumi','用僵尸变身反击jinu的嘲笑然后逃脱账单','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/105_僵尸整蛊披萨店揉面.mp4','/thumbs/105_ngxtJIrIW8w.jpg','');
INSERT INTO videos VALUES(106,'2026-03-29','冰封rumi化冰为金','','https://www.youtube.com/shorts/JPs90Zz5dSg','scripts/1039-视频拆解报告(4).md','2026-03-29 14:08:28','2026-03-29 19:45:07','Frozen rumi''s Summer Hustle: From ICE to GOLD! ❄️➡️💰','47','2026-03-22',unistr('在一间充满未来感的冷色调病房内，rumi\u000a    全身被厚重的冰晶覆盖，一动不动地躺在病床上。旁边的病床上，mira（红色双马尾）正趴在床边大声痛哭，双手掩面，情绪极度悲恸。mira\u000a    尝试着伸出颤抖的手去触摸 rumi\u000a    冰冷的身体，然而在指尖触碰的一瞬间，寒霜迅速顺着 mira\u000a    的手指蔓延，吓得她尖叫着缩回手。就在这时，rumi\u000a    猛地睁开双眼坐起身来，她没有理会身旁的\u000a    mira，而是神情恍惚、不敢置信地举起自己那双完全由晶莹蓝冰组成的双手，仔细端详。\u000a\u000a炎炎夏日，海滩阳光炽热。jinu（黑发偏分）和\u000a    zoye（黑发双丸子头）站在沙滩上大汗淋漓。jinu\u000a    不断用手扇风，抱怨天气炎热。此时，冰封状态的 rumi\u000a    优雅地走过沙滩，她所经之处不仅留下了霜痕，还自带强力降温场。jinu\u000a    和 zoye 瞬间感到一阵凉爽，惊讶地张大了嘴巴。\u000a\u000a在室内，zoye\u000a    兴冲冲地端出一碗冒着热气的美味拉面递给 rumi。rumi\u000a    略显迟疑地伸出冰状的手指想要接住碗。然而，就在指尖触碰到碗边的一瞬间，整碗拉面（包括蒸汽）瞬间被冻成了实心冰块。zoye\u000a    看着手中报废的拉面，满脸绝望和委屈。\u000a\u000arumi\u000a    来到一处平静的湖边码头。她坐在木质甲板边缘，轻轻将脚伸入湖水中。顷刻间，以她的脚为中心，冰层迅速向整个湖面蔓延。\u000a\u000a镜头一转，湖边立起了一个木牌，上面写着"ICE SKATING\u000a    \\$100/HR"（滑冰，每小时100美元）。原本炎热的季节里，这里成了避暑胜地。大批游客排队付钱。jinu\u000a    和 zoye 穿着溜冰鞋在冰封的湖面上快乐地滑行。\u000a\u000arumi\u000a    躺在遮阳伞下的沙滩椅上，戴着黑超墨镜。她身上堆满了厚厚的美钞，手里还抓着几叠，露出胜利者的微笑。旁边摆放着高级果汁。\u000a\u000a赚到巨款后，冰封的 rumi\u000a    拎着一个装满美金、印有"\\$"标志的金属手提箱，大步走进了一家顶级SPA会所。在一众服务人员的注目礼下，她步入了一个充满金色液体的特制浴缸中。随着金光闪烁，她身上的冰层开始碎裂、融化。\u000a\u000a冰晶破裂，rumi\u000a    恢复了人类的肤色和质感。她换上了时尚的运动装，和朋友们再次出现在海滩。\u000a\u000a在夕阳余晖下，rumi、jinu、zoye 和 mira\u000a    一起在沙滩上打排球。大家欢呼雀跃，庆祝 rumi 找回自我。'),'冷色调病房内rumi全身被厚重冰晶覆盖躺在床上，大哭的mira伸出颤抖的手触碰她，寒霜瞬间顺着手指蔓延，吓得mira尖叫缩回手','身体异常','热血, 感动','医院冰封苏醒→海滩自带降温→触碰拉面瞬间冻结→脚伸入湖水冻住整个湖面→开溜冰场收费→暴富→SPA金色浴缸破冰重生→朋友排球大团圆','诅咒能力递进','角色获得诅咒型能力→生活受阻→发现能力的商业价值→赚大钱→用钱解除诅咒→回归正常','','','5996644','71552','','故事类','rumi','利用冰封能力赚钱并最终解除诅咒','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/106_冰封rumi化冰为金.mp4','/thumbs/106_JPs90Zz5dSg.jpg','');
INSERT INTO videos VALUES(107,'2026-03-29','三扇小门老虎破墙','','https://www.youtube.com/shorts/P4IHgjICR28','scripts/1040-视频拆解报告(5).md','2026-03-29 14:08:28','2026-03-29 19:45:07','The door in the middle must not be opened #kpop #rumi','14','2026-03-19',unistr('一名蓝发女孩（Rumi）穿着白色蕾丝睡裙，蹲在浅蓝色墙壁前。墙上有三扇微型门：绿、白、紫。\u000a\u000aRumi伸出左手，带着好奇心打开了最左侧的绿色小门。门内突然伸出无数条枯槁、灰绿色的怪手抓向她的手臂。Rumi惊恐万分，大声尖叫，身体后缩，迅速关上房门。\u000a\u000a平复心情后，Rumi转向最右侧的紫色小门并将其打开。一只巨大的黑色蜘蛛瞬间爬出。Rumi再次尖叫，双手护在胸前，露出极度恐惧的表情，并快速将门合上。\u000a\u000aRumi犹豫片刻，最终决定尝试中间那扇白色小门。她轻轻拉开门把手，门内空无一物。她微微松了一口气，表情从紧张转为疑惑。\u000a\u000a就在Rumi认为中间这扇门最安全时，她站起身，白色小门上方（中间门的正上方）的墙壁突然发生剧烈爆炸。一只巨大的老虎破墙而出，伴随着震耳欲聋的咆哮。\u000a\u000aRumi被突如其来的巨兽吓得摔倒在地，面带惊愕，画面在老虎张开血盆大口的瞬间戛然而止。'),'穿白色蕾丝睡裙的Rumi蹲在有三扇微型门的墙边，好奇打开最左侧绿色小门，门内突然伸出无数条枯槁灰绿怪手抓向她的手臂','异常物品','惊悚','开绿门→怪手抓出→关门→开紫门→大蜘蛛爬出→关门→开白门→空的松口气→站起来→白门上方墙壁爆炸老虎破墙而出','递进挑战','左门危险→右门也危险→中间门安全→以为安全时→危险从意想不到的维度(上方)出现','','','10633119','46032','','故事类','rumi','找到安全的门','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/107_三扇小门老虎破墙.mp4','/thumbs/107_P4IHgjICR28.jpg','');
INSERT INTO videos VALUES(108,'2026-03-29','爆米花触发八臂英雄','','https://www.youtube.com/shorts/2TRpFB9Ahto','scripts/1041-视频拆解报告(6).md','2026-03-29 14:08:28','2026-03-29 19:45:07','#kpop #kpopdemonhunters #rumi','22','2026-03-22',unistr('视频开始于一个明亮的现代化厨房，rumi（紫色麻花辫女孩）正神情专注地操作平底锅炸爆米花，锅中冒出红色"100"字样的特效。jinu（黑发偏分男生）悄悄站在她身后，左手搭在她的右肩上，张大嘴巴露出极度夸张的惊恐表情，试图吓唬正在专注烹饪的\u000arumi。\u000a\u000a突然，许多颗爆米花精准地掉在了一只赤裸且青筋暴起的脚背上，画面极度写实。\u000a\u000ajinu 见状试图放声大叫，rumi\u000a迅速反应，右手死死捂住他的嘴，随后抬起左手食指放在唇边，对他做出"嘘"的手势，神情严厉且神秘。\u000a\u000a画面诡异地切换到沙发上三只戴着红领结的熊猫正在休息。随后 jinu\u000a的面部发生突变：整个面部充血变成深红色，双眼流下紫色的粘稠泪水，脸颊像气球一样鼓起，嘴唇紧闭。\u000a\u000a紧接着，jinu\u000a坐在轮椅上，身体两侧突然长出六只手臂（共八只手），手掌全部被染红。rumi\u000a推着他在各种极端场景中疾驰：\u000a\u000a1.  穿过夜间霓虹闪烁的街道，轮椅车轮摩擦出火花。\u000a\u000a2.  冲过摆满薯片的超市货架，薯片漫天飞舞。\u000a\u000a3.  掠过烟雾缭绕的夜市小吃摊。\u000a\u000a4.  在悬崖间的玻璃栈道上狂奔。\u000a\u000a5.  甚至在陡峭的山脊和云海之上穿梭。\u000a\u000a最后，jinu 从巨大的城市屏幕中飞跃而出，强大的冲击力导致他身后巨大的 LED\u000a广告牌发生崩塌。jinu\u000a双眼放光，全身缠绕紫色闪电，在无数手臂的助推下落向城市广场。画面最后，在摇摇欲坠的建筑残骸下，jinu\u000a在一名正吃着零食的小女孩面前重重着陆，激起巨大的尘埃云，他张开八只手臂呈绝对保护姿态，为女孩挡住了后方倒塌的广告牌。'),'明亮现代厨房里rumi神情专注地炸爆米花。jinu悄悄站在她身后，张大嘴巴露出极度夸张的惊恐表情试图进行惊吓恶作剧','异常行为','热血','炸爆米花→jinu吓唬→爆米花落脚上→rumi捂嘴嘘→jinu面部充血变异→长出八臂坐轮椅→rumi推轮椅穿越各场景→飞出屏幕→八臂挡住倒塌广告牌保护小女孩','隐忍爆发','搞笑触发→被迫憋住→能量在体内变异→极速穿越积蓄→最终在危机时刻释放保护弱者','','','9028862','45313','','故事类','jinu','在能量失控前找到释放方式保护他人','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/108_爆米花触发八臂英雄.mp4','/thumbs/108_2TRpFB9Ahto.jpg','');
INSERT INTO videos VALUES(109,'2026-03-29','咬披萨盘擦脏手','','https://www.youtube.com/shorts/8IWGLIFDgEw','scripts/1042-视频拆解报告(7).md','2026-03-29 14:09:47','2026-03-29 19:45:07','kind-hearted Rumi#funny #kpopdemonhunters #comedy #rumi','22','2026-03-07','','画面中心zoye正全神贯注啃咬着手中热狗，镜头前方突然伸出一只布满黑色淤泥污垢的左手，zoye抬头看向镜头，眼神透露出呆萌的惊讶','猎奇恶心, 贫穷与美好','搞笑, 感动','zoye喷番茄酱在脏手上→jinu喷可乐→rumi捧披萨出现→用牙咬住披萨盘腾出双手→用毛巾擦净→脏手拿走一角披萨','递进荒诞+正确解法','第一人用错误方式帮忙(喷酱)→第二人也用错误方式(喷可乐)→第三人用正确但荒诞的方式(咬盘擦手)解决问题','','','5443349','33204','','故事类','rumi','腾出双手帮脏手擦干净','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/109_咬披萨盘擦脏手.mp4','/thumbs/109_8IWGLIFDgEw.jpg','');
INSERT INTO videos VALUES(110,'2026-03-29','Mira栽赃rumi偷戒指','','https://www.youtube.com/shorts/G2ORYXAiOtY','scripts/1043-视频拆解报告(8).md','2026-03-29 14:09:47','2026-03-29 19:45:06','Part 2: Was The Spider Just The Beginning? #rumi','49','2026-02-23',unistr('\\\u000a    Mira（粉红色双马尾）坐在一张木质长桌前，对着镜子露出阴冷且自信的微笑。她一边自言自语说出核心逻辑："Jinu（黑发偏分男）比起真相更愿意相信眼泪"，一边熟练地用一块木质刮板在自己的左小臂上摩擦出鲜红的、类似划痕的血迹（实为特效化妆）。\u000a\u000a\\\u000a    Mira拿起手机拨打电话，眼神犀利，下达指令："20分钟内送达，署名写Rumi。"她这是在利用Rumi（紫色麻花辫）的名义策划一场栽赃。\u000a\u000a\\\u000a    Rumi如约来到Mira家。Mira笑容灿烂地迎接，嘴上说着："Rumi，我好想你，快进来坐。"两人在玄关处亲密拥抱，Mira趁着拥抱的视觉死角，动作极快且隐蔽地将一枚钻戒塞进了Rumi的外套口袋里，随后眼神中闪过一丝得逞的寒光。\u000a\u000a\\\u000a    客厅内，Rumi显得有些局促，她对Mira说："Mira，我只想知道真相。"\u000a    Mira此时正在倒水，眼神闪烁。突然门铃响起，一名穿着黑色连帽衫、戴手套的快递员递给Mira一个黑色礼盒。Mira假装惊讶："这是什么？你要给我送礼物吗？"\u000a\u000a\\\u000a    Mira打开盒子，突然发出一声尖叫，盒子里是一堆令人毛骨悚然的假蜘蛛。Mira立刻变脸，愤怒地质问Rumi："是你送的？你策划了这一切！"\u000a    Rumi满脸疑惑和震惊。\u000a\u000a\\\u000a    两人隔着桌子对峙。Mira手中拿着一杯水，她挑衅地看着Rumi，然后故意松手让水杯砸碎在地上。就在此时，Jinu听到动静冲入房间。\u000a\u000a\\\u000a    Mira迅速倒在碎玻璃和水渍旁，手捂着"受伤"的手臂，声泪俱下地对Jinu告状："我不能让你拿走一切，她偷了戒指，她无法接受你选择了我的事实！"\u000a\u000a\\\u000a    Rumi拼命辩解："我没有！"但在Mira的引导下，Rumi下意识摸向自己的外套口袋，竟然真的从口袋里掏出了一枚钻戒。Rumi整个人僵住，百口莫辩。\u000a\u000a\\\u000a    Jinu愤怒地挡在Mira身前，对Rumi咆哮："你不可理喻，你太危险了！离我们远点！"\u000a    Rumi掩面痛哭，绝望地跑出房间。\u000a\u000a\\\u000a    镜头切回Mira的特写。她转头看向镜头，脸上毫无泪痕，取而代之的是邪魅的笑容。她展示着手上的戒指，低语道："太简单了。别点赞，别分享，否则他就会发现我做了什么。"'),'Mira坐在桌前对镜子露出阴冷微笑，自语Jinu比起真相更愿意相信眼泪，边熟练用木质刮板在自己小臂摩擦出鲜红的划痕特效血迹','异常行为, 暗中算计','悬疑, 虐心','制造假伤痕→电话署名rumi订假蜘蛛→拥抱时偷塞戒指进口袋→快递送蜘蛛嫁祸→故意摔杯引jinu→假哭告状→rumi掏出戒指百口莫辩→jinu驱逐rumi→mira对镜头炫耀胜利','全链条栽赃陷害','伪造证据→栽植物证→制造事件→表演受害→引导发现物证→受害者百口莫辩→施害者对镜头炫耀','','','5280772','366876','','故事类','rumi','来找mira对质了解真相','mira','用全套栽赃计划让jinu赶走rumi','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/110_Mira栽赃rumi偷戒指.mp4','/thumbs/110_G2ORYXAiOtY.jpg','');
INSERT INTO videos VALUES(111,'2026-03-29','工地女总裁微服私访','','https://www.youtube.com/shorts/dQ2TKf1W940','scripts/1044-视频拆解报告(9).md','2026-03-29 14:09:47','2026-03-29 19:45:06','#kpop #funny #rumi #jinu #mira #zoey','26','2026-03-15','','奢华大堂里，满身灰尘穿脏旧夹克的rumi快步走向大理石吧台，极度干渴抓起杯子仰头猛灌，大量清水顺脖子流下滴落光洁地面','急迫, 贫穷与美好','爽文','脏兮兮rumi冲进大堂喝水→zoye温柔递水→mira经理怒斥赶人→jinu带随从冲来对rumi九十度鞠躬喊Boss→rumi摘安全帽揭示身份→开除mira→降级jinu→提拔zoye为总经理','身份伪装微服私访','高位者以底层身份出现→善人帮助→恶人欺辱→高位者揭示真身→恶人被惩罚→善人被奖励','','','8594398','69865','','故事类','rumi','以工人身份测试公司员工的品格','mira','赶走弄脏大堂的脏工人','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/111_工地女总裁微服私访.mp4','/thumbs/111_dQ2TKf1W940.jpg','');
INSERT INTO videos VALUES(112,'2026-03-29','三轮竞赛卡丁车铁球','','http://www.youtube.com/watch?v=ROyG_4ZkkDM','scripts/1045-视频拆解报告.md','2026-03-29 14:09:47','2026-03-29 19:45:06','Who will win the competition, Rumi or Jinu #rumi #kpop','43','2026-03-11',unistr('在波光粼粼的湖边，jinu（黑发偏分）自信地拍着一辆大型红色越野卡丁车，大声宣布："我要选这个！"他一脸胜券在握，坚信"大的总是更快的"。\u000a\u000a裁判mira（红色双马尾，身穿黑白条纹裁判服）举着红旗宣布第一轮规则：驾驶车辆穿过前方的石拱隧道。jinu此时已经在红车里露出了惊讶的神色，似乎察觉到了前方赛道的异样。\u000a\u000a镜头转到隧道，出口极其狭窄。rumi（紫色麻花辫）开着一辆玩具大小的黄色卡丁车轻松穿过。jinu试图冲过去时，巨大的红车直接侧翻卡在隧道口，jinu惊恐大叫："这到底是怎么回事！"\u000a\u000a画面切回赛道终点，mira举起rumi的手宣布她获胜。jinu垂头丧气地坐在地上。\u000a\u000amira拿出一个蓝水桶和一个红纸杯。jinu为了避免重蹈覆辙，这次选择了极小的红纸杯，咬牙切齿地说："这次我肯定赢。"\u000a\u000a规则公布------谁先排干水池里的水谁赢。jinu看着面前巨大的水池\u000a    and 手里的纸杯，直接崩溃："你在逗我吗？"\u000a\u000arumi拎着大蓝桶疯狂舀水，直呼"太简单了"。jinu蹲在水池边用纸杯一点点舀水，绝望感叹："照这个速度什么时候能弄完？"\u000a\u000a来到码头，jinu看到三个巨大的绿色登山包，心想不能再输，直接左右开弓背起两个重包："这两个我全要了！"\u000a\u000amira宣布谁先游到对岸谁赢。jinu背着两个包跳入泳池，结果包里装满了沉重的铁球，他瞬间沉底，只能在水下透过气泡发出微弱的呼救："等一下......太重了......"\u000a\u000arumi在岸上举起金色奖杯欢呼，邀请观众点赞订阅。jinu则在岸边拆开背包，发现里面是一堆黑色实心铁球，崩溃质问："你是认真的吗？"'),'波光粼粼的湖边，jinu自信拍着一辆大型红色卡丁车大声宣布我要选这个！坚信大的更快，身穿裁判服的mira随即举红旗宣布第一轮规则','竞赛与挑战, 致命傲慢','搞笑','选大卡丁车过不了窄隧道→第二轮学聪明选小纸杯但要排干泳池→第三轮两个包都背跳水→包里全是铁球直接沉底','策略进化全败循环','选大失败→学聪明选小→又失败→索性全要→包里装铁球差点溺水→越努力越惨','','','5033076','70531','','故事类','rumi','赢得三轮竞赛','jinu','通过策略选择赢过rumi但全败','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/112_三轮竞赛卡丁车铁球.mp4','/thumbs/112_ROyG_4ZkkDM.jpg','');
INSERT INTO videos VALUES(113,'2026-03-29','紫色拖把头寻主记','','https://www.youtube.com/shorts/aKxKa4_pW4c','scripts/1046-视频拆解报告：OMG Mira.md','2026-03-29 14:09:47','2026-03-29 19:45:06','OMG Mira 🤣#cute #kpopfunny #korea #funny #kpop #rumi','52','2026-02-26',unistr('mira（粉色双马尾）在沙滩边弯腰捡起一捆长长的、带有编织质感的紫色假发。她一脸嫌弃又疑惑地对着镜头问："喂，这是谁的？"\u000a\u000amira挺直身子，推测道："肯定是rumi的，看，她的长辫子不见了。"她张大嘴巴露出夸张的惊讶表情。\u000a\u000amira拿着紫色头发冲到正在遮阳伞下看书的rumi面前，气势汹汹地喊道："rumi别装了，这就是你的对吧？"rumi疑惑地抬起头，挥手驱赶mira："mira我在看书呢，走开。我的头发就在这儿。"rumi指了指自己完好无损的紫色长辫子，一脸无语。\u000a\u000amira尴尬地走在椰林小道上，对着紫色假发自言自语："我知道了，这是一个紫色的水母。它干透了，需要水。"\u000a\u000amira来到海边，蹲下身子虔诚地将紫色假发放入浅滩水中，温柔地挥手告别："回家吧小家伙，自由去吧。"\u000a\u000a突然，一个赤裸上身、长着蓝色鱼尾的肌肉男abby从海里冒出来，愤怒地把紫色头发扔回mira脸上，大喊："嘿！大海里不准扔垃圾！"mira被砸得满脸是水，大惊失色。\u000a\u000amira意识到这确实不是水母。她看到坐在海边礁石上、头套纸袋静坐的mystery。她躲在树后窃窃私语："纸袋？他肯定是在掩盖秃头。是mystery！"\u000a\u000amira冲过去，趁mystery不备，将紫色假发按在他的纸袋顶端，兴奋地喊道："嘿，别害羞，我找到你的头发了！"\u000a\u000amystery愤怒地扯掉纸袋，露出一头飘逸的紫色短发，大吼："我在冥想！这个袋子是帮我入定的！"mira吓得表情管理失控。\u000a\u000amira垂头丧气地坐在长椅上，手里攥着紫色假发："我放弃了，也许这是个外星人。"\u000a\u000ajinu扛着一根光秃秃的木棍跑过来，兴奋地喊道："嘿，你找到了！我的宝贝发团！"\u000a\u000ajinu从mira手中接过紫色假发，把它按在木棍顶端，并用胶带熟练地缠绕几圈。他如获至宝地亲吻着这个"拖把头"："我终于找到你了。"\u000a\u000ajinu欢快地拿着这个刚修好的紫色拖把在露台上跳舞拖地，背景响起了愉快的旋律。mira对着镜头如释重负地微笑："好吧，它终于回到它该去的地方了。"'),'mira在沙滩边弯腰捡起一捆长长的紫色假发，一脸嫌弃又疑惑对镜头问喂，这是谁的？肯定是rumi的，她的长辫子不见了','异常物品, 提出疑问','搞笑','捡到紫色发团→以为是rumi的被否认→以为是水母放生→人鱼abby扔回来→以为mystery秃头强行植发→mystery有头发→放弃→jinu跑来认领→原来是拖把头→jinu用它拖地跳舞','连续误判身份揭晓','捡到神秘物品→误判归属1被否认→误判物种被惩罚→误判归属2被否认→真正主人出现→揭示荒诞真相(拖把头)','','','8977561','68323','','故事类','mira','找到紫色发团的主人','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/113_紫色拖把头寻主记.mp4','/thumbs/113_aKxKa4_pW4c.jpg','');
INSERT INTO videos VALUES(114,'2026-03-29','婚纱店女总裁微服私访','','https://www.youtube.com/shorts/MfbBlzbbEMA','scripts/1047-视频拆解报告：Wusdom Lab 短剧.md','2026-03-29 18:34:47','2026-03-29 19:45:06','This ending is so satisfying, Do you like it? #kpop','35','2026-03-16',unistr('rumi（紫色麻花辫）穿着破旧、打满补丁的深灰色工装外套，神色极其慌张且口渴难耐地推开豪华婚纱店的玻璃门。她冲进店内，大声喘息着乞求："Water\u000a    please, I need some water."（水，请给我点水）。\u000a\u000a正在店内的店员mira（红色双马尾）看到后，没有丝毫嫌弃。她穿着白衬衫黑背心，立刻拿出一瓶矿泉水快步上前。mira温柔地拍着rumi的肩膀安抚道："Whoa,\u000a    take it easy. Drink this. Are you okay\u000a    ma\\''am?"（喔，慢点喝。喝这个。女士你还好吗？）。rumi接过水，疯狂吞咽。\u000a\u000a就在这时，一双黑色高跟鞋踏着凌厉的步伐走近。经理zoye（黑发双丸子头）冷脸出现，猛地挥手将rumi手中的水瓶打飞。水花在空中溅射，zoye愤怒地指着大门对mira吼道："Mira,\u000a    get this person out of my store\u000a    now!"（mira，现在就把这个人赶出我的店！）。\u000a\u000amira试图辩解："Manager, she\\''s just\u000a    thirsty."（经理，她只是渴了）。zoye凶狠地打断："Shut up! We don\\''t\u000a    serve people like her\u000a    here."（闭嘴！我们这里不接待她这种人）。随后，zoye双臂交叉抱胸，极度轻蔑地对rumi说："Listen,\u000a    you couldn\\''t afford a single thread in this shop if you worked ten\u000a    lifetimes. Get\u000a    out!"（听着，你打十辈子工也买不起这店里的一根线。滚出去！）。\u000a\u000arumi低下的头缓缓抬起，眼神变得冰冷而锐利。她突然伸手撕开外层的破旧工装，露出了里面闪耀着金属光泽的金色西装套装。rumi气场全开，冷冷说道："Your\u000a    arrogance is disgusting."（你的傲慢真令人恶心）。\u000a\u000azoye看到金色西装后瞬间认出了对方身份，吓得全身颤抖，语无伦次地求饶："Boss,\u000a    I\\... I didn\\''t know, I was\u000a    just\\..."（老板，我\\...我不知道，我只是\\...）。rumi果断打断她："Save\u000a    it. You\\''re right, some people don\\''t belong here, and that\\''s\u000a    you."（省省吧。你说得对，有些人确实不属于这里，那就是你）。rumi宣布："You\\''re\u000a    fired! Pack your bags and get out!"（你被解雇了！收拾东西滚！）。\u000a\u000arumi转头看向惊讶的mira，温柔地笑道："Mira, kindness is\u000a    the true luxury. Congratulations, you\\''re the new general\u000a    manager."（mira，善良才是真正的奢侈。恭喜你，你现在是新任总经理了）。mira惊喜万分地握住双手。'),'穿破旧补丁外套的rumi神色惊慌且极度口渴，推开豪华婚纱店门大声喘息乞求Water please, I need some water！','急迫, 贫穷与美好','爽文','rumi脏兮兮闯入婚纱店求水→mira善良递水→zoye经理打飞水瓶怒斥→rumi撕开工装露出金色西装→揭示老板身份→开除zoye→提拔mira为总经理','身份伪装微服私访','高位者以底层身份出现→善人帮助→恶人欺辱→高位者揭示真身→恶人被惩罚→善人被奖励','','','5190095','132305','','故事类','rumi','以乞丐身份测试婚纱店员工品格','zoye','赶走弄脏店铺的穷人','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/114_婚纱店女总裁微服私访.mp4','/thumbs/114_MfbBlzbbEMA.jpg','');
INSERT INTO videos VALUES(115,'2026-03-29','嗜辣者偷吃辣椒循环','','https://www.youtube.com/shorts/1G0WKAuplr8','scripts/1048-视频拆解报告：二毛的辣椒与鸡腿(1).md','2026-03-29 18:34:47','2026-03-29 19:45:05','Er Mao just wants to eat chili🌶️ #funny #comedy','27','2026-02-07',unistr('视频发生在一段充满乡村气息的屋顶露台上，讲述了一个关于"诱惑、反转与宿命循环"的荒诞故事：\u000a\u000a1.  第一幕：自虐的嗜辣者 (00:00-00:03)\u000a    身穿灰色中式棉袄的男子（以下称"灰衣男子"）双手捧着一大捆鲜红的辣椒，张开大口猛烈啃咬。他的表情狰狞，每咬一口都伴随着剧烈的咀嚼声，展现出一种近乎自虐的吃播表演感。\u000a\u000a2.  第二幕：被发现的恐慌 (00:03-00:05)\u000a    灰衣男子余光瞥见有人走来，神色瞬间变得极度惊恐，吓得赶快停下动作并放下手中的辣椒。此时，一名身穿蓝色棉袄的壮汉（以下称"蓝衣壮汉"）出现在左侧，一脸嫌弃且严肃地将桌上那盘红辣椒强行撤走。\u000a\u000a3.  第三幕：厌恶的奖赏 (00:05-00:08)\u000a    蓝衣壮汉换上一脸"强制纠正"的表情，利落地在桌上拍下一只金黄的鸡腿。灰衣男子看着鸡腿满脸嫌弃，他作为一个只爱辣椒的极端嗜辣者，对这种"奖赏"毫无兴趣，他高举鸡腿对着镜头展示时，眼神中透着无奈与排斥，脑子里只想将其扔掉。\u000a\u000a4.  第四幕：力量的审视 (00:08-00:10)\u000a    画面切到露台边缘，蓝衣壮汉脱掉了蓝色棉袄，竟穿着一套夸张的"棕色肌肉紧身衣"，他摆出拳击手的姿势，对着镜头挥出一记重拳，眼神充满压迫感，仿佛在警告灰衣男子必须接受这个"健康"的奖赏。\u000a\u000a5.  第五幕：寻找机会的丢弃 (00:10-00:16)\u000a    灰衣男子拿着鸡腿，脸上的假笑逐渐消失，转而露出痛苦与困扰的表情（对肉食的生理抗拒）。就在他纠结如何处理这只他不爱吃的鸡腿时，一只黑猫窜出，灰衣男子如获至福，顺势将鸡腿递给黑猫，完成了他"处理掉垃圾"的目标。\u000a\u000a6.  第六幕：宿命的归宿 (00:16-00:27)\u000a    灰衣男子守着空荡荡的盘子，最后只剩下一根干枯的骨头。虽然摆脱了鸡腿，但他那颗想吃辣椒的心依然在骚动。就在这时，蓝衣壮汉端着那盘最初的红辣椒再次登场，灰衣男子绝望地大喊一声"Okay"，再次抓起一把辣椒塞进嘴里，回到了他最爱的自虐循环中。'),'乡村屋顶露台上，一名灰衣男子双手捧着一大捆鲜红辣椒，张开大口表情狰狞猛烈啃咬，展现出近乎自虐的吃播表演感','异常行为','搞笑','偷吃辣椒→被壮汉发现收走→强塞鸡腿→展示肌肉威胁→偷偷喂猫丢掉鸡腿→壮汉又送辣椒回来→继续吃辣椒循环','极端执念与治愈反转','角色偷做被禁止的事→被强者阻止并强塞替代品→想办法处理掉替代品→最终又回到偷做禁忌的循环','','','123824600','978499','','故事类','灰衣男子','偷吃辣椒逃避壮汉监管','蓝衣壮汉','强制灰衣男子吃鸡腿不吃辣椒','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/115_嗜辣者偷吃辣椒循环.mp4','/thumbs/115_1G0WKAuplr8.jpg','');
INSERT INTO videos VALUES(116,'2026-03-29','魔力红盆棒棒糖变钱','','https://www.youtube.com/shorts/B8uo-20iEUA','scripts/1050-视频拆解报告：魔力红盆与欲望的轮回.md','2026-03-29 18:34:47','2026-03-29 19:45:05','rumi is so kind🥰 #kpopdemonhunters #kpop #rumi #mira','46','2026-02-27',unistr('1.  00:00 -\u000a    00:02：在斑驳的灰色石墙下，rumi（紫色麻花辫）微笑着对一脸愁苦、甚至在抽泣的mira（红色双马尾）说："Look\u000a    I found a candy for you." 她递出一支彩虹纹理的圆盘棒棒糖。\u000a\u000a2.  00:02 -\u000a    00:04：mira由于心情极差，表现出明显的烦躁。面对递来的棒棒糖，她猛地挥手一推，试图拒绝。然而，这一推由于力道偏差，棒棒糖脱手飞出，精准地划过一道抛物线，落入了两人面前地上的一个破旧红陶花盆中。\u000a\u000a3.  00:04 -\u000a    00:06：沉寂一秒后，红陶盆突然爆发出清脆的响声，盆底瞬间涌现出大量的彩虹棒棒糖，填满了整个容器。mira和rumi同时僵住，双眼圆睁，嘴巴呈O型，mira惊叫道："Oh\u000a    my god!"\u000a\u000a4.  00:06 -\u000a    00:08：mira的悲伤瞬间被狂喜和贪婪取代。她一把推开身边的rumi，抢过红陶盆抱在怀里，急切地喊道："Wait\u000a    let me see that bowl! Let\\''s try this!"\u000a    她颤抖着手从怀里掏出一张20美元的纸币。\u000a\u000a5.  00:08 -\u000a    00:10：她将纸币丢入盆中，纸币在触碰盆底的刹那如同细胞分裂般疯狂倍增，几秒钟内，一叠叠百元大钞溢出了盆边缘。\u000a\u000a6.  00:10 -\u000a    00:13：rumi惊讶地想上前查看，mira却面露凶光，用肩膀狠狠撞开rumi，语气决绝："Get\u000a    away from me! This is all mine now!"\u000a    说罢抱着满盆美钞狂奔离去。rumi瘫坐在地，伸出尔康手悲鸣："No!\u000a    Wait! Please don\\''t leave me!"\u000a\u000a7.  00:14 -\u000a    00:21：场景跃迁至豪华公寓。mira已换上昂贵的白裙。jinu（黑发中分男）正谄媚地在后方为她按摩双肩，称呼道："Here\u000a    you go my queen. Is it good?"\u000a    mira神情冷傲，向jinu展示魔力。她轻蔑地将一张美钞丢入盆中，钞票再次翻倍，jinu贪婪地喊道："It\\...\u000a    it multiplied!"\u000a\u000a8.  00:22 -\u000a    00:29：户外公园。mira挽着jinu，高傲地走在石径上。她看到了蹲在路边、再次陷入饥饿困境的rumi。mira露出一脸恶毒的嘲笑，咬了一口手中的鸡腿后，将其丢向rumi，羞辱道："Here\u000a    doggy." rumi卑微地捡起鸡肉，满眼委屈。\u000a\u000a9.  00:30 -\u000a    00:35：深夜室内。mira在卧室内熟睡。jinu鬼鬼祟祟地潜入，眼中闪烁着背叛的冷光，低声念叨："All\u000a    this money is mine." 他伸手抓向床边的魔力盆。\u000a\u000a10. 00:36 -\u000a    00:40：mira猛然惊醒，跳下床与jinu疯狂厮打抢夺。她怒吼："What\u000a    are you doing? Let go! This is my money!"\u000a    两人在拉扯中失去了平衡，红陶盆重重摔在木地板上，当场碎裂。\u000a\u000a11. 00:41 -\u000a    00:46：就在两人因失去聚宝盆而绝望时，rumi穿着干净利落的衣服出现在房门口，手中的手机屏幕显示正在拨打911。她冷冷地说："I\\''ve\u000a    already called the police. It\\''s over for you."\u000a    然后她温柔地抱住崩溃大哭的mira，安慰道："It\\''s okay now."'),'灰色石墙下rumi微笑着对抽泣的mira递出棒棒糖说Look I found a candy for you。mira极度烦躁猛地挥手一推试图拒绝','贫穷与美好, 视觉目标绑架','搞笑, 感动','递棒棒糖→被推开掉入红盆→盆中涌出大量棒棒糖→mira贪心投入20美元→钞票疯狂翻倍→mira抢盆抛弃rumi→jinu谄媚讨好→贪婪升级','魔力容器欲望吞噬','偶然发现魔力道具→小物品复制验证→投入更大价值→贪婪吞噬善良→抛弃朋友独占→欲望失控','','','9464420','102361','','故事类','rumi','用棒棒糖安慰哭泣的mira','mira','独占魔力红盆疯狂复制金钱','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/116_魔力红盆棒棒糖变钱.mp4','/thumbs/116_B8uo-20iEUA.jpg','');
INSERT INTO videos VALUES(117,'2026-03-29','小丑神医黑洞取子弹','','https://www.youtube.com/shorts/3uoThTmD_Vs','scripts/1051-视频拆解：Jinu is Clown Miracle Doctor.md','2026-03-29 18:34:47','2026-03-29 19:45:05','Jinu is Clown Miracle Doctor？ #kpopshorts #funny','28','2026-03-16',unistr('手术室内，jinu（黑发偏分）一边哼着歌一边抛玩一颗粉色糖果。他试图张嘴接住糖果，却发生失误，糖果顺着脸颊滑落。\u000a\u000a糖果不偏不倚掉入了病患\u000a    romance（粉发黄色冷帽）腹部覆盖的手术单黑洞中。jinu\u000a    的表情由嬉笑瞬间转为凝重，他低头盯着那个深邃的空洞。\u000a\u000a为了找回糖果，jinu\u000a    戴着黑手套把手伸进黑洞。结果他掏出来的竟是一颗底部滴着黑色粘稠液体的金色子弹。jinu\u000a    惊恐地瞪大双眼，随后神色鬼祟地迅速扭头看向四周，确认没人发现这个"危险证据"。\u000a\u000a他再次将手伸入黑洞深处。这一次，他终于成功找回了那颗粉色糖果。\u000a\u000ajinu\u000a    发现糖果被污染了，于是用长镊子夹着它放入装满水的玻璃杯中疯狂搅动清洗。水瞬间变黑并产生沸腾感。洗净后，他毫不犹豫地将糖果塞进嘴里嚼碎，露出一种吸取了能量的得意神情。\u000a\u000a蓝帘拉开，rumi、mira 和 mystery\u000a    护士团队拿着专业的手术镊子准备介入。jinu\u000a    见状立刻摇头制止，表示这些工具毫无用处。\u000a\u000a在众人注视下，jinu\u000a    猛地将整只右手及小臂全部没入黑洞。他面部肌肉极度紧绷，身体剧烈颤抖，仿佛在从另一个次元拖拽重物。\u000a\u000a随着一声沉重的音效，jinu\u000a    竟从黑洞中徒手拔出一枚巨大的、如人头大小的纯金大子弹（此处对应用户提到的"超大子弹/紫檀"感道具）。\u000a\u000a画面一转，病患 romance\u000a    瞬间满血复活。他帅气地坐起，对着镜头竖起大拇指，笑容灿烂。jinu\u000a    则在背景中露出深功名藏的自信微笑。'),'手术室内医生jinu边哼歌边抛起粉色糖果试图用嘴接，却失误滑落，糖果不偏不倚掉入病患romance腹部的手术单黑洞中，jinu笑容瞬间凝固','突发意外, 身体异常, 视觉目标绑架','热血','抛糖果失误掉入黑洞→伸手捞出滴黑液的金色小子弹→鬼祟偷看确认无人→再次捞出糖果→清洗后吃掉→拒绝护士团队的常规器械→徒手猛扎黑洞→拔出巨大金色子弹→病人满血复活','体内异次元掏取','搞笑意外触发→发现异常病灶→常规医疗无效→天才以非常规极端方式(徒手)解决→奇迹康复','','','70233589','399650','','故事类','jinu','用非常规方式取出黑洞中的异物治愈病人','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/117_小丑神医黑洞取子弹.mp4','/thumbs/117_3uoThTmD_Vs.jpg','');
INSERT INTO videos VALUES(118,'2026-03-29','万圣节丧尸追逐噩梦','','http://www.youtube.com/watch?v=lsTPUs9CrjY','scripts/1052-视频拆解：Rumi怎么了？.md','2026-03-29 18:34:47','2026-03-29 19:45:05','What happened to Rumi? #kpop #demonhunters #funny','19','2026-02-25',unistr('Rumi（紫色麻花辫）独自站在阳光明媚的海滩边，手中捧着刚捡到的贝壳。突然，一艘白色小船冲向岸边。Rumi惊恐地转头，手中的贝壳散落一地。\u000a\u000aJinu（黑发丧尸妆）从小船上腾空跃起，大喊"We found\u000a    you!"。随后，Mystery（银发）、Mira（红色双马尾）和Zoye（黑发丸子头）也以丧尸姿态从船上跳下，对Rumi展开疯狂追逐。Rumi在沙滩上拼命奔跑，神色慌张。\u000a\u000a场景切换至丛林，Rumi躲在一棵棕榈树后喘息，眼神充满恐惧。Mystery突然从树后探出头，阴森地低语"Peek-a-boo"。Rumi尖叫着逃走。\u000a\u000aRumi躲入室内，企图用白布遮盖自己。Zoye猛地掀开白布，怪笑着说"Come\u000a    out and play"。Rumi被吓到几乎瘫软。\u000a\u000aRumi躲进浴室，背靠着浴缸瑟瑟发抖，低头啜泣。浴室门被猛地推开，Jinu、Mira和Mystery挤在门口，张开双臂大喊"Gotcha!"。Rumi发出最后的尖叫。\u000a\u000a画面转到温馨的卧室。Rumi猛地在床上坐起，剧烈喘息，原来刚才的一切都是噩梦。\u000a\u000a就在Rumi庆幸是梦时，卧室门打开。Mystery、Mira、Jinu和Zoye穿着同样的服装，但神情友善，手里提着南瓜糖果桶。他们齐声说"Trick\u000a    or treat, Happy\u000a    Halloween!"。Rumi愣在原地，情绪从恐惧转为无奈的惊讶。'),'Rumi在海滩手捧刚捡到的贝壳，突然一艘白色小船冲向岸边，Rumi惊恐转头贝壳散落，Jinu以恐怖丧尸妆跃下大喊We found you！','经典桥段, 生命威胁','惊悚, 搞笑','海滩被丧尸从船上追→沙滩奔跑→丛林躲藏被发现→室内白布遮盖被掀开→浴室角落被围堵→猛然惊醒是噩梦→朋友穿同样服装提南瓜桶说Trick or Treat','噩梦追逐反转','恐怖追逐不断升级→被围堵绝望→猛然醒来是梦→现实中追逐者以友好身份出现→恐怖变温馨','','','6065498','25861','','故事类','rumi','逃脱丧尸追逐','jinu','带领丧尸团队追逐rumi','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/118_万圣节丧尸追逐噩梦.mp4','/thumbs/118_lsTPUs9CrjY.jpg','');
INSERT INTO videos VALUES(119,'2026-03-29','憋笑到南极分贝挑战','','http://www.youtube.com/watch?v=pShazWO3nQE','scripts/1053-视频拆解：Where did Jinu go_.md','2026-03-29 18:36:03','2026-03-29 19:45:04','Where did Jinu go? #funny #rumi #kpop #jinu #mira','35','2026-03-19',unistr('1.  00:00 -\u000a    00:01：Mira（红色双马尾）满脸笑容，轻盈地走进客厅，双手托着一大盘堆满芝士和牛油果酱的玉米片，对Jinu大声喊道："Jinu，快来吃玉米片！"（Jinu\u000a    come get some nachos）。\u000a\u000a2.  00:01 -\u000a    00:02：伴随一声滑稽的音效，Mira在行走中意外摔倒，脸部直接重重地扣进了手中的玉米片盘子里。画面闪切，Mira瞬间全身被绿色的牛油果酱和碎玉米片覆盖，面部表情极其震惊和僵硬。\u000a\u000a3.  00:02 -\u000a    00:04：画面切到沙发。Mira急切地用右手死死捂住Jinu（黑发男生）的嘴，瞪大双眼示意他安静。Jinu神情极度惊恐，双眼圆睁。Mira压低声音警告："别出声！她正在准备司法考试！"（Don\\''t\u000a    make a sound. She\\''s studying for the bar exam.）。\u000a\u000a4.  00:04 -\u000a    00:06：镜头扫向书桌。Rumi（紫色麻花辫）正埋头苦读，面前堆满了厚重的法学书籍。桌前贴着一个巨大的手绘警告牌，上面画着红色的骷髅，写着："发出声音，你就死定了"（MAKE\u000a    A SOUND AND YOU WILL DIE），气氛极其压抑。\u000a\u000a5.  00:06 -\u000a    00:09：回到沙发。Jinu因为过度紧张开始无法抑制地发抖，脸色憋得通红。他终于无法忍受，挣脱Mira的手，抓起手机狂奔出门。\u000a\u000a6.  00:09 -\u000a    00:11：Jinu站在别墅外的车道上，高举着一块硬纸板，上面写着："我需要笑。开车。去远方。"（I\u000a    NEED TO LAUGH. DRIVE. FAR.）。\u000a\u000a7.  00:11 -\u000a    00:13：一辆红色的奔驰G级（G-Wagon）越野车疾驰而至。驾车的是Romance（粉发男生），他戴着黄色冷帽，酷酷地吐出一个字："上车。"（Get\u000a    in.）。\u000a\u000a红色的越野车在南极的冰原上疾驰，扬起阵阵雪雾。\u000a\u000a9.  00:16 -\u000a    00:18：Jinu和Romance站在雪地上，身边围着一群帝企鹅。Jinu被冻得浑身发抖，牙齿打颤："我感觉不到我的脚趾了......"（I\u000a    can\\''t feel my toes）。Zoye一脸淡定："我知道个地方。"（I know a\u000a    place.）。\u000a\u000a10. 00:18 -\u000a    00:20：Zoye（黑发，双丸子头）穿着橙色的专业极地探险服出现，引导他们望向远方。\u000a\u000a一艘名为"NANUK\u000a    TIKKUR"的红色巨型科学考察船停泊在冰面边缘，背景是初升的极地暖阳。\u000a\u000a12. 00:22 -\u000a    00:25：画面切回现代化的客厅。Rumi已经学习完，正在优雅地吃着披萨，她疑惑地问Mira："Jinu去哪了？我一整天都没见到他。"\u000a\u000a13. 00:25 -\u000a    00:30：Mira正坐在沙发上偷笑，她指了指面前巨大的液晶电视。电视画面中，Jinu正站在名为"DECIBEL\u000a    CHALLENGE"（分贝挑战）的综艺舞台中央。\u000a\u000a14. 00:30 -\u000a    00:32：Jinu在舞台上张开双臂，爆发出毁天灭地的尖叫。画面中出现了巨大的震荡波纹，舞台背景发生了爆炸，彩带横飞。\u000a\u000a15. 00:32 -\u000a    00:33：舞台下方的观众（全是长得一模一样的小孩）被巨大的声浪直接吹飞，场面极其震撼。\u000a\u000a16. 00:33 -\u000a    00:35：Mira转过头，带着得意的笑容说："他现在大概在回来的飞机上了。"。窗外夜空中，一架大型客机降落，身后拖着由发光烟雾构成的巨大"HAHAHAHA"字符，视频结束。'),'Mira满脸笑容端着一大盘芝士和牛油果玉米片走进客厅喊Jinu come get some nachos！突然意外脸朝下摔倒重重扣进盘子里','突发意外, 滑稽疼痛','搞笑','mira脸扣玉米片→捂住jinu嘴不让笑(rumi在备考)→jinu憋不住逃出门→举牌搭车→开G级去南极→被冻僵→登上科考船→rumi学完问jinu去哪了→电视上jinu参加分贝挑战爆发尖叫→飞机拉出HAHAHAHA','隐忍爆发','因强力压制不许笑→压抑到极限→逃往地球最远处→找到释放场所→积攒的情绪以毁天灭地的方式爆发','','','9888858','91749','','故事类','jinu','找到一个可以安全大笑的地方','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/119_憋笑到南极分贝挑战.mp4','/thumbs/119_pShazWO3nQE.jpg','');
INSERT INTO videos VALUES(120,'2026-03-29','魔法火车许愿三连','','https://www.youtube.com/shorts/t4X68or53r0','scripts/1054-视频深度影视拆解报告.md','2026-03-29 18:36:03','2026-03-29 19:45:04','Meant to Be✨❤️ #kpop #abby #jinu #mira #rumi #zoey','53','2026-03-13',unistr('视频描述了一列拥有"愿望成真"魔力的蒸汽朋克风格火车。\u000a\u000a1.  开端（00:00 -\u000a    00:06）：jinu（蓝羽绒服）吃力地拉开带有巨大齿轮的沉重金属车门，伴随着漫天飞雪和冷气。他快步跑入车厢，一边哈气一边对rumi（紫色麻花辫）和romance（粉发黄色冷帽）大喊："嘿，rumi，abby（此处指romance），我得暖和下，外面太冷了！"他满脸冻得通红，身体颤抖。\u000a\u000ajinu\u000a    走到车厢中央的大型黄铜操纵杆前，大喊："我想这能停下！"他猛力拉下操纵杆。瞬间，金光闪烁，沉重的金属车门率先向两侧滑开，门外原本的暴风雪景象瞬间消失，取而代之的是阳光明媚的碧海沙滩。紧接着，jinu\u000a    身上的蓝羽绒服瞬间变换成了亮蓝底色黄色扶桑花的夏威夷衬衫，脖子挂着粉色火烈鸟泳圈，脚穿凉鞋。他兴奋地大喊："Aloha\u000a    baby！我要离开这儿！我爱夏天！"随即纵身跳入沙滩，激起巨大浪花。\u000a\u000a车厢内的 rumi 和 romance\u000a    惊呆了。rumi 兴奋地冲向操纵杆，推开 romance\u000a    大喊："纯魔法！我也要试试！我要变有钱！给我所有的钱！"她疯狂摇动拉杆。画面一转，车门外变成了璀璨的钻石水晶宫殿。rumi\u000a    瞬间换上粉金色华丽公主裙，漫天美元飘落。她在金钱雨中旋转，zoye\u000a    为她戴上皇冠。她尖叫着："这火车太神奇了！我生命中最好的一天！"\u000a\u000aromance\u000a    走到拉杆前，整理了一下黄色冷帽，满脸期待："好吧，火车，给我带来我的梦中情人！我准备好真爱了！"他拉下拉杆。车门打开，mira（红色双马尾）穿着米色羽绒服出现。两人对视一秒后同时发出尖叫："啊------！"romance\u000a    愤怒指责："你不是我的梦中情人！"mira\u000a    满脸厌恶："呕！我要的是亿万富翁，不是你！"\u000a\u000a5.  结局（00:44 -\u000a    00:53）：两人互相嫌弃地背对背。然而画面突变，两人瞬间出现在阳光明媚的户外婚礼拱门下，身着白色西装和婚纱。romance\u000a    牵着 mira\u000a    的手，无奈地笑："我想我们只能接受命运了，哈？你愿意嫁给我吗？"mira\u000a    害羞点头："我愿意！"周围 jinu、rumi、zoye\u000a    等人欢呼并喷洒香槟，全剧在甜蜜的氛围中结束。'),'jinu吃力拉开带有巨大齿轮的沉重金属车门，伴随漫天飞雪冻得浑身发抖跑入车厢，对rumi大喊外面太冷了我得暖和下！','异常场景','搞笑, 感动','jinu拉操纵杆→暴风雪变海滩换夏威夷衫→rumi许愿变有钱→水晶宫殿金钱雨公主裙→romance许愿梦中情人→mira出现互相嫌弃→强制婚礼拱门结婚','魔法许愿反转成真','发现魔法机制→第一愿物质满足→第二愿财富满足→第三愿感情→结果不如预期→但命运强制成真→嫌弃变甜蜜','','','5412371','67228','','故事类','jinu','在暴风雪中寻找温暖','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/120_魔法火车许愿三连.mp4','/thumbs/120_t4X68or53r0.jpg','');
INSERT INTO videos VALUES(121,'2026-03-29','假蜘蛛英雄骗局揭穿','','https://www.youtube.com/shorts/Kv_RIjKdP0I','scripts/1055-视频深度拆解报告(1).md','2026-03-29 18:36:03','2026-03-29 19:45:04','FAKE HERO EXPOSED!! 💨 #kpop #kpopdemonhunters #funny','25','2026-03-17','','客厅里rumi含情脉脉看着jinu，abby突然在旁边单膝跪地热切盯着rumi，rumi极度不耐烦挥手示意他离开说Abby, give us a break','亲密互动, 冲突对峙','搞笑','甜蜜对视→abby骚扰→地上出现蜘蛛→jinu吓到后空翻躲柜顶→abby淡定捏起蜘蛛当英雄→rumi踢走胆小jinu→jinu偷看发现abby裤兜有假蜘蛛包→冲进去扯掉帽子露出光头→踢屁股放绿色臭屁','自编自演英雄被揭穿','角色A自导自演危机→角色A英雄救美→受害者被骗→真相被第三方偶然发现→骗子被公开羞辱双重暴露(秃头+放屁)','','','5458506','39697','','故事类','jinu','揭穿abby自导自演的假蜘蛛骗局','abby','用假蜘蛛自编自演英雄救美骗取rumi好感','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/121_假蜘蛛英雄骗局揭穿.mp4','/thumbs/121_Kv_RIjKdP0I.jpg','');
INSERT INTO videos VALUES(122,'2026-03-29','触物成冰蝴蝶诅咒','','https://www.youtube.com/shorts/ryKghomDoC4','scripts/1056-视频深度拆解报告.md','2026-03-29 18:36:03','2026-03-29 19:45:04','Rumi''s Icy Nightmare: Everything She Touches Turns to','69','2026-03-19',unistr('深夜，rumi（紫色长麻花辫）静躺在奢华的棕色绸缎枕头上熟睡。一只散发着幽蓝色光芒的半透明蝴蝶在半空中飞舞，随后精准地俯冲钻入了\u000a    rumi 微微张开的口中。rumi\u000a    瞬间惊醒，面色惨白，口中喷出浓重的、如液氮般的白色冷气。她惊恐地坐起，双手紧抓双臂，全身剧烈颤抖，牙齿咯咯作响。她绝望地低语："Why\u000a    is my body so cold? It feels like I swallowed a freezer. I need to\u000a    eat something. Maybe that will help."\u000a\u000arumi\u000a    踉跄走向厨房大理石导台。她看到一篮菠萝和香蕉。当她的右手食指轻触百香果的刹那，幽蓝冰晶迅速覆盖整个篮子，水果瞬间化作冰雕。她惊呼："Wait,\u000a    did that just turn to ice?"\u000a    她转而触碰旁边的炸鸡腿，指尖所到之处，热腾腾的鸡肉立刻挂满白霜。\u000a\u000a她试图洗手，但指尖刚靠近自来水，奔腾的水流竟在半空凝固成扭曲的冰柱，寒气顺着水槽四溢。rumi\u000a    崩溃地捧住自己的脸，冰霜甚至开始在她的脸颊蔓延。她哀号："What is\u000a    wrong with my hands? Even the water! Everything I touch turns to\u000a    ice!"\u000a\u000arumi\u000a    冲向壁炉寻找热源，看到跳动的橘红火焰，她以为找到了救星："I need to\u000a    find something warm! Yes, fire will fix it!"\u000a    谁料当她双手靠近，那团炽热的能量竟瞬间被冻结成晶莹剔透的蓝色固态冰焰。她吓得倒退坐在地上："Oh\u000a    my god! I just froze fire!"\u000a\u000a她抓起 iPhone\u000a    欲求救，手机却瞬间长出狰狞的白色冰刺。她哭喊着无法拨号，随后冲向落地玻璃门。双手触碰金属把手的瞬间，整扇厚重的玻璃门因极度温差剧烈爆裂。她逃到室外，手指划过白色跑车车门，整台车瞬间白化结霜。她跪在车旁，双手抓发痛哭："Not\u000a    my car! That\\''s it, I\\''m so done. Somebody help me, please!"\u000a\u000arumi 举着写有"HELP =\u000a    👍"的瓦楞纸板呼救，随后出现在医院走廊大喊："Doctors, please help\u000a    me!" 医生 jinu（黑色偏分头）走上前扶住她的双肩安慰："Calm down,\u000a    Rumi. Let me check you." 接触的一瞬，jinu\u000a    的身体从指尖开始透明化，瞬间变成一尊惊恐神态的冰雕。\u000a\u000a医生 zoye（两个丸子头）目睹惨剧，惊叫："Oh my god!\u000a    What did you do to him?" 在确认是误伤后，zoye\u000a    冲入实验室，将红色与绿色液体混合，调配出一瓶发光的橙色药水。\u000a\u000azoye 拿着药水跑回走廊，让 rumi 喝下。rumi\u000a    饮后寒气散去，肤色恢复红润。她惊喜地站起，激动地握住 zoye\u000a    的手："Doctor, you are a genius! Thank you!"\u000a    就在两人双手交握的一刻，zoye\u000a    的手掌突然剧烈起火燃烧，红色的火舌吞噬了她的手臂，rumi 与 zoye\u000a    同时露出惊骇表情，画面在火焰的噼啪声中切断。'),'深夜rumi熟睡时一只幽蓝色发光蝴蝶飞入她微张的口中','异常物品, 生命威胁','惊悚, 热血','蝴蝶入口获得冰冻诅咒→触碰水果冻成冰→炸鸡挂霜→水流凝固→壁炉火焰都被冻住→手机长冰刺→玻璃门炸裂→跑车冻白→举牌求救→医院jinu被碰后变冰雕→zoye实验室配药→喝下解药康复→握手时zoye手掌起火→诅咒从冰变成火','诅咒能力递进','获得诅咒→从小物到大物到人体逐级验证→寻找解药→治愈假象→诅咒进化为更极端形态','','','11685561','293069','','故事类','rumi','解除触物成冰的蝴蝶诅咒','','','https://aiyoutube.oss-cn-beijing.aliyuncs.com/videos/122_触物成冰蝴蝶诅咒.mp4','/thumbs/122_ryKghomDoC4.jpg','test notestest notes success');
